-- ============================================================
-- Migration 007 — Section 3 content (Comparable Selection & Analysis)
--
-- Two-part migration:
--   1. Schema: extend section_fields.field_type CHECK constraint to
--      allow the new 'comparables' field type used by Section 3.
--   2. Data: seed Section M2-S3 content.
--
-- Seeds Section M2-S3:
--   - 6 categories (Mortgage, Litigation, Estate&Tax, Private,
--     Government, Specialty) — same color palette as Section 2
--     for visual continuity across sections
--   - 1 field of type 'comparables' (a new field type)
--   - 60 scenarios (10 per category)
--   - 60 model_answers (one per scenario, since one field)
--   - All comp pool data per scenario lives in
--     model_answers.field_options_override (comps + rejection_reasons
--     + subject fact sheet) — student-facing display only.
--   - Model verdicts, ranking, per-comp explanations, and overall
--     justification live in model_answers.model_data — gated behind
--     submit-and-lock by the existing reveal endpoint.
--
-- The model_data and field_options_override JSONB columns themselves
-- already exist on model_answers (added in earlier migrations); this
-- migration only extends the field_type whitelist.
--
-- Idempotency: this migration runs once and is recorded in the
-- schemaversion table by the migration runner. It will never
-- run again.
-- ============================================================

-- Look up Section 3 (Comparable Selection) id; bail if not found
DO $$
DECLARE
  v_section_id INT;
BEGIN
  SELECT id INTO v_section_id FROM module_sections WHERE code = 'M2-S3';
  IF v_section_id IS NULL THEN
    RAISE EXCEPTION 'Section M2-S3 not found — seed must run first';
  END IF;
END $$;

-- ─────────────── Schema change: extend field_type allowed values ───────────────
-- An earlier migration restricted section_fields.field_type to a fixed list
-- (text, checklist, select, parameters, approaches). Section 3 introduces a
-- new type 'comparables' for the comp-selection workflow, so we drop and
-- recreate the CHECK constraint with the additional value. Postgres has no
-- in-place CHECK modify; drop+add is the standard pattern.
ALTER TABLE section_fields DROP CONSTRAINT IF EXISTS section_fields_field_type_check;
ALTER TABLE section_fields ADD CONSTRAINT section_fields_field_type_check
  CHECK (field_type IN ('text', 'checklist', 'select', 'parameters', 'approaches', 'comparables'));

-- ─────────────── Section field (one — the comparables workflow) ───────────────
INSERT INTO section_fields (section_id, order_index, field_key, label, help_text, field_type, field_options)
SELECT ms.id, 1, 'comparables', 'Comparable Selection & Analysis',
  'Screen the candidate comparables, select your best three, and justify your reasoning.',
  'comparables', NULL
FROM module_sections ms
WHERE ms.code = 'M2-S3';

-- ─────────────── Categories ───────────────
INSERT INTO scenario_categories (section_id, order_index, code, name, color_primary, color_accent, description)
SELECT ms.id, x.ord, x.code, x.name, x.cp, x.ca, NULL
FROM module_sections ms,
  (VALUES
    (1, 'M2-S3-C1', 'Mortgage Lending', '#1a1a2e', '#2a2a4e'),
    (2, 'M2-S3-C2', 'Litigation Support', '#4a1942', '#6a2962'),
    (3, 'M2-S3-C3', 'Estate & Tax', '#0f4c3a', '#1f6c5a'),
    (4, 'M2-S3-C4', 'Private/Consulting', '#8b4513', '#ab6533'),
    (5, 'M2-S3-C5', 'Government & Public Use', '#1a3a5c', '#2a5a7c'),
    (6, 'M2-S3-C6', 'Specialty Situations', '#6b1d1d', '#8b3d3d')
  ) AS x(ord, code, name, cp, ca)
WHERE ms.code = 'M2-S3';

-- ─────────────── Category 1: Mortgage Lending ───────────────
-- Scenario 1.1: Standard Purchase Appraisal
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 1, 'basic', 'Standard Purchase Appraisal', 'First National Bank engaged you for a purchase money mortgage appraisal. Contract price: $289,000. Scope: 1004/URAR with full interior and exterior inspection.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 1
  RETURNING id
)
