ar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C8","addr":"258 Willow Blvd","prox":"1.2 mi","sub":"Willowbrook","price":241000,"date":"1 month ago","style":"Ranch","bed":3,"bath":2,"gla":1390,"site":"7,400 SF","yr":2001,"cond":"C4","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Bank-owned REO / foreclosure","warn":true}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Different property type or style","Outside subject market area","Inadequate verification / data","Other"],"subject":{"address":"4821 Maplewood Drive","subdivision":"Maplewood Estates","style":"Ranch","bed":3,"bath":2,"gla":1450,"site":"7,500 SF","yr":2003,"cond":"C3","qual":"Q4","garage":"2-car attached","bsmt":"None","pool":"None"}}'::jsonb
