":"Q3","conc":"None","gar":"1-car attached","txn":"Sold as-is — condition at sale unverifiable","warn":true}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Different property type or style","Outside subject market area","Inadequate verification / data","Other"],"subject":{"address":"2847 Oakwood Avenue","subdivision":"Oakwood Heights","style":"Ranch","bed":3,"bath":"1.5","gla":1175,"site":"5,500 SF","yr":1968,"cond":"C3","qual":"Q3","garage":"1-car attached","bsmt":"Partial","pool":"None"}}'::jsonb
FROM ins,
  module_sections ms
  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- Scenario 1.5: Declining Market — Limited Sales
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 5, 'intermediate', 'Declining Market — Limited Sales', 'Regional Home Lenders engaged you for a purchase mortgage. Contract: $298,000. Market data shows values in this area have declined ~5–7% over 18 months. Scope: 1004/URAR. Comparables must reflect current market conditions.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 1
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'In a declining market, recent arm''s length sales are critical. C1 (same sub, 40 SF less, 2 mo.) is strongest; C2 (most recent, 1 mo., adjacent sub); C3 (same sub, concession adj, 4 mo.). All three reflect current conditions. C4 rejected — 22 months old, pre-decline pricing that would overstate value. C5 — outside competing market. C6 — relocation buyout, non-arm''s length. C7 acceptable but C4 condition adds adjustment uncertainty vs C1–C3. C8 — REO distressed sale.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"accept","C8":"reject"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, 40 SF less GLA, arm''s length 2 mo. ago. Reflects current declining market conditions.","C2":"Strong comp — adjacent sub, most recent sale (1 mo.), arm''s length. Small GLA and site adjustments needed.","C3":"Good comp — same sub, close size match, consistent with declining market trend. Seller concession adj required.","C4":"Reject — 22 months old, sold during pre-decline market. Using this sale would overstate current value — especially dangerous in a declining market.","C5":"Reject — 2.5 miles away in a non-competing neighborhood. Buyers for the subject would not consider Summit Overlook an alternative location.","C6":"Reject — employer/relocation buyout is not arm''s length. Employer''s motivation is employee retention, not market-value optimization.","C7":"Acceptable — similar and recent, but C4 condition vs C3 subject requires a condition adj that adds uncertainty. C1–C3 in matching C3 condition are preferable.","C8":"Reject — bank-owned REO. In a declining market, REO sales depress values beyond what arm''s length data supports."},"justification":"In a declining market, recent arm''s length sales are critical. C1 (same sub, 40 SF less, 2 mo.) is strongest; C2 (most recent, 1 mo., adjacent sub); C3 (same sub, concession adj, 4 mo.). All three reflect current conditions. C4 rejected — 22 months old, pre-decline pricing that would overstate value. C5 — outside competing market. C6 — relocation buyout, non-arm''s length. C7 acceptable but C4 condition adds adjustment uncertainty vs C1–C3. C8 — REO distressed sale."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"518 Maplecrest Court","prox":"0.4 mi","sub":"Maplecrest Ridge","price":291000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1680,"site":"8,000 SF","yr":2003,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C2","addr":"742 Ridgewood Drive","prox":"0.7 mi","sub":"Ridgewood Acres","price":295000,"date":"1 month ago","style":"Ranch","bed":3,"bath":2,"gla":1755,"site":"8,500 SF","yr":2001,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C3","addr":"189 Maplecrest Lane","prox":"0.5 mi","sub":"Maplecrest Ridge","price":287000,"date":"4 months ago","style":"Ranch","bed":3,"bath":2,"gla":1700,"site":"8,100 SF","yr":2004,"cond":"C3","qual":"Q4","conc":"$3,000 seller paid","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"401 Maplecrest Blvd","prox":"0.3 mi","sub":"Maplecrest Ridge","price":318000,"date":"22 months ago","style":"Ranch","bed":3,"bath":2,"gla":1690,"site":"7,900 SF","yr":2002,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C5","addr":"628 Summit View Drive","prox":"2.5 mi","sub":"Summit Overlook","price":293000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1730,"site":"8,300 SF","yr":2003,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C6","addr":"315 Maplecrest Ridge Ct","prox":"0.4 mi","sub":"Maplecrest Ridge","price":261000,"date":"3 months ago","style":"Ranch","bed":3,"bath":2,"gla":1665,"site":"7,800 SF","yr":2002,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Relocation company buyout — employer purchase","warn":true},{"id":"C7","addr":"57 Ridgewood Circle","prox":"0.8 mi","sub":"Ridgewood Acres","price":279000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1710,"site":"8,000 SF","yr":2001,"cond":"C4","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C8","addr":"902 Maplecrest Drive","prox":"0.4 mi","sub":"Maplecrest Ridge","price":267000,"date":"1 month ago","style":"Ranch","bed":3,"bath":2,"gla":1695,"site":"8,100 SF","yr":2003,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Bank-owned REO / foreclosure","warn":true}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Different property type or style","Outside subject market area","Inadequate verification / data","Other"],"subject":{"address":"3412 Maplecrest Drive","subdivision":"Maplecrest Ridge","style":"Ranch","bed":3,"bath":2,"gla":1720,"site":"8,200 SF","yr":2002,"cond":"C3","qual":"Q4","garage":"2-car attached","bsmt":"None","pool":"None"}}'::jsonb
FROM ins,
  module_sections ms
  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- Scenario 1.6: Rural Property — Extended Search
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 6, 'advanced', 'Rural Property — Extended Search', 'Farm Bureau Financial Services engaged you for a rural refinance appraisal. Subject is on 2.5 acres with well water and septic in an unincorporated rural area. Search area expanded due to limited local sales. Scope: 1004/URAR.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 1
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'In rural markets, expanded search is required. C1 (2.4 mi, well & septic, 2.2 ac, 50 SF less) is strongest; C2 (4.8 mi, well & septic, GLA/acreage adj); C3 (3.1 mi, near-identical GLA, utility adj for public water). C4 rejected — in-town subdivision, different market segment. C5 — 40-acre farm, different buyer pool. C6 — the nearest, most physically similar sale, yet rejected as a non-arm''s length estate sale: the core lesson here is that proximity never overrides the arm''s length requirement. C7 — 24 months old. C8 acceptable as supplementary support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"reject","C8":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — rural, well & septic, 2.2 acres, 50 SF less GLA. 2.4-mi distance is normal and expected in rural markets.","C2":"Strong comp — rural, well & septic, similar quality. GLA (+150 SF) and acreage (3.0 ac) adjustments needed. 4.8 mi acceptable for rural market.","C3":"Good comp — rural, near-identical GLA (+25 SF). Has public water vs subject''s well; utility adjustment needed.","C4":"Reject — suburban subdivision on a city lot with public utilities. Different market segment; rural acreage buyers do not compete with in-town subdivision buyers.","C5":"Reject — 40-acre farm with agricultural outbuildings. Different market segment from a 2.5-acre residential property; adjustments for excess acreage are not reliable.","C6":"Reject — estate sale; non-arm''s length. Physical proximity and similarity never override the arm''s length requirement. This is the key lesson in this scenario.","C7":"Reject — 24 months old. Recent arm''s length rural comps are available, making a speculative time adjustment on this sale unnecessary.","C8":"Acceptable — rural, well & septic, similar acreage. At 5.5 mi, C1–C3 are more comparable; useful as a 4th comp to support the value range."},"justification":"In rural markets, expanded search is required. C1 (2.4 mi, well & septic, 2.2 ac, 50 SF less) is strongest; C2 (4.8 mi, well & septic, GLA/acreage adj); C3 (3.1 mi, near-identical GLA, utility adj for public water). C4 rejected — in-town subdivision, different market segment. C5 — 40-acre farm, different buyer pool. C6 — the nearest, most physically similar sale, yet rejected as a non-arm''s length estate sale: the core lesson here is that proximity never overrides the arm''s length requirement. C7 — 24 months old. C8 acceptable as supplementary support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"5214 County Rd 475 N","prox":"2.4 mi","sub":"Rural — unincorporated","price":312000,"date":"3 months ago","style":"Ranch","bed":3,"bath":2,"gla":1850,"site":"2.2 acres","yr":1997,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car detached","txn":"Arm''s length — well & septic","warn":false},{"id":"C2","addr":"11042 State Road 37","prox":"4.8 mi","sub":"Rural — unincorporated","price":308000,"date":"5 months ago","style":"Ranch","bed":3,"bath":2,"gla":2050,"site":"3.0 acres","yr":1993,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car detached","txn":"Arm''s length — well & septic","warn":false},{"id":"C3","addr":"2871 County Rd 400 N","prox":"3.1 mi","sub":"Rural — unincorporated","price":319000,"date":"4 months ago","style":"Ranch","bed":3,"bath":2,"gla":1925,"site":"2.0 acres","yr":1999,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — public water/septic","warn":false},{"id":"C4","addr":"418 Elmwood Drive","prox":"0.0 mi (in town)","sub":"Elmwood Subdivision","price":285000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1880,"site":"0.25 acres","yr":1996,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C5","addr":"15200 State Road 37","prox":"6.2 mi","sub":"Rural — agricultural","price":425000,"date":"3 months ago","style":"Ranch","bed":3,"bath":2,"gla":1950,"site":"40 acres","yr":1994,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car detached + farm bldgs","txn":"Arm''s length — deed verified","warn":false},{"id":"C6","addr":"7341 County Rd 450 N","prox":"1.2 mi","sub":"Rural — unincorporated","price":289000,"date":"3 months ago","style":"Ranch","bed":3,"bath":2,"gla":1875,"site":"2.4 acres","yr":1996,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car detached","txn":"Estate sale — per deed/court records","warn":true},{"id":"C7","addr":"3918 County Rd 500 N","prox":"4.2 mi","sub":"Rural — unincorporated","price":302000,"date":"24 months ago","style":"Ranch","bed":3,"bath":2,"gla":1780,"site":"2.8 acres","yr":1993,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car detached","txn":"Arm''s length — deed verified","warn":false},{"id":"C8","addr":"9102 US Hwy 150","prox":"5.5 mi","sub":"Rural — unincorporated","price":315000,"date":"4 months ago","style":"Ranch","bed":3,"bath":2,"gla":1960,"site":"2.1 acres","yr":1998,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car detached","txn":"Arm''s length — well & septic","warn":false}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Different property type or style","Outside subject market area","Inadequate verification / data","Other"],"subject":{"address":"8842 County Road 450 N","subdivision":"Rural — unincorporated","style":"Ranch","bed":3,"bath":2,"gla":1900,"site":"2.5 acres","yr":1995,"cond":"C3","qual":"Q4","garage":"2-car detached","bsmt":"Partial","pool":"None"}}'::jsonb
FROM ins,
  module_sections ms
  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

