  SELECT cat.id, 7, 'advanced', 'Unique Property — Custom Home', 'Heritage Private Bank engaged you for a luxury custom home refinance. Subject is 3,800 SF with pool and outdoor kitchen. Comparable sales are limited due to the property''s unique characteristics. Scope: 1004/URAR.'
  FROM scenario_categories cat
