INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'In luxury markets, quality grade and amenities matter more than proximity; extended distances are appropriate. C1 (same sub, Q6, pool, 150 SF less) is strongest; C2 (adjacent luxury sub, Q6, pool, GLA/bath adj); C3 (Q6, pool, 1.8 mi, bedroom adj). C4 rejected — Q4 tract vs Q6 custom, not bridgeable. C5 — premium size/tier, too large. C6 — 28 miles, different market. C7 accepted as paired-sale to extract pool contribution; preferred comps are C1–C3 with pools. C8 — builder/family transfer, non-arm''s length.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"accept","C8":"reject"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, Q6 custom quality, pool, 150 SF less GLA. Recent arm''s length sale. Small age and GLA adjustments needed.","C2":"Strong comp — adjacent luxury sub, Q6, pool. GLA (+300 SF) and half-bath adjustments needed. 1.2 mi appropriate for luxury market with limited sales.","C3":"Good comp — Q6 quality, pool, 250 SF less GLA. Bedroom adjustment needed. 1.8 mi acceptable for luxury market with limited inventory.","C4":"Reject — Q4 tract construction vs Q6 custom. A $400k+ price gap reflects the quality difference; adjustments between Q4 and Q6 are not supportable.","C5":"Reject — 1,400 SF larger GLA (37%), 6BR/5BA, C1 condition, 4-car. Higher market tier; gross adjustments are too large to produce a reliable result.","C6":"Reject — 28 miles away in a different city. Despite physical similarity, this is a non-competing market; school districts and amenities are entirely different.","C7":"Acceptable — same sub, Q6, 50 SF less GLA. No pool; useful as a paired-sale to quantify the pool/outdoor kitchen contribution. C1–C3 with pools are preferred.","C8":"Reject — builder sold to family member per deed. Non-arm''s length; scarcity of luxury comps does not lower the arm''s length standard."},"justification":"In luxury markets, quality grade and amenities matter more than proximity; extended distances are appropriate. C1 (same sub, Q6, pool, 150 SF less) is strongest; C2 (adjacent luxury sub, Q6, pool, GLA/bath adj); C3 (Q6, pool, 1.8 mi, bedroom adj). C4 rejected — Q4 tract vs Q6 custom, not bridgeable. C5 — premium size/tier, too large. C6 — 28 miles, different market. C7 accepted as paired-sale to extract pool contribution; preferred comps are C1–C3 with pools. C8 — builder/family transfer, non-arm''s length."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"1847 Ridgemont Drive","prox":"0.6 mi","sub":"Ridgemont Estates","price":895000,"date":"4 months ago","style":"Two-Story","bed":5,"bath":4,"gla":3650,"site":"0.8 acres","yr":2017,"cond":"C2","qual":"Q6","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C2","addr":"412 Hillcrest Manor","prox":"1.2 mi","sub":"Hillcrest Estates","price":920000,"date":"6 months ago","style":"Two-Story","bed":5,"bath":"4.5","gla":4100,"site":"0.9 acres","yr":2014,"cond":"C2","qual":"Q6","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C3","addr":"78 Summit Ridge Place","prox":"1.8 mi","sub":"Summit Ridge Estates","price":875000,"date":"5 months ago","style":"Two-Story","bed":4,"bath":4,"gla":3550,"site":"0.7 acres","yr":2013,"cond":"C2","qual":"Q6","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"2100 Clearwood Blvd","prox":"0.8 mi","sub":"Clearwood Park (tract)","price":485000,"date":"2 months ago","style":"Two-Story","bed":4,"bath":3,"gla":3200,"site":"0.35 acres","yr":2018,"cond":"C2","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C5","addr":"14 Mountainview Drive","prox":"3.5 mi","sub":"Mountainview Estates","price":1150000,"date":"3 months ago","style":"Two-Story","bed":6,"bath":5,"gla":5200,"site":"1.5 acres","yr":2016,"cond":"C1","qual":"Q6","conc":"None","gar":"4-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C6","addr":"889 Grand View Terrace","prox":"28 mi","sub":"Northgate Hills","price":905000,"date":"4 months ago","style":"Two-Story","bed":5,"bath":4,"gla":3900,"site":"0.8 acres","yr":2015,"cond":"C2","qual":"Q6","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C7","addr":"1125 Ridgemont Lane","prox":"0.4 mi","sub":"Ridgemont Estates","price":868000,"date":"3 months ago","style":"Two-Story","bed":5,"bath":4,"gla":3750,"site":"0.7 acres","yr":2016,"cond":"C2","qual":"Q6","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C8","addr":"301 Eastbrook Manor","prox":"1.5 mi","sub":"Eastbrook Estates","price":912000,"date":"4 months ago","style":"Two-Story","bed":5,"bath":4,"gla":3900,"site":"0.85 acres","yr":2015,"cond":"C2","qual":"Q6","conc":"None","gar":"3-car attached","txn":"Builder sold to family member — per deed","warn":true}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Different property type or style","Outside subject market area","Inadequate verification / data","Other"],"subject":{"address":"2241 Ridgemont Lane","subdivision":"Ridgemont Estates","style":"Two-Story","bed":5,"bath":4,"gla":3800,"site":"0.75 acres","yr":2015,"cond":"C2","qual":"Q6 (custom)","garage":"3-car attached","bsmt":"Finished","pool":"Pool & outdoor kitchen"}}'::jsonb
FROM ins,
