-- Scenario 1.8: Multi-Unit Residential (2–4 Family)
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 8, 'advanced', 'Multi-Unit Residential (2–4 Family)', 'Tri-State Savings Bank engaged you to appraise a residential duplex for a purchase mortgage. Contract: $387,000. Both units are tenant-occupied. Scope: 1025 Small Residential Income Property Report with full interior inspection of both units.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 1
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'The critical rule for a 1025 assignment: comparables must be 2-4 family properties. C1 (same neighborhood, 150 SF less), C2 (most recent, 2 mo.), and C3 (adjacent district, parking adj) are all duplexes with matching unit configurations. C4 and C5 rejected — single-family homes; SFR sales never qualify for a duplex appraisal, period. C6 — 6-unit commercial property. C7 — 21 months old. C8 acceptable as a 4th comp on the 1025 grid.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"reject","C8":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same neighborhood, same property type (duplex), matching unit configuration, 150 SF less total GLA. Recent arm''s length sale.","C2":"Strong comp — same property type and unit mix, most recent sale (2 mo.). Total GLA +120 SF requires adjustment.","C3":"Good comp — correct property type, similar total GLA. Parking adjustment needed (street vs 2 off-street).","C4":"Reject — single-family residence vs 2-unit income property. For a 1025 appraisal, comparables must be 2-4 family sales. SFR is never appropriate regardless of proximity.","C5":"Reject — single-family home. The 1025 appraisal mandate is clear: 2-4 family comparable sales only. SFR sales never qualify regardless of price or location.","C6":"Reject — 6-unit apartment building is a commercial property. Exceeds the 2-4 unit residential classification; different market segment and buyer motivation.","C7":"Reject — 21 months old; exceeds the 12-month guideline. Adequate recent duplex sales are available.","C8":"Acceptable — correct property type, arm''s length. Farther at 1.3 miles; C1–C3 are more comparable but this sale is useful as a 4th comp on the 1025 grid."},"justification":"The critical rule for a 1025 assignment: comparables must be 2-4 family properties. C1 (same neighborhood, 150 SF less), C2 (most recent, 2 mo.), and C3 (adjacent district, parking adj) are all duplexes with matching unit configurations. C4 and C5 rejected — single-family homes; SFR sales never qualify for a duplex appraisal, period. C6 — 6-unit commercial property. C7 — 21 months old. C8 acceptable as a 4th comp on the 1025 grid."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"512 Commerce Avenue","prox":"0.5 mi","sub":"Commerce District","price":375000,"date":"3 months ago","style":"Duplex (2-unit)","bed":"2+2","bath":"1+1","gla":"2,650 SF (total)","site":"4,800 SF","yr":2001,"cond":"C3","qual":"Q4","conc":"None","gar":"2 off-street","txn":"Arm''s length — MLS","warn":false},{"id":"C2","addr":"1847 Franklin Street","prox":"0.8 mi","sub":"Franklin Park","price":392000,"date":"2 months ago","style":"Duplex (2-unit)","bed":"2+2","bath":"1+1","gla":"2,920 SF (total)","site":"5,200 SF","yr":1998,"cond":"C3","qual":"Q4","conc":"None","gar":"2 off-street","txn":"Arm''s length — MLS","warn":false},{"id":"C3","addr":"741 Industrial Blvd","prox":"1.1 mi","sub":"Industrial Park District","price":368000,"date":"5 months ago","style":"Duplex (2-unit)","bed":"2+2","bath":"1+1","gla":"2,700 SF (total)","site":"5,100 SF","yr":1997,"cond":"C3","qual":"Q4","conc":"None","gar":"Street parking","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"288 Maple Avenue","prox":"0.6 mi","sub":"Maple Heights","price":318000,"date":"2 months ago","style":"Single-Family","bed":4,"bath":2,"gla":"1,900 SF","site":"5,500 SF","yr":2002,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C5","addr":"415 Oak Street","prox":"0.4 mi","sub":"Oak Park","price":295000,"date":"3 months ago","style":"Single-Family","bed":3,"bath":2,"gla":"1,750 SF","site":"5,000 SF","yr":1999,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car","txn":"Arm''s length — MLS","warn":false},{"id":"C6","addr":"2200 Commerce Street","prox":"0.7 mi","sub":"Commerce District","price":875000,"date":"4 months ago","style":"Apartment bldg (6-unit)","bed":"Various","bath":"Various","gla":"5,400 SF (total)","site":"8,000 SF","yr":2003,"cond":"C3","qual":"Q4","conc":"None","gar":"6 off-street","txn":"Arm''s length — investor sale","warn":false},{"id":"C7","addr":"689 Railroad Avenue","prox":"0.9 mi","sub":"Railroad District","price":355000,"date":"21 months ago","style":"Duplex (2-unit)","bed":"2+2","bath":"1+1","gla":"2,600 SF (total)","site":"4,900 SF","yr":1999,"cond":"C3","qual":"Q4","conc":"None","gar":"2 off-street","txn":"Arm''s length — deed verified","warn":false},{"id":"C8","addr":"1044 Franklin Blvd","prox":"1.3 mi","sub":"Franklin Heights","price":381000,"date":"6 months ago","style":"Duplex (2-unit)","bed":"2+2","bath":"1+1","gla":"2,750 SF (total)","site":"5,300 SF","yr":2002,"cond":"C3","qual":"Q4","conc":"None","gar":"2 off-street","txn":"Arm''s length — MLS","warn":false}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Different property type or style","Outside subject market area","Inadequate verification / data","Other"],"subject":{"address":"4412 Commerce Street","subdivision":"Commerce District","style":"Duplex (2-unit)","bed":"2+2","bath":"1+1","gla":"2,800 SF (total)","site":"5,000 SF","yr":2000,"cond":"C3","qual":"Q4","garage":"2 off-street spaces","bsmt":"None","pool":"None"}}'::jsonb
