-- Scenario 1.9: Mixed-Use — Residential Component
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 9, 'advanced', 'Mixed-Use — Residential Component', 'Citizens Community Bank engaged you for a mixed-use residential conforming loan. Subject has ground-floor retail (600 SF) and an upper-floor 2BR/1BA apartment (1,200 SF). Appraising on a 1004 with mixed-use addendum. Comparables must reflect the residential owner-occupant market for this property type.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 1
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'Comparables must be mixed-use properties in the same urban market — not pure SFR or pure commercial. C1 (same district, 50 SF less residential GLA) is strongest; C2 (most recent, minor GLA adj); C3 (adjacent market, office vs retail adj, concession adj). C4 rejected — pure commercial, no residential component. C5 — suburban SFR, different lifestyle and market. C6 — investor portfolio purchase, not owner-occupant motivation; also a 3-unit. C7 — 17 months old. C8 — commercial REO/distressed sale.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"reject","C8":"reject"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same district, same property type, 50 SF less residential GLA, arm''s length 3 mo. ago.","C2":"Strong comp — same district, same property type, most recent sale (2 mo.). Minor residential GLA adj (+75 SF) needed.","C3":"Good comp — mixed-use with apt., adjacent market. Office vs retail first floor may need minor adj. Seller concession adj required.","C4":"Reject — pure commercial with no residential component. Different property type, buyer pool, and financing. Not appropriate for a residential 1004 assignment.","C5":"Reject — suburban single-family in a different market context. Downtown live/work buyers do not compete with suburban ranch buyers; different market segments entirely.","C6":"Reject — investor portfolio purchase does not reflect owner-occupant motivation relevant to a residential conforming loan. Also a 3-unit building — a different property type.","C7":"Reject — 17 months old; outside the 12-month guideline. Three adequate recent mixed-use comps are available.","C8":"Reject — bank-owned REO from a commercial foreclosure. Distressed pricing does not reflect the owner-occupant residential market."},"justification":"Comparables must be mixed-use properties in the same urban market — not pure SFR or pure commercial. C1 (same district, 50 SF less residential GLA) is strongest; C2 (most recent, minor GLA adj); C3 (adjacent market, office vs retail adj, concession adj). C4 rejected — pure commercial, no residential component. C5 — suburban SFR, different lifestyle and market. C6 — investor portfolio purchase, not owner-occupant motivation; also a 3-unit. C7 — 17 months old. C8 — commercial REO/distressed sale."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"842 Main Street","prox":"0.3 mi","sub":"Downtown Arts District","price":285000,"date":"3 months ago","style":"Mixed-use (retail + apt.)","bed":2,"bath":1,"gla":"1,150 SF (residential)","site":"1,600 SF","yr":2003,"cond":"C3","qual":"Q4","conc":"None","gar":"Street parking","txn":"Arm''s length — MLS","warn":false},{"id":"C2","addr":"1415 Central Avenue","prox":"0.6 mi","sub":"Downtown Arts District","price":298000,"date":"2 months ago","style":"Mixed-use (retail + apt.)","bed":2,"bath":1,"gla":"1,275 SF (residential)","site":"1,900 SF","yr":2007,"cond":"C3","qual":"Q4","conc":"None","gar":"Street parking","txn":"Arm''s length — MLS","warn":false},{"id":"C3","addr":"2041 Broadway","prox":"0.9 mi","sub":"Midtown","price":279000,"date":"5 months ago","style":"Mixed-use (office + apt.)","bed":2,"bath":1,"gla":"1,100 SF (residential)","site":"1,700 SF","yr":2004,"cond":"C3","qual":"Q4","conc":"$2,000 seller paid","gar":"Street parking","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"501 Commerce Blvd","prox":"1.8 mi","sub":"Commerce Park","price":650000,"date":"2 months ago","style":"Commercial retail strip (no residential)","bed":"N/A","bath":"N/A","gla":"3,200 SF (commercial)","site":"8,500 SF","yr":2002,"cond":"C2","qual":"Q4","conc":"None","gar":"20 spaces","txn":"Arm''s length — commercial sale","warn":false},{"id":"C5","addr":"4218 Suburban Way","prox":"3.5 mi","sub":"Greenfield Estates","price":275000,"date":"2 months ago","style":"Single-Family Ranch","bed":3,"bath":2,"gla":"1,400 SF","site":"7,500 SF","yr":2005,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C6","addr":"1720 Main Street","prox":"0.5 mi","sub":"Downtown Arts District","price":510000,"date":"3 months ago","style":"Mixed-use (restaurant + 3 apts.)","bed":"3 units","bath":"Various","gla":"3,600 SF (total)","site":"2,200 SF","yr":2001,"cond":"C3","qual":"Q4","conc":"None","gar":"Street parking","txn":"Investor portfolio purchase","warn":true},{"id":"C7","addr":"988 Central Avenue","prox":"0.7 mi","sub":"Downtown Arts District","price":282000,"date":"17 months ago","style":"Mixed-use (retail + apt.)","bed":2,"bath":1,"gla":"1,175 SF (residential)","site":"1,750 SF","yr":2004,"cond":"C3","qual":"Q4","conc":"None","gar":"Street parking","txn":"Arm''s length — MLS","warn":false},{"id":"C8","addr":"1340 Broadway","prox":"1.0 mi","sub":"Midtown","price":246000,"date":"4 months ago","style":"Mixed-use (retail + apt.)","bed":2,"bath":1,"gla":"1,175 SF (residential)","site":"1,650 SF","yr":2003,"cond":"C3","qual":"Q4","conc":"None","gar":"Street parking","txn":"Bank-owned REO — commercial foreclosure","warn":true}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Different property type or style","Outside subject market area","Inadequate verification / data","Other"],"subject":{"address":"1128 Main Street","subdivision":"Downtown Arts District","style":"Mixed-use (retail + apt.)","bed":2,"bath":1,"gla":"1,200 SF (residential)","site":"1,800 SF (lot)","yr":2005,"cond":"C3","qual":"Q4","garage":"Street parking","bsmt":"None","pool":"None"}}'::jsonb
