-- Scenario 1.10: REO Appraisal — Limited Market
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 10, 'advanced', 'REO Appraisal — Limited Market', 'National Asset Recovery Corp (bank REO servicer) engaged you for an as-is appraisal of a bank-owned property. The subject has significant deferred maintenance (C5 condition). Intended use: REO disposition pricing. Scope: 1004/URAR. Comparables must reflect the subject''s actual condition and competitive market segment.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 1
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'For an as-is C5 appraisal, comparables must reflect C4-C5 condition — the subject''s actual market segment. C1 (same neighborhood, confirmed C5, near-identical GLA) is strongest; C2 (most recent, C4 condition, small adj); C3 (same neighborhood, C4-C5 straddle). C4 rejected — fully renovated C2; adjusting ~$90k on a $130k property is speculative and would overstate value — the most critical decision in this scenario. C5 — duplex, wrong property type. C6 — client''s own bank REO, circular and non-arm''s length. C7 — 22 months old. C8 acceptable as 4th comp.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"reject","C8":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same neighborhood, confirmed C5 condition, near-identical GLA and era. Directly reflects the subject''s market segment.","C2":"Strong comp — C4 condition (adjacent to C5), similar GLA and era, most recent sale (2 mo.). Small downward condition adj and half-bath adj needed.","C3":"Good comp — same neighborhood, C4-C5 condition straddles subject''s, near-identical GLA and era.","C4":"Reject — fully renovated C2 vs subject''s C5 as-is. The ~$90,000 condition gap requires a speculative adjustment. Using a renovated comp for a C5 appraisal systematically overstates value. Most critical decision in this scenario.","C5":"Reject — 2-unit duplex vs single-family residence. Different property type, buyer pool, and income characteristics.","C6":"Reject — REO by the same bank that is the client in this assignment. Circular and non-arm''s length; this cannot be used regardless of condition match or proximity.","C7":"Reject — 22 months old. Recent C4-C5 condition comps are available; a speculative time adjustment on this sale is unnecessary.","C8":"Acceptable — C4 condition, similar era and GLA, arm''s length. Farther at 1.2 mi; C1–C3 are more comparable but this sale supports the value range."},"justification":"For an as-is C5 appraisal, comparables must reflect C4-C5 condition — the subject''s actual market segment. C1 (same neighborhood, confirmed C5, near-identical GLA) is strongest; C2 (most recent, C4 condition, small adj); C3 (same neighborhood, C4-C5 straddle). C4 rejected — fully renovated C2; adjusting ~$90k on a $130k property is speculative and would overstate value — the most critical decision in this scenario. C5 — duplex, wrong property type. C6 — client''s own bank REO, circular and non-arm''s length. C7 — 22 months old. C8 acceptable as 4th comp."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"821 Jefferson Avenue","prox":"0.5 mi","sub":"Harrison Heights","price":127000,"date":"3 months ago","style":"Ranch","bed":3,"bath":1,"gla":1075,"site":"4,800 SF","yr":1975,"cond":"C5","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length MLS — sold as-is, condition confirmed","warn":false},{"id":"C2","addr":"1412 Monroe Street","prox":"0.7 mi","sub":"Monroe Park","price":138000,"date":"2 months ago","style":"Ranch","bed":3,"bath":"1.5","gla":1150,"site":"5,200 SF","yr":1980,"cond":"C4","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C3","addr":"548 Harrison Court","prox":"0.4 mi","sub":"Harrison Heights","price":131000,"date":"5 months ago","style":"Ranch","bed":3,"bath":1,"gla":1085,"site":"5,100 SF","yr":1977,"cond":"C4-C5","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length — deed/MLS verified","warn":false},{"id":"C4","addr":"215 Park Avenue","prox":"0.6 mi","sub":"Harrison Heights","price":218000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1095,"site":"4,900 SF","yr":1978,"cond":"C2 (fully renovated)","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C5","addr":"1821 Willow Street","prox":"0.9 mi","sub":"Willow Park","price":142000,"date":"3 months ago","style":"Duplex (2-unit)","bed":"2+1","bath":"1+1","gla":"2,100 SF (total)","site":"5,800 SF","yr":1982,"cond":"C4","qual":"Q4","conc":"None","gar":"None","txn":"Arm''s length — MLS","warn":false},{"id":"C6","addr":"712 Harrison Avenue","prox":"0.3 mi","sub":"Harrison Heights","price":115000,"date":"2 months ago","style":"Ranch","bed":3,"bath":1,"gla":1080,"site":"4,950 SF","yr":1976,"cond":"C5","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Bank-owned REO — client''s same institution","warn":true},{"id":"C7","addr":"319 Jefferson Terrace","prox":"0.6 mi","sub":"Harrison Heights","price":128000,"date":"22 months ago","style":"Ranch","bed":3,"bath":1,"gla":1090,"site":"4,700 SF","yr":1979,"cond":"C5","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length — deed verified","warn":false},{"id":"C8","addr":"1047 Monroe Blvd","prox":"1.2 mi","sub":"Monroe Heights","price":133000,"date":"4 months ago","style":"Ranch","bed":3,"bath":1,"gla":1120,"site":"5,400 SF","yr":1981,"cond":"C4","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length — MLS","warn":false}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Different property type or style","Outside subject market area","Inadequate verification / data","Other"],"subject":{"address":"714 Harrison Avenue","subdivision":"Harrison Heights","style":"Ranch","bed":3,"bath":1,"gla":1100,"site":"5,000 SF","yr":1978,"cond":"C5 (significant deferred maint.)","qual":"Q4","garage":"1-car attached","bsmt":"None","pool":"None"}}'::jsonb
FROM ins,
  module_sections ms
  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- ─────────────── Category 2: Litigation Support ───────────────
-- Scenario 2.1: Marital Dissolution — Date of Separation
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 1, 'basic', 'Marital Dissolution — Date of Separation', 'Attorney Susan Keller retained you to establish market value as of the date of marital separation (14 months ago) for divorce proceedings. The current market has appreciated approximately 9% since the separation date. Your value opinion must reflect conditions as of 14 months ago — not today''s market.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 2
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'For a marital dissolution retrospective date of 14 months ago, only comps contemporaneous with the separation date are appropriate. C1 (same sub, 16 mo.), C2 (13 mo., 1 mo. post-separation but no market change), and C3 (same sub, 17 mo.) are all within 3 months and arm''s length. C4 and C5 rejected — post-separation current sales with ~9% appreciation embedded; using them overstates the retroactive value. C6 — 28 months old, pre-dates separation by 14 months. C7 — relocation buyout at separation date, non-arm''s length. C8 acceptable as secondary support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"reject","C8":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, sold 16 mo. ago (2 mo. before separation date), arm''s length. Squarely within the retrospective window.","C2":"Strong comp — adjacent sub, 13 mo. ago (1 mo. after separation date). No post-separation market movement had occurred; appropriate for retrospective date. Minor GLA adj.","C3":"Good comp — same sub, 17 mo. ago (3 mo. before separation date), arm''s length. Slightly older effective age; within acceptable range.","C4":"Reject — sold 2 mo. ago, 12 months post-separation. Current market is ~9% above the separation-date value. Using this sale would overstate the retrospective value.","C5":"Reject — sold 3 mo. ago; post-dates the separation date by 11 months. Current market appreciation of ~9% is embedded in this price.","C6":"Reject — 28 mo. old; sold 14 months before the separation date. Market conditions at that time do not adequately represent conditions as of the retrospective effective date.","C7":"Reject — contemporaneous with separation date but relocation/employer buyout. Non-arm''s length; litigation appraisals demand the highest verification standard.","C8":"Acceptable — sold 11 mo. ago (3 mo. after separation date, no post-separation market change), arm''s length. Farther at 1.1 mi; C1–C3 more directly comparable."},"justification":"For a marital dissolution retrospective date of 14 months ago, only comps contemporaneous with the separation date are appropriate. C1 (same sub, 16 mo.), C2 (13 mo., 1 mo. post-separation but no market change), and C3 (same sub, 17 mo.) are all within 3 months and arm''s length. C4 and C5 rejected — post-separation current sales with ~9% appreciation embedded; using them overstates the retroactive value. C6 — 28 months old, pre-dates separation by 14 months. C7 — relocation buyout at separation date, non-arm''s length. C8 acceptable as secondary support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"312 Shelbourne Way","prox":"0.4 mi","sub":"Shelbourne Park","price":302000,"date":"16 months ago","style":"Ranch","bed":3,"bath":2,"gla":1540,"site":"7,000 SF","yr":2007,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C2","addr":"541 Briarwood Circle","prox":"0.7 mi","sub":"Briarwood Park","price":309000,"date":"13 months ago","style":"Ranch","bed":3,"bath":2,"gla":1620,"site":"7,400 SF","yr":2009,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C3","addr":"108 Shelbourne Court","prox":"0.5 mi","sub":"Shelbourne Park","price":298000,"date":"17 months ago","style":"Ranch","bed":3,"bath":2,"gla":1560,"site":"7,100 SF","yr":2006,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"719 Briarwood Drive","prox":"0.6 mi","sub":"Briarwood Park","price":335000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1590,"site":"7,200 SF","yr":2008,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C5","addr":"88 Clover Court","prox":"0.3 mi","sub":"Shelbourne Park","price":341000,"date":"3 months ago","style":"Ranch","bed":3,"bath":2,"gla":1570,"site":"7,100 SF","yr":2007,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C6","addr":"421 Ridgemont Way","prox":"0.8 mi","sub":"Ridgemont Crossing","price":278000,"date":"28 months ago","style":"Ranch","bed":3,"bath":2,"gla":1600,"site":"7,300 SF","yr":2007,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C7","addr":"215 Shelbourne Lane","prox":"0.4 mi","sub":"Shelbourne Park","price":306000,"date":"14 months ago","style":"Ranch","bed":3,"bath":2,"gla":1550,"site":"7,000 SF","yr":2008,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Relocation company buyout — employer purchase","warn":true},{"id":"C8","addr":"877 Oakdale Drive","prox":"1.1 mi","sub":"Oakdale Commons","price":304000,"date":"11 months ago","style":"Ranch","bed":3,"bath":2,"gla":1610,"site":"7,400 SF","yr":2009,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false}],"rejection_reasons":["Sale post-dates retrospective effective date","Sale reflects post-event market conditions","Sale too old — pre-dates effective date","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Outside subject market area","Inadequate verification / data","Other"],"subject":{"address":"2847 Clover Lane","subdivision":"Shelbourne Park","style":"Ranch","bed":3,"bath":2,"gla":1580,"site":"7,200 SF","yr":2008,"cond":"C3","qual":"Q4","garage":"2-car attached","bsmt":"None","pool":"None"}}'::jsonb
FROM ins,
  module_sections ms
  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- Scenario 2.2: Property Damage — Pre-Loss Value
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 2, 'basic', 'Property Damage — Pre-Loss Value', 'You have been retained by counsel to establish the pre-damage market value of 1114 Oak Terrace as of the date of fire (8 months ago) for an insurance coverage dispute. The subject sustained a total loss and has since been demolished. Your value opinion must reflect conditions as of the date of loss — not current conditions.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 2
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'The effective date is the date of fire (8 months ago). C1 (9 mo., same sub), C2 (7 mo., same sub), and C3 (10 mo., adjacent sub) bracket the loss date and are arm''s length. C4 and C5 rejected — post-loss date sales; the date of value is the date of loss, not today. C6 — 22 months old, sold 14 months before the fire. C7 — estate sale contemporaneous with loss date; non-arm''s length fails the litigation verification standard. C8 acceptable as secondary support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"reject","C8":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, sold 9 mo. ago (1 mo. before date of loss), arm''s length. Reflects pre-fire market conditions.","C2":"Strong comp — same sub, 7 mo. ago (1 mo. after fire). No market change between fire date and sale; appropriate for this retrospective date. Minor GLA adj.","C3":"Good comp — adjacent sub, 10 mo. ago (2 mo. before fire). Arm''s length, pre-loss conditions.","C4":"Reject — sold 2 mo. ago, 6 months post-loss. The date of value is the date of loss, not today; this sale reflects post-loss market conditions.","C5":"Reject — sold 3 mo. ago; post-dates the loss date. Even without significant market movement, the effective date governs: only pre-loss comps establish the pre-damage value.","C6":"Reject — 22 mo. old; sold 14 months before the date of fire. Too distant from the retrospective date to reliably represent pre-loss market conditions.","C7":"Reject — estate sale contemporaneous with loss date. Non-arm''s length; insurance litigation requires heightened verification and arm''s length sales only.","C8":"Acceptable — sold 6 mo. ago (2 mo. post-loss, no intervening market change), arm''s length. Farther at 1.0 mi; C1–C3 more directly comparable."},"justification":"The effective date is the date of fire (8 months ago). C1 (9 mo., same sub), C2 (7 mo., same sub), and C3 (10 mo., adjacent sub) bracket the loss date and are arm''s length. C4 and C5 rejected — post-loss date sales; the date of value is the date of loss, not today. C6 — 22 months old, sold 14 months before the fire. C7 — estate sale contemporaneous with loss date; non-arm''s length fails the litigation verification standard. C8 acceptable as secondary support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"88 Oak Lane","prox":"0.4 mi","sub":"Northgate Estates","price":261000,"date":"9 months ago","style":"Ranch","bed":3,"bath":2,"gla":1390,"site":"6,600 SF","yr":1998,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C2","addr":"412 Northgate Circle","prox":"0.6 mi","sub":"Northgate Estates","price":265000,"date":"7 months ago","style":"Ranch","bed":3,"bath":2,"gla":1445,"site":"7,000 SF","yr":2001,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C3","addr":"217 Birchwood Court","prox":"0.8 mi","sub":"Birchwood Estates","price":258000,"date":"10 months ago","style":"Ranch","bed":3,"bath":2,"gla":1400,"site":"6,900 SF","yr":1998,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"519 Northgate Pkwy","prox":"0.5 mi","sub":"Northgate Estates","price":281000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1430,"site":"6,800 SF","yr":2000,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C5","addr":"342 Maple Grove Drive","prox":"0.7 mi","sub":"Maple Grove Estates","price":276000,"date":"3 months ago","style":"Ranch","bed":3,"bath":2,"gla":1405,"site":"6,700 SF","yr":1999,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C6","addr":"771 Northgate Drive","prox":"0.4 mi","sub":"Northgate Estates","price":238000,"date":"22 months ago","style":"Ranch","bed":3,"bath":2,"gla":1410,"site":"6,700 SF","yr":1998,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C7","addr":"104 Oak Terrace","prox":"0.3 mi","sub":"Northgate Estates","price":263000,"date":"8 months ago","style":"Ranch","bed":3,"bath":2,"gla":1400,"site":"6,500 SF","yr":1999,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Estate sale — court confirmed","warn":true},{"id":"C8","addr":"688 Birchwood Drive","prox":"1.0 mi","sub":"Birchwood Estates","price":260000,"date":"6 months ago","style":"Ranch","bed":3,"bath":2,"gla":1435,"site":"7,000 SF","yr":2000,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false}],"rejection_reasons":["Sale post-dates retrospective effective date","Sale reflects post-event market conditions","Sale too old — pre-dates effective date","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Outside subject market area","Inadequate verification / data","Other"],"subject":{"address":"1114 Oak Terrace","subdivision":"Northgate Estates","style":"Ranch","bed":3,"bath":2,"gla":1420,"site":"6,800 SF","yr":1999,"cond":"C3 (pre-loss)","qual":"Q4","garage":"2-car attached","bsmt":"None","pool":"None"}}'::jsonb
