-- Scenario 2.3: Property Tax Appeal — Assessment Date
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 3, 'intermediate', 'Property Tax Appeal — Assessment Date', 'You have been retained by the property owner to support a formal property tax appeal. The subject was over-assessed as of the January 1 assessment (lien) date, 10 months ago. Your value opinion must reflect conditions as of the lien date. The current market has risen ~6% since the assessment date, so current sales would understate the taxpayer''s argument that the assessment was already too high.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 2
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'The effective date is the January 1 lien (assessment) date, 10 months ago. C1 (12 mo.), C2 (10 mo. — at lien date), and C3 (11 mo.) are all within 2 months of the assessment date and arm''s length, forming a value range of $376k–$389k. C4 and C5 rejected — post-lien date sales reflecting ~6% current appreciation; they fall outside the statutory evidentiary window for a tax appeal. C6 — 24 months old, pre-dates lien date by 14 months. C7 — bank-owned REO at lien date; distressed sale. C8 acceptable as supplementary lien-date support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"reject","C8":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, sold 12 mo. ago (2 mo. before lien date), arm''s length. Contemporaneous with assessment period.","C2":"Strong comp — same sub, sold exactly at lien date (10 mo. ago), arm''s length. Half-bath and minor GLA adjustments needed.","C3":"Good comp — same sub, 11 mo. ago (1 mo. before lien date), arm''s length. Closely mirrors subject; minor GLA adj.","C4":"Reject — sold 2 mo. ago, 8 months post-lien date. Reflects ~6% current appreciation above lien-date value. Post-assessment sales are not appropriate for a tax appeal retrospective opinion.","C5":"Reject — sold 3 mo. ago, post-lien date. In a tax appeal, the effective date is the statutory lien (assessment) date; post-date sales are outside the evidentiary time window.","C6":"Reject — 24 mo. old; sold 14 months before the lien date. Does not adequately reflect market conditions as of the January 1 assessment date.","C7":"Reject — bank-owned REO sale at lien date. Distressed pricing cannot represent the fair market value standard required for a property tax appeal.","C8":"Acceptable — sold at lien date, arm''s length. Located in a less comparable subdivision (1.0 mi); C1–C3 provide more direct market support but this sale confirms the value range."},"justification":"The effective date is the January 1 lien (assessment) date, 10 months ago. C1 (12 mo.), C2 (10 mo. — at lien date), and C3 (11 mo.) are all within 2 months of the assessment date and arm''s length, forming a value range of $376k–$389k. C4 and C5 rejected — post-lien date sales reflecting ~6% current appreciation; they fall outside the statutory evidentiary window for a tax appeal. C6 — 24 months old, pre-dates lien date by 14 months. C7 — bank-owned REO at lien date; distressed sale. C8 acceptable as supplementary lien-date support."}'::jsonb,
