","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Bank-owned REO","warn":true},{"id":"C8","addr":"217 Rolling Hills Way","prox":"1.0 mi","sub":"Rolling Hills","price":379000,"date":"10 months ago","style":"Two-Story","bed":4,"bath":3,"gla":2095,"site":"9,400 SF","yr":2005,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false}],"rejection_reasons":["Sale post-dates retrospective effective date","Sale reflects post-event market conditions","Sale too old — pre-dates effective date","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Outside subject market area","Inadequate verification / data","Other"],"subject":{"address":"2241 Fieldstone Drive","subdivision":"Heritage Hills","style":"Two-Story","bed":4,"bath":3,"gla":2100,"site":"9,500 SF","yr":2005,"cond":"C3","qual":"Q4","garage":"2-car attached","bsmt":"Unfinished","pool":"None"}}'::jsonb
