-- Scenario 2.4: Eminent Domain — Date of Take
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 4, 'intermediate', 'Eminent Domain — Date of Take', 'You have been retained by the property owner''s attorney in an eminent domain proceeding for highway right-of-way acquisition. The subject was partially taken 20 months ago. You are establishing ''before'' market value as of the date of take. Sales within 5 years before the take date are preferred; limited sales shortly after the take date may be used if free of project influence.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 2
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'For eminent domain, comps must reflect before-take market conditions (20 months ago). C1 (22 mo., 2 mo. before take), C2 (18 mo., 2 mo. after take with no project influence), and C3 (24 mo., 4 mo. before take) are all within 4 months of the take date and arm''s length. C4 and C5 rejected — current market sales reflecting post-take appreciation. C6 — Oak Valley is a non-competing market area. C7 — relocation buyout at take date, non-arm''s length; eminent domain demands the highest data reliability. C8 acceptable as supplementary support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"reject","C8":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same area, sold 22 mo. ago (2 mo. before take date), arm''s length. Reflects pre-take market conditions.","C2":"Strong comp — sold 18 mo. ago (2 mo. after take date, no project influence on this property), arm''s length. Minor GLA adj.","C3":"Good comp — same area, 24 mo. ago (4 mo. before take date), arm''s length. Slightly older at 24 months; well within the pre-take evidentiary window.","C4":"Reject — sold 3 mo. ago, 17 months post-take. Market has appreciated since the date of take; this sale does not reflect before-take conditions.","C5":"Reject — current market sale, 16 months post-take date. Market conditions have changed materially since the date of take.","C6":"Reject — 3.5 miles away in Oak Valley, a non-competing market area. Buyers for the subject along Riverside would not consider Oak Valley an alternative.","C7":"Reject — contemporaneous with take date but relocation/employer buyout. Non-arm''s length; eminent domain proceedings require the highest standard of market data reliability.","C8":"Acceptable — 23 mo. ago (3 mo. before take date), arm''s length. Slightly larger GLA (+70 SF) and farther at 0.9 mi; C1–C3 more directly comparable but this supports the range."},"justification":"For eminent domain, comps must reflect before-take market conditions (20 months ago). C1 (22 mo., 2 mo. before take), C2 (18 mo., 2 mo. after take with no project influence), and C3 (24 mo., 4 mo. before take) are all within 4 months of the take date and arm''s length. C4 and C5 rejected — current market sales reflecting post-take appreciation. C6 — Oak Valley is a non-competing market area. C7 — relocation buyout at take date, non-arm''s length; eminent domain demands the highest data reliability. C8 acceptable as supplementary support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"2814 Riverside Court","prox":"0.5 mi","sub":"Riverside Heights","price":348000,"date":"22 months ago","style":"Ranch","bed":3,"bath":2,"gla":1840,"site":"10,200 SF","yr":2002,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C2","addr":"591 Highlands Drive","prox":"0.8 mi","sub":"Highlands Estates","price":355000,"date":"18 months ago","style":"Ranch","bed":3,"bath":2,"gla":1920,"site":"10,800 SF","yr":2004,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C3","addr":"109 Riverside Blvd","prox":"0.6 mi","sub":"Riverside Heights","price":341000,"date":"24 months ago","style":"Ranch","bed":3,"bath":2,"gla":1870,"site":"10,400 SF","yr":2003,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"428 Riverside Pkwy","prox":"0.5 mi","sub":"Riverside Heights","price":388000,"date":"3 months ago","style":"Ranch","bed":3,"bath":2,"gla":1880,"site":"10,300 SF","yr":2004,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C5","addr":"712 Highlands Blvd","prox":"0.8 mi","sub":"Highlands Estates","price":382000,"date":"4 months ago","style":"Ranch","bed":3,"bath":2,"gla":1905,"site":"10,600 SF","yr":2003,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C6","addr":"2241 Oak Valley Road","prox":"3.5 mi","sub":"Oak Valley","price":352000,"date":"21 months ago","style":"Ranch","bed":3,"bath":2,"gla":1875,"site":"10,500 SF","yr":2003,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C7","addr":"311 Riverside Court","prox":"0.4 mi","sub":"Riverside Heights","price":347000,"date":"20 months ago","style":"Ranch","bed":3,"bath":2,"gla":1855,"site":"10,200 SF","yr":2003,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Relocation company buyout — employer purchase","warn":true},{"id":"C8","addr":"544 Highlands Court","prox":"0.9 mi","sub":"Highlands Estates","price":349000,"date":"23 months ago","style":"Ranch","bed":3,"bath":2,"gla":1960,"site":"10,900 SF","yr":2002,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false}],"rejection_reasons":["Sale post-dates retrospective effective date","Sale reflects post-event market conditions","Sale too old — pre-dates effective date","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Outside subject market area","Inadequate verification / data","Other"],"subject":{"address":"4418 Riverside Drive","subdivision":"Riverside Heights","style":"Ranch","bed":3,"bath":2,"gla":1890,"site":"10,500 SF","yr":2003,"cond":"C3","qual":"Q4","garage":"2-car attached","bsmt":"None","pool":"None"}}'::jsonb
