-- Scenario 2.5: Estate Tax — Date of Death
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 5, 'intermediate', 'Estate Tax — Date of Death', 'The estate''s executor retained you to establish fair market value as of the date of death (18 months ago) for federal estate tax purposes. IRS regulations require the value opinion to reflect conditions as of the date of death. The current market has appreciated approximately 11% since that date, meaning current sales would overstate the taxable estate value.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 2
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'For federal estate tax, market value must be established as of the date of death (18 months ago). C1 (20 mo.), C2 (17 mo., no market change in the 1 mo. interval), and C3 (19 mo.) are all within 2 months and arm''s length. Their values ($407k–$419k) contrast sharply with C4 and C5 ($461k–$468k) — the 11% appreciation shows exactly why current sales overstate the taxable estate value. C6 — contemporaneous probate sale, non-arm''s length (circular). C7 — 32 months old, pre-dates death by 14 months. C8 acceptable as supplementary support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"reject","C8":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, 20 mo. ago (2 mo. before date of death), arm''s length. Reflects pre-death market conditions.","C2":"Strong comp — same sub, 17 mo. ago (1 mo. after death, no market change), arm''s length. Minor GLA adj (+60 SF).","C3":"Good comp — same sub, 19 mo. ago (1 mo. before death), arm''s length. Extra full bath requires adjustment.","C4":"Reject — sold 2 mo. ago, 16 months post-death. Reflects ~11% market appreciation above the date-of-death value. IRS requires value as of date of death.","C5":"Reject — current sale post-dating the date of death by 15 months. Current market does not reflect the conditions on which estate tax liability is based.","C6":"Reject — contemporaneous court-confirmed probate sale. Non-arm''s length; using another estate sale in an estate tax appraisal introduces circular reasoning — both values may reflect estate pricing rather than open-market conditions.","C7":"Reject — 32 mo. old; sold 14 months before the date of death. Insufficient temporal proximity to reflect conditions as of the retrospective date.","C8":"Acceptable — sold at date-of-death (18 mo. ago), arm''s length. Farther in a less comparable subdivision; extra bath adj needed. C1–C3 provide stronger direct support."},"justification":"For federal estate tax, market value must be established as of the date of death (18 months ago). C1 (20 mo.), C2 (17 mo., no market change in the 1 mo. interval), and C3 (19 mo.) are all within 2 months and arm''s length. Their values ($407k–$419k) contrast sharply with C4 and C5 ($461k–$468k) — the 11% appreciation shows exactly why current sales overstate the taxable estate value. C6 — contemporaneous probate sale, non-arm''s length (circular). C7 — 32 months old, pre-dates death by 14 months. C8 acceptable as supplementary support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"812 Maple Drive","prox":"0.5 mi","sub":"Heritage Crossing","price":412000,"date":"20 months ago","style":"Colonial","bed":4,"bath":"2.5","gla":2140,"site":"8,800 SF","yr":1991,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C2","addr":"421 Heritage Way","prox":"0.7 mi","sub":"Heritage Crossing","price":419000,"date":"17 months ago","style":"Colonial","bed":4,"bath":"2.5","gla":2260,"site":"9,300 SF","yr":1994,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C3","addr":"108 Cloverleaf Court","prox":"0.6 mi","sub":"Heritage Crossing","price":407000,"date":"19 months ago","style":"Colonial","bed":4,"bath":3,"gla":2180,"site":"8,900 SF","yr":1993,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"513 Maple Terrace","prox":"0.5 mi","sub":"Heritage Crossing","price":468000,"date":"2 months ago","style":"Colonial","bed":4,"bath":"2.5","gla":2215,"site":"9,000 SF","yr":1993,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C5","addr":"742 Heritage Blvd","prox":"0.6 mi","sub":"Heritage Crossing","price":461000,"date":"3 months ago","style":"Colonial","bed":4,"bath":"2.5","gla":2195,"site":"8,900 SF","yr":1992,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C6","addr":"310 Cloverleaf Drive","prox":"0.6 mi","sub":"Heritage Crossing","price":408000,"date":"18 months ago","style":"Colonial","bed":4,"bath":"2.5","gla":2170,"site":"8,800 SF","yr":1991,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Court-confirmed probate sale","warn":true},{"id":"C7","addr":"88 Heritage Court","prox":"0.8 mi","sub":"Heritage Crossing","price":401000,"date":"32 months ago","style":"Colonial","bed":4,"bath":"2.5","gla":2220,"site":"9,100 SF","yr":1992,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C8","addr":"619 Parkview Drive","prox":"1.2 mi","sub":"Parkview Estates","price":415000,"date":"18 months ago","style":"Colonial","bed":4,"bath":3,"gla":2230,"site":"9,200 SF","yr":1993,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false}],"rejection_reasons":["Sale post-dates retrospective effective date","Sale reflects post-event market conditions","Sale too old — pre-dates effective date","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Outside subject market area","Inadequate verification / data","Other"],"subject":{"address":"4421 Maple Court","subdivision":"Heritage Crossing","style":"Colonial","bed":4,"bath":"2.5","gla":2200,"site":"9,000 SF","yr":1992,"cond":"C3","qual":"Q4","garage":"2-car attached","bsmt":"Partial","pool":"None"}}'::jsonb
