-- Scenario 2.6: Before-and-After — Partial Road Taking
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 6, 'advanced', 'Before-and-After — Partial Road Taking', 'You have been retained by the property owner''s attorney in an eminent domain partial-taking case. The state took a 25-foot strip from the front of the subject lot 16 months ago, reducing site area from 0.25 acres to 0.18 acres. You are establishing the ''before'' market value as of the date of take. ''Before'' comps must reflect properties with full, unencumbered lots similar to the subject''s pre-take site.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 2
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'For the ''before'' value in a partial taking, comps must satisfy two requirements: (1) standard full lots comparable to the subject''s pre-take site, and (2) conditions as of the take date (16 months ago). C1 (same sub, 0.26-ac. lot, 2 mo. before take), C2 (0.24-ac. lot, 1 mo. post-take, no project influence), and C3 (same sub, identical 0.25-ac. lot, 1 mo. before take) meet both. C4 — current sale, post-take appreciation. C5 — the critical insight: a comp with a prior reduced lot (0.16 ac.) would understate full-lot value and must be rejected. C6 — builder/partner transaction, non-arm''s length. C7 — 30 months old. C8 acceptable as supplementary.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"reject","C8":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, standard full lot (0.26 ac.), sold 2 mo. before take date. Reflects pre-take conditions with similar lot characteristics.","C2":"Strong comp — full standard lot (0.24 ac.), sold 1 mo. after take with no project influence. Arm''s length. Minor GLA adj (+50 SF).","C3":"Good comp — same sub, identical lot size (0.25 ac.), sold 1 mo. before take date. Half-bath adjustment needed.","C4":"Reject — sold 2 mo. ago, 14 months post-take. Reflects post-take market appreciation; not appropriate for establishing ''before'' value as of the take date.","C5":"Reject — this property already had a prior-reduced lot (0.16 ac.) from a different project. Using a comp with a non-standard reduced lot would understate the subject''s full before-take lot value.","C6":"Reject — builder sold to business partner per deed records. Non-arm''s length; eminent domain proceedings require the highest standard of data reliability in the before-value analysis.","C7":"Reject — 30 mo. old; sold 14 months before the take date. Too far from the retrospective date to adequately represent before-take market conditions.","C8":"Acceptable — full lot (0.27 ac.), sold 3 mo. before take date, arm''s length. Slightly farther; C1–C3 provide more direct support but this confirms the value range."},"justification":"For the ''before'' value in a partial taking, comps must satisfy two requirements: (1) standard full lots comparable to the subject''s pre-take site, and (2) conditions as of the take date (16 months ago). C1 (same sub, 0.26-ac. lot, 2 mo. before take), C2 (0.24-ac. lot, 1 mo. post-take, no project influence), and C3 (same sub, identical 0.25-ac. lot, 1 mo. before take) meet both. C4 — current sale, post-take appreciation. C5 — the critical insight: a comp with a prior reduced lot (0.16 ac.) would understate full-lot value and must be rejected. C6 — builder/partner transaction, non-arm''s length. C7 — 30 months old. C8 acceptable as supplementary."}'::jsonb,
