:"0.25 acres","yr":2007,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C8","addr":"617 Elmwood Way","prox":"0.9 mi","sub":"Elmwood Estates","price":481000,"date":"19 months ago","style":"Two-Story","bed":4,"bath":3,"gla":2440,"site":"0.27 acres","yr":2006,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS","warn":false}],"rejection_reasons":["Sale post-dates retrospective effective date","Sale reflects post-event market conditions","Sale too old — pre-dates effective date","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Outside subject market area","Inadequate verification / data","Other"],"subject":{"address":"1842 Ridgeway Lane","subdivision":"Ridgeway Estates","style":"Two-Story","bed":4,"bath":3,"gla":2400,"site":"0.25 acres (before taking)","yr":2007,"cond":"C2","qual":"Q4","garage":"3-car attached","bsmt":"Finished","pool":"None"}}'::jsonb
