-- Scenario 2.7: Environmental Stigma — Pre-Contamination Value
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 7, 'advanced', 'Environmental Stigma — Pre-Contamination Value', 'You have been retained by plaintiff''s counsel to establish pre-contamination market value as of the effective date (30 months ago), prior to any public awareness of TCE contamination from an adjacent former dry cleaner. The contamination was publicly announced 28 months ago. Current market values in the immediate area are depressed approximately 18% relative to pre-contamination conditions.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 2
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'For pre-contamination value, only pre-announcement sales are appropriate. C1 (32 mo., 2 mo. before effective date), C2 (30 mo., at effective date), and C3 (31 mo.) all predate the announcement and reflect unaffected market conditions. C4 and C5 — the most critical teaching point: post-announcement sales embody the very stigma discount being quantified; using them to establish pre-contamination value is circular and would directly understate the plaintiff''s damages. C6 — relocation buyout at effective date, non-arm''s length. C7 — sold 6 months post-announcement, may already carry partial stigma. C8 acceptable as an unaffected-market control.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"reject","C8":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same neighborhood, 32 mo. ago (2 mo. before effective date). Pre-announcement; reflects unaffected market conditions.","C2":"Strong comp — same area, sold at effective date (30 mo. ago), pre-announcement, arm''s length. Minor GLA adj (+40 SF).","C3":"Good comp — adjacent unaffected neighborhood, 31 mo. ago (1 mo. before effective date). Pre-announcement conditions.","C4":"Reject — current market sale, 28 months post-announcement, reflecting ~18% contamination stigma discount. Using stigmatized sales to establish pre-contamination value is circular reasoning — these sales ARE the damages being quantified.","C5":"Reject — post-announcement sale reflecting contamination stigma. The pre-contamination value must use pre-announcement comps; post-announcement sales in the affected area reflect diminished market conditions.","C6":"Reject — contemporaneous relocation/employer buyout. Non-arm''s length; contamination litigation requires the highest quality data for the pre-contamination baseline.","C7":"Reject — sold 24 mo. ago, 6 months after the contamination announcement. May already reflect partial stigma discount; not appropriate for establishing the fully unaffected pre-contamination baseline.","C8":"Acceptable — sold at effective date, pre-announcement, in an adjacent unaffected neighborhood, arm''s length. Useful as a control to confirm unaffected market value; C1–C3 more directly comparable."},"justification":"For pre-contamination value, only pre-announcement sales are appropriate. C1 (32 mo., 2 mo. before effective date), C2 (30 mo., at effective date), and C3 (31 mo.) all predate the announcement and reflect unaffected market conditions. C4 and C5 — the most critical teaching point: post-announcement sales embody the very stigma discount being quantified; using them to establish pre-contamination value is circular and would directly understate the plaintiff''s damages. C6 — relocation buyout at effective date, non-arm''s length. C7 — sold 6 months post-announcement, may already carry partial stigma. C8 acceptable as an unaffected-market control."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"414 Maplewood Drive","prox":"0.5 mi","sub":"Maplewood Heights","price":318000,"date":"32 months ago","style":"Ranch","bed":3,"bath":2,"gla":1640,"site":"7,500 SF","yr":2000,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C2","addr":"812 Creekside Drive","prox":"0.6 mi","sub":"Maplewood Heights","price":322000,"date":"30 months ago","style":"Ranch","bed":3,"bath":2,"gla":1720,"site":"8,000 SF","yr":2002,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C3","addr":"219 Hillcrest Way","prox":"0.8 mi","sub":"Hillcrest Park","price":315000,"date":"31 months ago","style":"Ranch","bed":3,"bath":2,"gla":1660,"site":"7,700 SF","yr":2001,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"508 Maplewood Circle","prox":"0.5 mi","sub":"Maplewood Heights","price":261000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1670,"site":"7,600 SF","yr":2001,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C5","addr":"714 Creekside Court","prox":"0.4 mi","sub":"Maplewood Heights","price":268000,"date":"6 months ago","style":"Ranch","bed":3,"bath":2,"gla":1655,"site":"7,500 SF","yr":2000,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C6","addr":"1041 Hillcrest Blvd","prox":"0.8 mi","sub":"Hillcrest Park","price":319000,"date":"30 months ago","style":"Ranch","bed":3,"bath":2,"gla":1690,"site":"7,900 SF","yr":2001,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Relocation company buyout","warn":true},{"id":"C7","addr":"215 Maplewood Court","prox":"0.5 mi","sub":"Maplewood Heights","price":285000,"date":"24 months ago","style":"Ranch","bed":3,"bath":2,"gla":1660,"site":"7,600 SF","yr":2001,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C8","addr":"881 Creekside Way","prox":"0.9 mi","sub":"Northside Park (no contamination)","price":320000,"date":"30 months ago","style":"Ranch","bed":3,"bath":2,"gla":1700,"site":"8,000 SF","yr":2002,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false}],"rejection_reasons":["Sale post-dates retrospective effective date","Sale reflects post-event market conditions","Sale too old — pre-dates effective date","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Outside subject market area","Inadequate verification / data","Other"],"subject":{"address":"2841 Creekside Circle","subdivision":"Maplewood Heights","style":"Ranch","bed":3,"bath":2,"gla":1680,"site":"7,800 SF","yr":2001,"cond":"C3","qual":"Q4","garage":"2-car attached","bsmt":"None","pool":"None"}}'::jsonb
