-- Scenario 2.8: Retroactive Date — Rapidly Rising Market
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 8, 'advanced', 'Retroactive Date — Rapidly Rising Market', 'You have been retained by counsel in a breach of contract dispute. The plaintiff alleges they were wrongfully denied the opportunity to purchase the subject property at an agreed contract price approximately 3 years ago. You must establish market value as of that historical date (36 months ago). The current market has appreciated approximately 38% since that date.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 2
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'With the current market at 38% above the retroactive effective date (36 months ago), the temporal distinction is the defining issue. C1 (37 mo.), C2 (35 mo., 1 mo. post-date with no change), and C3 (38 mo.) all reflect what the property was actually worth when the disputed transaction should have occurred ($341k–$355k). C4 and C5 rejected — current market sales with 38% appreciation; using them would overstate historical value by ~$130k. C6 — relocation buyout at effective date, non-arm''s length. C7 — Pinecrest Estates is a non-competing market area despite physical and temporal similarity. C8 acceptable as supplementary support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"reject","C8":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, 37 mo. ago (1 mo. before effective date), arm''s length. Squarely contemporaneous with the retroactive date.","C2":"Strong comp — adjacent competing sub, 35 mo. ago (1 mo. after effective date, no market change), arm''s length. Minor GLA adj (+40 SF).","C3":"Good comp — same sub, 38 mo. ago (2 mo. before effective date), arm''s length. Slightly older at 38 months; within the acceptable range.","C4":"Reject — sold 2 mo. ago. Current market is ~38% above the retroactive value date. Using this sale would overstate the historical value by approximately $130,000.","C5":"Reject — current market with 38% appreciation over the retroactive effective date. In a breach of contract case, the value must reflect what the property was worth when the wrong occurred, not today.","C6":"Reject — relocation/employer buyout at the effective date. Non-arm''s length; retroactive litigation appraisals require arm''s length verification for the historical baseline.","C7":"Reject — 1.8 miles in a non-competing neighborhood. Physically similar and contemporaneous, but buyers for the subject would not consider Pinecrest Estates a market alternative.","C8":"Acceptable — 39 mo. ago (3 mo. before effective date), arm''s length. Slightly older at 39 months; C1–C3 are more directly contemporaneous but this sale supports the historical value range."},"justification":"With the current market at 38% above the retroactive effective date (36 months ago), the temporal distinction is the defining issue. C1 (37 mo.), C2 (35 mo., 1 mo. post-date with no change), and C3 (38 mo.) all reflect what the property was actually worth when the disputed transaction should have occurred ($341k–$355k). C4 and C5 rejected — current market sales with 38% appreciation; using them would overstate historical value by ~$130k. C6 — relocation buyout at effective date, non-arm''s length. C7 — Pinecrest Estates is a non-competing market area despite physical and temporal similarity. C8 acceptable as supplementary support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"512 Lakeview Court","prox":"0.4 mi","sub":"Lakeview Commons","price":348000,"date":"37 months ago","style":"Ranch","bed":3,"bath":2,"gla":1740,"site":"8,200 SF","yr":2008,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C2","addr":"814 Greenway Drive","prox":"0.7 mi","sub":"Greenway Estates","price":355000,"date":"35 months ago","style":"Ranch","bed":3,"bath":2,"gla":1820,"site":"8,700 SF","yr":2010,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C3","addr":"119 Lakeview Drive","prox":"0.5 mi","sub":"Lakeview Commons","price":341000,"date":"38 months ago","style":"Ranch","bed":3,"bath":2,"gla":1760,"site":"8,400 SF","yr":2008,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"721 Lakeview Way","prox":"0.5 mi","sub":"Lakeview Commons","price":481000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1775,"site":"8,300 SF","yr":2009,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C5","addr":"412 Greenway Circle","prox":"0.7 mi","sub":"Greenway Estates","price":469000,"date":"4 months ago","style":"Ranch","bed":3,"bath":2,"gla":1800,"site":"8,600 SF","yr":2009,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C6","addr":"88 Lakeview Court","prox":"0.4 mi","sub":"Lakeview Commons","price":361000,"date":"36 months ago","style":"Ranch","bed":3,"bath":2,"gla":1790,"site":"8,400 SF","yr":2010,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Relocation company buyout","warn":true},{"id":"C7","addr":"319 Pinecrest Drive","prox":"1.8 mi","sub":"Pinecrest Estates","price":352000,"date":"36 months ago","style":"Ranch","bed":3,"bath":2,"gla":1755,"site":"8,300 SF","yr":2008,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C8","addr":"614 Greenway Drive","prox":"0.8 mi","sub":"Greenway Estates","price":346000,"date":"39 months ago","style":"Ranch","bed":3,"bath":2,"gla":1810,"site":"8,600 SF","yr":2009,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false}],"rejection_reasons":["Sale post-dates retrospective effective date","Sale reflects post-event market conditions","Sale too old — pre-dates effective date","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Outside subject market area","Inadequate verification / data","Other"],"subject":{"address":"3214 Lakeview Drive","subdivision":"Lakeview Commons","style":"Ranch","bed":3,"bath":2,"gla":1780,"site":"8,500 SF","yr":2009,"cond":"C3","qual":"Q4","garage":"2-car attached","bsmt":"None","pool":"None"}}'::jsonb
