-- Scenario 2.9: Foreclosure Challenge — Date of Sheriff's Sale
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 9, 'advanced', 'Foreclosure Challenge — Date of Sheriff''s Sale', 'You have been retained by the borrower''s counsel to establish market value as of the date of a contested foreclosure/sheriff''s sale (11 months ago). The borrower alleges the $248,000 sheriff''s sale price was grossly inadequate compared to actual market value, and seeks to have the sale set aside. Your opinion must reflect arm''s length market conditions as of the date of the forced sale.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 2
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'The effective date is the sheriff''s sale date (11 months ago). C1 ($295k), C2 ($301k), and C3 ($289k) establish a market value range of $289k–$301k, compared to the contested $248k bid — strong evidence the bid was grossly inadequate. C4 rejected — post-sale current market. C5 — another sheriff''s/foreclosure sale; cannot use distressed forced-sale prices in a proceeding that challenges whether such prices represent market value. C6 — relocation buyout, non-arm''s length. C7 — 26 months old. C8 acceptable as supplementary support corroborating the market-value range.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"reject","C8":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, 12 mo. ago (1 mo. before sheriff''s sale), arm''s length. Establishes that $295k was fair market value at the time of the contested sale.","C2":"Strong comp — adjacent sub, 10 mo. ago (1 mo. after sheriff''s sale, no post-sale market change), arm''s length. Minor GLA adj (+30 SF).","C3":"Good comp — same sub, 13 mo. ago (2 mo. before sale), arm''s length. Seller concession adj required. Combined with C1 and C2, establishes fair market value ~$47k above the contested sheriff''s bid.","C4":"Reject — sold 1 mo. ago, 10 months post-sheriff''s sale. Reflects current market conditions, not conditions at the date of the contested foreclosure.","C5":"Reject — another sheriff''s / foreclosure sale at the same time. Cannot use distressed forced-sale prices as comparable evidence in a proceeding that challenges whether foreclosure pricing reflects market value.","C6":"Reject — relocation buyout contemporaneous with sheriff''s sale. Non-arm''s length; in a foreclosure challenge the value standard is arm''s length market value, not distressed or institutional transaction prices.","C7":"Reject — 26 mo. old; sold 15 months before the sheriff''s sale. Does not adequately reflect conditions prevailing at the date of the foreclosure.","C8":"Acceptable — sold at sheriff''s sale date, arm''s length. Farther at 1.1 mi; C1–C3 provide more direct support but this sale confirms the market-value range and the inadequacy of the $248k bid."},"justification":"The effective date is the sheriff''s sale date (11 months ago). C1 ($295k), C2 ($301k), and C3 ($289k) establish a market value range of $289k–$301k, compared to the contested $248k bid — strong evidence the bid was grossly inadequate. C4 rejected — post-sale current market. C5 — another sheriff''s/foreclosure sale; cannot use distressed forced-sale prices in a proceeding that challenges whether such prices represent market value. C6 — relocation buyout, non-arm''s length. C7 — 26 months old. C8 acceptable as supplementary support corroborating the market-value range."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"814 Pinehurst Court","prox":"0.4 mi","sub":"Pinehurst Estates","price":295000,"date":"12 months ago","style":"Ranch","bed":3,"bath":2,"gla":1620,"site":"7,800 SF","yr":2005,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C2","addr":"421 Hillside Drive","prox":"0.7 mi","sub":"Hillside Estates","price":301000,"date":"10 months ago","style":"Ranch","bed":3,"bath":2,"gla":1680,"site":"8,200 SF","yr":2007,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C3","addr":"119 Pinehurst Drive","prox":"0.5 mi","sub":"Pinehurst Estates","price":289000,"date":"13 months ago","style":"Ranch","bed":3,"bath":2,"gla":1630,"site":"7,900 SF","yr":2006,"cond":"C3","qual":"Q4","conc":"$2,500 seller paid","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"614 Pinehurst Way","prox":"0.5 mi","sub":"Pinehurst Estates","price":311000,"date":"1 month ago","style":"Ranch","bed":3,"bath":2,"gla":1660,"site":"8,000 SF","yr":2007,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C5","addr":"88 Hillside Court","prox":"0.7 mi","sub":"Hillside Estates","price":248000,"date":"11 months ago","style":"Ranch","bed":3,"bath":2,"gla":1640,"site":"7,900 SF","yr":2005,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Sheriff''s / foreclosure sale","warn":true},{"id":"C6","addr":"721 Pinehurst Blvd","prox":"0.5 mi","sub":"Pinehurst Estates","price":285000,"date":"11 months ago","style":"Ranch","bed":3,"bath":2,"gla":1655,"site":"7,900 SF","yr":2006,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Relocation company buyout — employer purchase","warn":true},{"id":"C7","addr":"215 Pinehurst Court","prox":"0.4 mi","sub":"Pinehurst Estates","price":278000,"date":"26 months ago","style":"Ranch","bed":3,"bath":2,"gla":1645,"site":"7,800 SF","yr":2006,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C8","addr":"512 Meadowbrook Lane","prox":"1.1 mi","sub":"Meadowbrook Estates","price":293000,"date":"11 months ago","style":"Ranch","bed":3,"bath":2,"gla":1670,"site":"8,100 SF","yr":2007,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false}],"rejection_reasons":["Sale post-dates retrospective effective date","Sale reflects post-event market conditions","Sale too old — pre-dates effective date","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Outside subject market area","Inadequate verification / data","Other"],"subject":{"address":"2417 Pinehurst Drive","subdivision":"Pinehurst Estates","style":"Ranch","bed":3,"bath":2,"gla":1650,"site":"8,000 SF","yr":2006,"cond":"C3","qual":"Q4","garage":"2-car attached","bsmt":"None","pool":"None"}}'::jsonb
