-- Scenario 2.10: Opposing Expert Appraisal — Contested Comparable Pool
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 10, 'advanced', 'Opposing Expert Appraisal — Contested Comparable Pool', 'You are serving as a court-appointed neutral expert appraiser in a complex property dispute. Both plaintiff''s and defendant''s appraisers have submitted competing comparable pools. You have been given the combined pool of 8 sales and must independently evaluate each on its merits — rejecting cherry-picks from both sides and selecting only the most appropriate. Effective date: 24 months ago. Market has risen approximately 14% since that date.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 2
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'As a neutral expert, the test is consistent: arm''s length sales contemporaneous with the effective date (24 months ago) within the subject''s competing market. C1 (plaintiff''s, 26 mo., same sub), C2 (defendant''s, 23 mo., adjacent sub), and C3 (defendant''s, at effective date) meet all criteria and form a coherent value range of $541k–$558k — regardless of who submitted them. C4 rejected — plaintiff''s current-market cherry-pick with 14% appreciation. C5 — plaintiff''s superior-neighborhood cherry-pick using a non-competing luxury enclave. C6 — defendant''s REO anchor to deflate value; distressed pricing. C7 — plaintiff''s builder/LLC sale, non-arm''s length. A neutral expert methodically rejects the inflated and deflated cherry-picks from both sides.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"reject","C8":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, 26 mo. ago (2 mo. before effective date), arm''s length, pool. Submitted by plaintiff''s appraiser; appropriate on its own merits.","C2":"Strong comp — adjacent competing sub, 23 mo. ago (1 mo. after effective date, no change), arm''s length, pool. Minor GLA adj (+60 SF). Submitted by defendant; appropriate on its own merits.","C3":"Good comp — adjacent sub, at effective date (24 mo. ago), arm''s length, pool. Half-bath adjustment needed. Submitted by defendant; appropriate on its own merits.","C4":"Reject — current market sale, 22 months post-effective date, with ~14% appreciation embedded. Submitted by plaintiff''s appraiser; this is a classic cherry-pick to inflate the retroactive value.","C5":"Reject — Grandview Estates is a demonstrably superior luxury market with a different buyer pool. Submitted by plaintiff''s appraiser to anchor the value high; using a competing superior market area inflates the retrospective value.","C6":"Reject — bank-owned REO at the effective date. Submitted by defendant''s appraiser to anchor the value low; distressed pricing does not reflect arm''s length market value regardless of timing.","C7":"Reject — builder sold to an LLC under common family ownership; non-arm''s length. Submitted by plaintiff''s appraiser as a high-end comp but fails the arm''s length test required in litigation, regardless of price proximity.","C8":"Acceptable — adjacent sub, 26 mo. ago, arm''s length, pool. Larger lot (+0.05 ac.) and GLA (+70 SF) adjustments needed. Submitted by defendant; appropriate on its merits; C1–C3 provide more direct comparisons."},"justification":"As a neutral expert, the test is consistent: arm''s length sales contemporaneous with the effective date (24 months ago) within the subject''s competing market. C1 (plaintiff''s, 26 mo., same sub), C2 (defendant''s, 23 mo., adjacent sub), and C3 (defendant''s, at effective date) meet all criteria and form a coherent value range of $541k–$558k — regardless of who submitted them. C4 rejected — plaintiff''s current-market cherry-pick with 14% appreciation. C5 — plaintiff''s superior-neighborhood cherry-pick using a non-competing luxury enclave. C6 — defendant''s REO anchor to deflate value; distressed pricing. C7 — plaintiff''s builder/LLC sale, non-arm''s length. A neutral expert methodically rejects the inflated and deflated cherry-picks from both sides."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"512 Heritage Court","prox":"0.5 mi","sub":"Heritage Estates","price":548000,"date":"26 months ago","style":"Colonial","bed":4,"bath":3,"gla":2280,"site":"0.48 acres","yr":2005,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS (plaintiff''s appraiser)","warn":false},{"id":"C2","addr":"814 Ridgewood Manor","prox":"0.8 mi","sub":"Ridgewood Manor","price":558000,"date":"23 months ago","style":"Colonial","bed":4,"bath":3,"gla":2410,"site":"0.52 acres","yr":2007,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS (defendant''s appraiser)","warn":false},{"id":"C3","addr":"109 Crestview Circle","prox":"0.7 mi","sub":"Crestview Estates","price":541000,"date":"24 months ago","style":"Colonial","bed":4,"bath":"2.5","gla":2320,"site":"0.47 acres","yr":2006,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS (defendant''s appraiser)","warn":false},{"id":"C4","addr":"721 Heritage Way","prox":"0.5 mi","sub":"Heritage Estates","price":635000,"date":"2 months ago","style":"Colonial","bed":4,"bath":3,"gla":2370,"site":"0.50 acres","yr":2007,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS (plaintiff''s appraiser)","warn":false},{"id":"C5","addr":"88 Grandview Place","prox":"2.2 mi","sub":"Grandview Estates (luxury enclave)","price":592000,"date":"24 months ago","style":"Colonial","bed":4,"bath":3,"gla":2360,"site":"0.50 acres","yr":2006,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS (plaintiff''s appraiser)","warn":false},{"id":"C6","addr":"312 Heritage Drive","prox":"0.5 mi","sub":"Heritage Estates","price":498000,"date":"24 months ago","style":"Colonial","bed":4,"bath":3,"gla":2310,"site":"0.48 acres","yr":2005,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Bank-owned REO (defendant''s appraiser)","warn":true},{"id":"C7","addr":"419 Heritage Blvd","prox":"0.6 mi","sub":"Heritage Estates","price":553000,"date":"24 months ago","style":"Colonial","bed":4,"bath":3,"gla":2380,"site":"0.50 acres","yr":2006,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Builder sold to LLC (common family ownership) — plaintiff''s appraiser","warn":true},{"id":"C8","addr":"617 Ridgewood Circle","prox":"0.9 mi","sub":"Ridgewood Manor","price":545000,"date":"26 months ago","style":"Colonial","bed":4,"bath":3,"gla":2420,"site":"0.55 acres","yr":2005,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS (defendant''s appraiser)","warn":false}],"rejection_reasons":["Sale post-dates retrospective effective date","Sale reflects post-event market conditions","Sale too old — pre-dates effective date","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Outside subject market area","Inadequate verification / data","Other"],"subject":{"address":"4821 Heritage Drive","subdivision":"Heritage Estates","style":"Colonial","bed":4,"bath":3,"gla":2350,"site":"0.50 acres","yr":2006,"cond":"C2","qual":"Q4","garage":"3-car attached","bsmt":"Finished","pool":"Pool"}}'::jsonb
FROM ins,
  module_sections ms
  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- ─────────────── Category 3: Estate & Tax ───────────────
-- Scenario 3.1: Estate Tax — Date of Death, Standard SFR
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 1, 'basic', 'Estate Tax — Date of Death, Standard SFR', 'You have been engaged by the estate executor to establish fair market value as of the date of death (14 months ago) for federal estate tax purposes (IRS Form 706). The current market has appreciated approximately 9% since the date of death. IRS regulations require value as of the date of death — not today''s market.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 3
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'For IRS Form 706 estate tax, value must be as of the date of death (14 months ago). C1 (16 mo., same sub), C2 (13 mo., adjacent sub), and C3 (15 mo., same sub, concession adj) are all within 3 months and arm''s length ($318k–$325k). C4 and C5 rejected — current sales with 9% appreciation; using them would overstate the taxable estate value and expose the executor to IRS penalties. C6 — 27 months old. C7 — court-confirmed estate sale; circular reasoning in a Form 706 appraisal. C8 acceptable as secondary support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"reject","C8":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, 16 mo. ago (2 mo. before death date), arm''s length. Reflects date-of-death market conditions.","C2":"Strong comp — adjacent sub, 13 mo. ago (1 mo. after death, no market change), arm''s length. Minor GLA adj (+40 SF).","C3":"Good comp — same sub, 15 mo. ago (1 mo. before death), arm''s length. Seller concession adjustment required.","C4":"Reject — sold 2 mo. ago, 12 months post-death. Reflects ~9% current appreciation. Overstates date-of-death value; IRS requires value as of death, not current market.","C5":"Reject — sold 3 mo. ago; post-dates the date of death by 11 months. Current market conditions are embedded in this price.","C6":"Reject — 27 mo. old; sold 13 months before the date of death. Insufficient temporal proximity to the retrospective effective date.","C7":"Reject — court-confirmed estate sale contemporaneous with the death date. Using another estate sale in a Form 706 appraisal is circular reasoning; both values may reflect estate pricing rather than open-market conditions.","C8":"Acceptable — sold 12 mo. ago (2 mo. post-death, no market change), arm''s length. Farther at 1.1 mi; C1–C3 more directly comparable."},"justification":"For IRS Form 706 estate tax, value must be as of the date of death (14 months ago). C1 (16 mo., same sub), C2 (13 mo., adjacent sub), and C3 (15 mo., same sub, concession adj) are all within 3 months and arm''s length ($318k–$325k). C4 and C5 rejected — current sales with 9% appreciation; using them would overstate the taxable estate value and expose the executor to IRS penalties. C6 — 27 months old. C7 — court-confirmed estate sale; circular reasoning in a Form 706 appraisal. C8 acceptable as secondary support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"312 Elmwood Drive","prox":"0.4 mi","sub":"Elmwood Heights","price":318000,"date":"16 months ago","style":"Ranch","bed":3,"bath":2,"gla":1580,"site":"7,200 SF","yr":2003,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C2","addr":"541 Briarwood Circle","prox":"0.7 mi","sub":"Briarwood Estates","price":325000,"date":"13 months ago","style":"Ranch","bed":3,"bath":2,"gla":1660,"site":"7,600 SF","yr":2005,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C3","addr":"108 Elmwood Court","prox":"0.5 mi","sub":"Elmwood Heights","price":321000,"date":"15 months ago","style":"Ranch","bed":3,"bath":2,"gla":1605,"site":"7,400 SF","yr":2004,"cond":"C3","qual":"Q4","conc":"$2,000 seller paid","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"719 Elmwood Way","prox":"0.6 mi","sub":"Elmwood Heights","price":352000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1630,"site":"7,300 SF","yr":2005,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C5","addr":"88 Briarwood Drive","prox":"0.7 mi","sub":"Briarwood Estates","price":347000,"date":"3 months ago","style":"Ranch","bed":3,"bath":2,"gla":1610,"site":"7,400 SF","yr":2004,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C6","addr":"421 Ridgewood Lane","prox":"0.8 mi","sub":"Ridgewood Park","price":298000,"date":"27 months ago","style":"Ranch","bed":3,"bath":2,"gla":1640,"site":"7,500 SF","yr":2003,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C7","addr":"215 Elmwood Lane","prox":"0.4 mi","sub":"Elmwood Heights","price":322000,"date":"14 months ago","style":"Ranch","bed":3,"bath":2,"gla":1595,"site":"7,200 SF","yr":2003,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Court-confirmed estate sale","warn":true},{"id":"C8","addr":"877 Oakdale Drive","prox":"1.1 mi","sub":"Oakdale Commons","price":316000,"date":"12 months ago","style":"Ranch","bed":3,"bath":2,"gla":1650,"site":"7,700 SF","yr":2005,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false}],"rejection_reasons":["Sale post-dates retrospective effective date","Sale too old — pre-dates effective date","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Reflects encumbered / restricted-use value","Insufficient physical similarity","Outside subject market area","Inadequate verification / data","Other"],"subject":{"address":"2847 Elmwood Court","subdivision":"Elmwood Heights","style":"Ranch","bed":3,"bath":2,"gla":1620,"site":"7,500 SF","yr":2004,"cond":"C3","qual":"Q4","garage":"2-car attached","bsmt":"None","pool":"None"}}'::jsonb
