-- Scenario 3.2: Gift Tax — Intra-Family Transfer
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 2, 'basic', 'Gift Tax — Intra-Family Transfer', 'You have been engaged by the taxpayers'' counsel to establish fair market value as of the date of deed transfer (9 months ago) for IRS Form 709 gift tax reporting. The parents transferred their lakeside vacation home to their adult child. The current market has appreciated approximately 6% since the transfer date. IRS requires value as of the date of the gift.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 3
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'For IRS Form 709 gift tax, value must be as of the date of deed transfer (9 months ago). C1 (10 mo., same sub), C2 (8 mo., adjacent area), and C3 (11 mo., same sub, concession adj) are all within 3 months and arm''s length. C4 and C5 rejected — post-transfer current market (+6%). C6 — 24 months old. C7 — another parent-to-child transfer; using a similar non-arm''s length intra-family transaction to value an intra-family gift creates a circular, unreliable basis for IRS reporting. C8 acceptable as secondary support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"reject","C8":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, 10 mo. ago (1 mo. before transfer), arm''s length. Reflects gift-date market conditions.","C2":"Strong comp — adjacent area, 8 mo. ago (1 mo. after transfer, no market change), arm''s length. Minor GLA and site adjustments.","C3":"Good comp — same sub, 11 mo. ago (2 mo. before transfer), arm''s length. Seller concession adjustment required.","C4":"Reject — sold 2 mo. ago, 7 months post-transfer. Reflects ~6% current appreciation; using it would overstate the gift value and potentially create excess gift tax liability.","C5":"Reject — sold 1 mo. ago; post-dates the gift transfer by 8 months. Current market conditions are not appropriate for a Form 709 retrospective value.","C6":"Reject — 24 mo. old; sold 15 months before the transfer date. Does not reflect conditions as of the gift date.","C7":"Reject — another intra-family parent-to-child transfer contemporaneous with the subject gift. Non-arm''s length; using a similar non-arm''s length transaction to value a non-arm''s length gift is circular and unreliable for IRS purposes.","C8":"Acceptable — sold at transfer date, arm''s length. Farther at 1.2 mi; C1–C3 more directly comparable but this confirms the gift-date value range."},"justification":"For IRS Form 709 gift tax, value must be as of the date of deed transfer (9 months ago). C1 (10 mo., same sub), C2 (8 mo., adjacent area), and C3 (11 mo., same sub, concession adj) are all within 3 months and arm''s length. C4 and C5 rejected — post-transfer current market (+6%). C6 — 24 months old. C7 — another parent-to-child transfer; using a similar non-arm''s length intra-family transaction to value an intra-family gift creates a circular, unreliable basis for IRS reporting. C8 acceptable as secondary support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"408 Lakeview Court","prox":"0.4 mi","sub":"Lakeview Shores","price":312000,"date":"10 months ago","style":"Ranch","bed":3,"bath":2,"gla":1450,"site":"0.33 acres","yr":2000,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C2","addr":"821 Clearwater Drive","prox":"0.7 mi","sub":"Clearwater Shores","price":318000,"date":"8 months ago","style":"Ranch","bed":3,"bath":2,"gla":1520,"site":"0.37 acres","yr":2002,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C3","addr":"217 Lakeview Lane","prox":"0.5 mi","sub":"Lakeview Shores","price":308000,"date":"11 months ago","style":"Ranch","bed":3,"bath":2,"gla":1465,"site":"0.34 acres","yr":2001,"cond":"C3","qual":"Q4","conc":"$1,500 seller paid","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"542 Clearwater Blvd","prox":"0.6 mi","sub":"Clearwater Shores","price":336000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1490,"site":"0.35 acres","yr":2002,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C5","addr":"119 Lakeview Drive","prox":"0.4 mi","sub":"Lakeview Shores","price":341000,"date":"1 month ago","style":"Ranch","bed":3,"bath":2,"gla":1475,"site":"0.34 acres","yr":2001,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C6","addr":"715 Clearwater Court","prox":"0.7 mi","sub":"Clearwater Shores","price":295000,"date":"24 months ago","style":"Ranch","bed":3,"bath":2,"gla":1500,"site":"0.36 acres","yr":2000,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C7","addr":"88 Lakeview Court","prox":"0.3 mi","sub":"Lakeview Shores","price":305000,"date":"9 months ago","style":"Ranch","bed":3,"bath":2,"gla":1460,"site":"0.33 acres","yr":2000,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Parent-to-child family transfer — per deed","warn":true},{"id":"C8","addr":"412 Shoreline Way","prox":"1.2 mi","sub":"Shoreline Estates","price":315000,"date":"9 months ago","style":"Ranch","bed":3,"bath":2,"gla":1505,"site":"0.38 acres","yr":2002,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false}],"rejection_reasons":["Sale post-dates retrospective effective date","Sale too old — pre-dates effective date","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Reflects encumbered / restricted-use value","Insufficient physical similarity","Outside subject market area","Inadequate verification / data","Other"],"subject":{"address":"1842 Lakeview Drive","subdivision":"Lakeview Shores","style":"Ranch","bed":3,"bath":2,"gla":1480,"site":"0.35 acres","yr":2001,"cond":"C3","qual":"Q4","garage":"2-car attached","bsmt":"None","pool":"None"}}'::jsonb
