WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 3, 'intermediate', 'Charitable Contribution — IRS Form 8283', 'You have been engaged to provide a qualified appraisal of a residential property donated to an affordable housing non-profit as of the date of donation (12 months ago) for IRS Form 8283. IRS regulations require the qualified appraisal to use contemporaneous arm''s length sales. The current market has risen ~7% since the donation date. An inflated deduction supported by post-donation comps could trigger IRS penalties.'
