INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'For an IRS Form 8283 qualified appraisal, value is as of the donation date (12 months ago) and must use contemporaneous arm''s length sales. C1 (13 mo., same sub), C2 (11 mo., adjacent sub), and C3 (14 mo., same sub, concession adj) meet both requirements. C4 and C5 rejected — post-donation current market (+7%); an inflated donation value creates an inflated tax deduction that risks IRS penalties. C6 — 26 months old. C7 — REO foreclosure at donation date; distressed sale fails the qualified appraisal standard. C8 acceptable as secondary support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"reject","C8":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, 13 mo. ago (1 mo. before donation), arm''s length. Reflects pre-donation market conditions.","C2":"Strong comp — adjacent sub, 11 mo. ago (1 mo. post-donation, no market change), arm''s length. Minor GLA adj (+30 SF).","C3":"Good comp — same sub, 14 mo. ago (2 mo. before donation), arm''s length. Seller concession adjustment required.","C4":"Reject — sold 2 mo. ago, 10 months post-donation. Reflects ~7% current appreciation. Using post-donation sales would inflate the charitable deduction, which is exactly the IRS concern in Form 8283 reviews.","C5":"Reject — sold 3 mo. ago, post-donation date. An inflated deduction from post-donation comps risks IRS penalties under IRC Section 6662.","C6":"Reject — 26 mo. old; sold 14 months before the donation. IRS scrutiny on Form 8283 appraisals is high; temporal accuracy is essential.","C7":"Reject — bank-owned REO contemporaneous with the donation date. Distressed pricing does not meet the arm''s length standard required for a qualified charitable contribution appraisal.","C8":"Acceptable — sold 11 mo. ago (1 mo. post-donation, no change), arm''s length. Farther at 1.0 mi; C1–C3 provide stronger direct support."},"justification":"For an IRS Form 8283 qualified appraisal, value is as of the donation date (12 months ago) and must use contemporaneous arm''s length sales. C1 (13 mo., same sub), C2 (11 mo., adjacent sub), and C3 (14 mo., same sub, concession adj) meet both requirements. C4 and C5 rejected — post-donation current market (+7%); an inflated donation value creates an inflated tax deduction that risks IRS penalties. C6 — 26 months old. C7 — REO foreclosure at donation date; distressed sale fails the qualified appraisal standard. C8 acceptable as secondary support."}'::jsonb,
