  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- Scenario 3.4: Estate Tax — Post-Peak Market Decline
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 4, 'intermediate', 'Estate Tax — Post-Peak Market Decline', 'You have been engaged by the estate executor for IRS Form 706 purposes. The decedent died 24 months ago, when the local market was near its peak. The market has since declined approximately 12%, meaning current sales reflect LOWER values than the date-of-death market. Your opinion must still reflect the date-of-death value — even though it will be higher than current market evidence.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 3
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'This scenario reverses the typical pattern. The market has DECLINED 12% since the date of death (24 months ago), so current sales now reflect LOWER values. C1 (26 mo.), C2 (22 mo., 2 mo. post-death before decline), and C3 (25 mo.) reflect peak-market conditions at the date of death ($421k–$435k). C4 and C5 rejected — current market at ~$376k–$381k; using them would understate the estate value and under-report tax liability. C6 — 38 months old, pre-dates the peak. C7 — builder/LLC transaction, non-arm''s length. C8 acceptable as supplementary support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"reject","C8":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, 26 mo. ago (2 mo. before death), arm''s length. Reflects peak-market conditions as of the date of death.","C2":"Strong comp — adjacent sub, 22 mo. ago (2 mo. after death, no post-death market shift at that time), arm''s length. Minor GLA adj (+50 SF).","C3":"Good comp — same sub, 25 mo. ago (1 mo. before death), arm''s length. Extra full bath requires adjustment.","C4":"Reject — sold 2 mo. ago; current market is ~12% below the date-of-death value. Using current comps would understate the date-of-death FMV, under-reporting estate tax liability and creating IRS compliance risk.","C5":"Reject — current market reflecting post-peak decline. In a declining post-death market, current sales understate the date-of-death value. The estate executor is still legally required to report the higher date-of-death FMV.","C6":"Reject — 38 mo. old; sold 14 months before the date of death, before the peak conditions. Does not reflect date-of-death market conditions.","C7":"Reject — builder sold to its own LLC; non-arm''s length. IRS Form 706 requires arm''s length transactions for the FMV determination.","C8":"Acceptable — sold at date of death (24 mo.), arm''s length. Farther at 1.0 mi; C1–C3 more directly comparable."},"justification":"This scenario reverses the typical pattern. The market has DECLINED 12% since the date of death (24 months ago), so current sales now reflect LOWER values. C1 (26 mo.), C2 (22 mo., 2 mo. post-death before decline), and C3 (25 mo.) reflect peak-market conditions at the date of death ($421k–$435k). C4 and C5 rejected — current market at ~$376k–$381k; using them would understate the estate value and under-report tax liability. C6 — 38 months old, pre-dates the peak. C7 — builder/LLC transaction, non-arm''s length. C8 acceptable as supplementary support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"812 Summit Court","prox":"0.5 mi","sub":"Summit Heights","price":428000,"date":"26 months ago","style":"Colonial","bed":4,"bath":"2.5","gla":2100,"site":"8,900 SF","yr":1998,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C2","addr":"421 Ridgeline Drive","prox":"0.7 mi","sub":"Ridgeline Estates","price":435000,"date":"22 months ago","style":"Colonial","bed":4,"bath":"2.5","gla":2200,"site":"9,500 SF","yr":2000,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C3","addr":"119 Summit Way","prox":"0.4 mi","sub":"Summit Heights","price":421000,"date":"25 months ago","style":"Colonial","bed":4,"bath":3,"gla":2170,"site":"9,100 SF","yr":1999,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"714 Summit Blvd","prox":"0.5 mi","sub":"Summit Heights","price":381000,"date":"2 months ago","style":"Colonial","bed":4,"bath":"2.5","gla":2130,"site":"9,000 SF","yr":2000,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C5","addr":"88 Ridgeline Court","prox":"0.8 mi","sub":"Ridgeline Estates","price":376000,"date":"3 months ago","style":"Colonial","bed":4,"bath":"2.5","gla":2155,"site":"9,200 SF","yr":1999,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C6","addr":"312 Summit Lane","prox":"0.5 mi","sub":"Summit Heights","price":392000,"date":"38 months ago","style":"Colonial","bed":4,"bath":"2.5","gla":2120,"site":"8,800 SF","yr":1998,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C7","addr":"619 Ridgeline Blvd","prox":"0.8 mi","sub":"Ridgeline Estates","price":429000,"date":"24 months ago","style":"Colonial","bed":4,"bath":"2.5","gla":2180,"site":"9,300 SF","yr":2000,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Builder sold to own LLC — per deed","warn":true},{"id":"C8","addr":"217 Crestwood Drive","prox":"1.0 mi","sub":"Crestwood Park","price":424000,"date":"24 months ago","style":"Colonial","bed":4,"bath":"2.5","gla":2195,"site":"9,400 SF","yr":2000,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false}],"rejection_reasons":["Sale post-dates retrospective effective date","Sale too old — pre-dates effective date","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Reflects encumbered / restricted-use value","Insufficient physical similarity","Outside subject market area","Inadequate verification / data","Other"],"subject":{"address":"3518 Summit Drive","subdivision":"Summit Heights","style":"Colonial","bed":4,"bath":"2.5","gla":2150,"site":"9,200 SF","yr":1999,"cond":"C3","qual":"Q4","garage":"2-car attached","bsmt":"Partial","pool":"None"}}'::jsonb
FROM ins,
