  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- Scenario 3.5: Step-Up in Basis — Long Retrospective Date
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 5, 'intermediate', 'Step-Up in Basis — Long Retrospective Date', 'Heirs who inherited and then sold a property need to establish the stepped-up basis (fair market value at date of death, 36 months ago) for capital gains tax reporting. The market has risen approximately 25% since the date of death. Establishing a higher date-of-death basis reduces capital gains; IRS scrutinizes large basis claims and cross-checks them against the original estate appraisal if one exists.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 3
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'For a capital gains step-up-in-basis calculation, FMV at date of death (36 months ago) is the baseline. C1 (38 mo.), C2 (35 mo.), and C3 (37 mo.) reflect date-of-death market conditions ($408k–$418k). C4 and C5 rejected — current market at $515k–$521k, 25% above the historical value; overstating the step-up basis improperly reduces reportable capital gains and IRS penalties may follow. C6 — 52 months old, pre-dates death by 16 months. C7 — non-competing market area. C8 acceptable as supplementary support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"reject","C8":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, 38 mo. ago (2 mo. before death), arm''s length. Reflects date-of-death market conditions.","C2":"Strong comp — adjacent sub, 35 mo. ago (1 mo. after death, no change at that point), arm''s length. Minor GLA adj (+50 SF).","C3":"Good comp — same sub, 37 mo. ago (1 mo. before death), arm''s length. Half-bath adjustment needed.","C4":"Reject — current market at 25% above the date-of-death value. Overstating the step-up basis reduces reportable capital gains; IRS cross-checks basis claims and may penalize inflated values.","C5":"Reject — current market with 25% appreciation above the retrospective date. An inflated step-up basis allows heirs to eliminate more capital gains than is legally supportable.","C6":"Reject — 52 mo. old; sold 16 months before the date of death. Does not reflect conditions at the retrospective effective date.","C7":"Reject — 1.8 miles in Oakdale Heights, a non-competing market area. Despite temporal and physical similarity, buyers for the subject would not consider this an alternative location.","C8":"Acceptable — 38 mo. ago (2 mo. before death), arm''s length. Slightly larger GLA (+85 SF) and farther; C1–C3 more directly comparable but this supports the range."},"justification":"For a capital gains step-up-in-basis calculation, FMV at date of death (36 months ago) is the baseline. C1 (38 mo.), C2 (35 mo.), and C3 (37 mo.) reflect date-of-death market conditions ($408k–$418k). C4 and C5 rejected — current market at $515k–$521k, 25% above the historical value; overstating the step-up basis improperly reduces reportable capital gains and IRS penalties may follow. C6 — 52 months old, pre-dates death by 16 months. C7 — non-competing market area. C8 acceptable as supplementary support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"812 Maplewood Court","prox":"0.5 mi","sub":"Maplewood Estates","price":412000,"date":"38 months ago","style":"Two-Story","bed":4,"bath":3,"gla":2260,"site":"9,700 SF","yr":2001,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C2","addr":"421 Pinewood Drive","prox":"0.7 mi","sub":"Pinewood Estates","price":418000,"date":"35 months ago","style":"Two-Story","bed":4,"bath":3,"gla":2350,"site":"10,300 SF","yr":2003,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C3","addr":"119 Maplewood Lane","prox":"0.4 mi","sub":"Maplewood Estates","price":408000,"date":"37 months ago","style":"Two-Story","bed":4,"bath":"2.5","gla":2280,"site":"9,800 SF","yr":2002,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"714 Maplewood Blvd","prox":"0.5 mi","sub":"Maplewood Estates","price":521000,"date":"2 months ago","style":"Two-Story","bed":4,"bath":3,"gla":2310,"site":"9,900 SF","yr":2003,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C5","addr":"88 Pinewood Court","prox":"0.7 mi","sub":"Pinewood Estates","price":515000,"date":"3 months ago","style":"Two-Story","bed":4,"bath":3,"gla":2330,"site":"10,200 SF","yr":2002,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C6","addr":"312 Maplewood Way","prox":"0.5 mi","sub":"Maplewood Estates","price":375000,"date":"52 months ago","style":"Two-Story","bed":4,"bath":3,"gla":2290,"site":"9,800 SF","yr":2001,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C7","addr":"619 Oakdale Drive","prox":"1.8 mi","sub":"Oakdale Heights","price":414000,"date":"37 months ago","style":"Two-Story","bed":4,"bath":3,"gla":2315,"site":"10,100 SF","yr":2002,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C8","addr":"217 Pinewood Lane","prox":"0.8 mi","sub":"Pinewood Estates","price":415000,"date":"38 months ago","style":"Two-Story","bed":4,"bath":3,"gla":2385,"site":"10,400 SF","yr":2002,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false}],"rejection_reasons":["Sale post-dates retrospective effective date","Sale too old — pre-dates effective date","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Reflects encumbered / restricted-use value","Insufficient physical similarity","Outside subject market area","Inadequate verification / data","Other"],"subject":{"address":"4421 Maplewood Drive","subdivision":"Maplewood Estates","style":"Two-Story","bed":4,"bath":3,"gla":2300,"site":"10,000 SF","yr":2002,"cond":"C3","qual":"Q4","garage":"2-car attached","bsmt":"Unfinished","pool":"None"}}'::jsonb
FROM ins,
  module_sections ms
  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- Scenario 3.6: Conservation Easement — Before Value
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 6, 'advanced', 'Conservation Easement — Before Value', 'You have been engaged to establish the ''before'' market value of this property as of the date of conservation easement donation (8 months ago) for IRS Form 8283. The ''before'' value must reflect the property with full development rights intact. Comparables must show similar unencumbered residential properties — not properties already subject to easements. IRS scrutinizes conservation easement appraisals intensely; comparable selection is critical.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 3
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'Conservation easement ''before'' comps must (1) have full unencumbered development rights and (2) be contemporaneous with the donation date (8 months ago). C1, C2, and C3 all meet both criteria. C4 — post-donation current sale. C5 — the critical decision: a property already subject to a conservation easement reflects an encumbered ''after'' value; using it would understate the before value and the easement benefit, which the IRS treats as a fraud indicator. C6 — agricultural farmland, different market segment. C7 — intra-family transfer, non-arm''s length in an intensely scrutinized appraisal context. C8 acceptable as supplementary support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"reject","C8":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — rural residential, full development rights (11.0 ac., no restrictions), 2 mo. before donation, arm''s length. Reflects unencumbered before-value conditions.","C2":"Strong comp — full development rights (13.5 ac.), 1 mo. post-donation (no market change), arm''s length. GLA (+120 SF) and acreage adjustments needed.","C3":"Good comp — full development rights (10.8 ac.), 1 mo. before donation, arm''s length. Half-bath adjustment needed.","C4":"Reject — sold 2 mo. ago, 6 months post-donation. Reflects post-donation market appreciation; not appropriate for establishing ''before'' value as of the donation date.","C5":"Reject — conservation easement already recorded on this property 5 years ago. This reflects an encumbered ''after'' value, not full development-rights ''before'' value. Using it would understate the before value and therefore the easement donation benefit — a key IRS red flag.","C6":"Reject — 85-acre working farm in an agricultural zone. Different market segment; rural residential buyers seeking 12-acre sites do not compete with agricultural buyers for 85-acre working farms.","C7":"Reject — intra-family parent-to-child transfer at the donation date. Non-arm''s length; IRS conservation easement appraisals are under heavy scrutiny and require the highest quality arm''s length evidence.","C8":"Acceptable — full development rights (14.0 ac.), 3 mo. before donation, arm''s length. Farther at 1.8 mi with slightly more acreage; C1–C3 more directly comparable."},"justification":"Conservation easement ''before'' comps must (1) have full unencumbered development rights and (2) be contemporaneous with the donation date (8 months ago). C1, C2, and C3 all meet both criteria. C4 — post-donation current sale. C5 — the critical decision: a property already subject to a conservation easement reflects an encumbered ''after'' value; using it would understate the before value and the easement benefit, which the IRS treats as a fraud indicator. C6 — agricultural farmland, different market segment. C7 — intra-family transfer, non-arm''s length in an intensely scrutinized appraisal context. C8 acceptable as supplementary support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"714 Meadowbrook Lane","prox":"0.8 mi","sub":"Rural residential","price":685000,"date":"10 months ago","style":"Colonial","bed":4,"bath":3,"gla":2750,"site":"11.0 acres (no restrictions)","yr":2007,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS/deed verified","warn":false},{"id":"C2","addr":"1842 Ridge Road","prox":"1.2 mi","sub":"Rural residential","price":698000,"date":"7 months ago","style":"Colonial","bed":4,"bath":3,"gla":2920,"site":"13.5 acres (no restrictions)","yr":2009,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS/deed verified","warn":false},{"id":"C3","addr":"412 Creekside Road","prox":"1.5 mi","sub":"Rural residential","price":671000,"date":"9 months ago","style":"Colonial","bed":4,"bath":"2.5","gla":2810,"site":"10.8 acres (no restrictions)","yr":2007,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS/deed verified","warn":false},{"id":"C4","addr":"88 Meadowbrook Court","prox":"0.9 mi","sub":"Rural residential","price":741000,"date":"2 months ago","style":"Colonial","bed":4,"bath":3,"gla":2820,"site":"12.0 acres","yr":2009,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS/deed verified","warn":false},{"id":"C5","addr":"2219 Highland Road","prox":"1.4 mi","sub":"Rural residential","price":498000,"date":"8 months ago","style":"Colonial","bed":4,"bath":3,"gla":2790,"site":"11.5 acres","yr":2008,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS/deed verified","warn":false},{"id":"C6","addr":"5800 Farm Road 220","prox":"4.5 mi","sub":"Agricultural zone","price":485000,"date":"8 months ago","style":"Farmhouse","bed":4,"bath":2,"gla":2200,"site":"85 acres","yr":1985,"cond":"C3","qual":"Q3","conc":"None","gar":"2-car + farm buildings","txn":"Arm''s length — deed verified","warn":false},{"id":"C7","addr":"618 Meadowbrook Road","prox":"0.6 mi","sub":"Rural residential","price":692000,"date":"8 months ago","style":"Colonial","bed":4,"bath":3,"gla":2760,"site":"12.0 acres","yr":2008,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Parent-to-child family transfer — per deed","warn":true},{"id":"C8","addr":"1045 Ridge Lane","prox":"1.8 mi","sub":"Rural residential","price":674000,"date":"11 months ago","style":"Colonial","bed":4,"bath":3,"gla":2880,"site":"14.0 acres (no restrictions)","yr":2006,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS/deed verified","warn":false}],"rejection_reasons":["Sale post-dates retrospective effective date","Sale too old — pre-dates effective date","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Reflects encumbered / restricted-use value","Insufficient physical similarity","Outside subject market area","Inadequate verification / data","Other"],"subject":{"address":"2841 Meadowbrook Road","subdivision":"Rural residential — unincorporated","style":"Colonial","bed":4,"bath":3,"gla":2800,"site":"12.5 acres (full dev. rights)","yr":2008,"cond":"C2","qual":"Q4","garage":"3-car attached","bsmt":"Finished","pool":"None"}}'::jsonb
FROM ins,
  module_sections ms
  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- Scenario 3.7: Estate with Residential Income Property
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 7, 'advanced', 'Estate with Residential Income Property', 'The estate of James R. Henderson contains a 3-unit residential triplex that must be appraised at fair market value as of the date of death (15 months ago) for IRS Form 706. The appropriate report form is the 1025 Small Residential Income Property Appraisal Report. Comparables must be 2-4 family residential sales contemporaneous with the date of death.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 3
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'Two rules govern this estate 1025 appraisal: (1) 2-4 family comparables only, and (2) contemporaneous with date of death (15 months ago). C1, C2, and C3 are all triplexes within 3 months of the death date. C4 — correct property type but post-death current sale. C5 — SFR; never appropriate for a triplex income property appraisal regardless of proximity or price. C6 — 5-unit commercial property, exceeds the 2-4 family classification. C7 — 22 months old, pre-dates death by 7 months. C8 acceptable as a 4th 1025 grid support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"reject","C8":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same district, same property type (3-unit), 17 mo. ago (2 mo. before death), arm''s length.","C2":"Strong comp — same district, same property type, 14 mo. ago (1 mo. after death, no change), arm''s length. Total GLA adj (+150 SF).","C3":"Good comp — correct property type, 16 mo. ago (1 mo. before death), arm''s length. Parking adjustment needed (street vs 3 off-street).","C4":"Reject — sold 2 mo. ago, 13 months post-death. Reflects current market appreciation; not appropriate for establishing the date-of-death estate value.","C5":"Reject — single-family residence. For a 1025 triplex estate appraisal, comparables must be 2-4 family sales. SFR sales do not reflect the income characteristics, buyer motivation, or market segment of a 3-unit property.","C6":"Reject — 5-unit apartment building exceeds the 2-4 unit residential classification. Commercial investment property with different financing, buyer pool, and market segment.","C7":"Reject — 22 mo. old; sold 7 months before the date of death. Outside the 12-month guideline; adequate recent triplex comps are available.","C8":"Acceptable — correct property type, sold at death date, arm''s length. Farther at 1.3 mi; C1–C3 more comparable, but useful as a 4th comp on the 1025 grid."},"justification":"Two rules govern this estate 1025 appraisal: (1) 2-4 family comparables only, and (2) contemporaneous with date of death (15 months ago). C1, C2, and C3 are all triplexes within 3 months of the death date. C4 — correct property type but post-death current sale. C5 — SFR; never appropriate for a triplex income property appraisal regardless of proximity or price. C6 — 5-unit commercial property, exceeds the 2-4 family classification. C7 — 22 months old, pre-dates death by 7 months. C8 acceptable as a 4th 1025 grid support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"512 Franklin Court","prox":"0.5 mi","sub":"Commerce District","price":398000,"date":"17 months ago","style":"Triplex (3-unit)","bed":"2+2+2","bath":"1+1+1","gla":"3,500 SF (total)","site":"5,800 SF","yr":1994,"cond":"C3","qual":"Q4","conc":"None","gar":"3 off-street","txn":"Arm''s length — MLS","warn":false},{"id":"C2","addr":"1847 Commerce Street","prox":"0.8 mi","sub":"Commerce District","price":415000,"date":"14 months ago","style":"Triplex (3-unit)","bed":"2+2+2","bath":"1+1+1","gla":"3,750 SF (total)","site":"6,200 SF","yr":1997,"cond":"C3","qual":"Q4","conc":"None","gar":"3 off-street","txn":"Arm''s length — MLS","warn":false},{"id":"C3","addr":"741 Industrial Way","prox":"1.1 mi","sub":"Industrial Park District","price":385000,"date":"16 months ago","style":"Triplex (3-unit)","bed":"2+2+2","bath":"1+1+1","gla":"3,450 SF (total)","site":"5,900 SF","yr":1993,"cond":"C3","qual":"Q4","conc":"None","gar":"Street parking","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"288 Franklin Blvd","prox":"0.6 mi","sub":"Commerce District","price":441000,"date":"2 months ago","style":"Triplex (3-unit)","bed":"2+2+2","bath":"1+1+1","gla":"3,580 SF (total)","site":"6,100 SF","yr":1996,"cond":"C3","qual":"Q4","conc":"None","gar":"3 off-street","txn":"Arm''s length — MLS","warn":false},{"id":"C5","addr":"415 Oak Street","prox":"0.4 mi","sub":"Oak Park","price":318000,"date":"16 months ago","style":"Single-Family","bed":4,"bath":2,"gla":"1,900 SF","site":"5,500 SF","yr":2002,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C6","addr":"215 Commerce Ave","prox":"0.7 mi","sub":"Commerce District","price":548000,"date":"15 months ago","style":"Apt. building (5-unit)","bed":"Various","bath":"Various","gla":"4,800 SF (total)","site":"7,500 SF","yr":1998,"cond":"C3","qual":"Q4","conc":"None","gar":"5 off-street","txn":"Arm''s length — investor sale","warn":false},{"id":"C7","addr":"687 Railroad Ave","prox":"0.9 mi","sub":"Railroad District","price":372000,"date":"22 months ago","style":"Triplex (3-unit)","bed":"2+2+2","bath":"1+1+1","gla":"3,400 SF (total)","site":"5,700 SF","yr":1993,"cond":"C3","qual":"Q4","conc":"None","gar":"2 off-street","txn":"Arm''s length — deed verified","warn":false},{"id":"C8","addr":"1044 Franklin Heights Dr","prox":"1.3 mi","sub":"Franklin Heights","price":408000,"date":"15 months ago","style":"Triplex (3-unit)","bed":"2+2+2","bath":"1+1+1","gla":"3,700 SF (total)","site":"6,300 SF","yr":1997,"cond":"C3","qual":"Q4","conc":"None","gar":"2 off-street","txn":"Arm''s length — MLS","warn":false}],"rejection_reasons":["Sale post-dates retrospective effective date","Sale too old — pre-dates effective date","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Reflects encumbered / restricted-use value","Insufficient physical similarity","Outside subject market area","Inadequate verification / data","Other"],"subject":{"address":"8842 Franklin Avenue","subdivision":"Commerce District","style":"Triplex (3-unit)","bed":"2+2+2","bath":"1+1+1","gla":"3,600 SF (total)","site":"6,000 SF","yr":1995,"cond":"C3","qual":"Q4","garage":"3 off-street spaces","bsmt":"None","pool":"None"}}'::jsonb
FROM ins,
  module_sections ms
  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- Scenario 3.8: Gift Tax — Historic Registered Property
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 8, 'advanced', 'Gift Tax — Historic Registered Property', 'Parents transferred a National Register-listed Victorian home to their adult child as a gift (date of transfer: 20 months ago) for IRS Form 709 reporting. The property has a historic designation and was recently restored to high quality. The historic home market is distinct from the general residential market. The current market has risen ~10% since the transfer date in the general area.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 3
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'For a National Register Victorian, comparable quality and market segment matter most. C1 (22 mo., same district, Q6), C2 (19 mo., Q6, minor adj), and C3 (21 mo., same district, Q6, concession adj) all match the historic restoration market. C4 — post-transfer current sale (+10%). C5 — the key lesson: Q4 modern colonial in the suburbs serves a completely different buyer pool. Despite similar GLA and price, Q4 tract construction never competes with Q6 historic restoration; quality and character govern market segment in this context. C6 — same district and style but C4 condition creates an unbridgeable gap. C7 — intra-family transfer, non-arm''s length. C8 acceptable as adjacent historic market support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"reject","C8":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same district, matching C2/Q6 historic restoration, 22 mo. ago (2 mo. before transfer), arm''s length. Minor GLA adj (50 SF less).","C2":"Strong comp — same district, Q6 historic, 19 mo. ago (1 mo. after transfer, no change), arm''s length. Half-bath and minor GLA adj (+120 SF).","C3":"Good comp — same district, matching quality, 21 mo. ago (1 mo. before transfer), arm''s length. Seller concession adjustment required.","C4":"Reject — sold 2 mo. ago, 18 months post-transfer. Reflects ~10% current appreciation; using it would overstate the gift value for Form 709 reporting.","C5":"Reject — modern 2015 tract-built colonial in a suburban subdivision. Despite similar GLA and price, Q4 tract construction does not compete with a Q6 National Register Victorian. The historic character, materials, and buyer pool are fundamentally different markets.","C6":"Reject — same district and style but C4 deteriorating condition vs. subject''s C2 restored finish. The condition gap of $200k+ reflects a different market tier; adjustment would be unreliable and speculative.","C7":"Reject — intra-family parent-to-sibling transfer at the gift date. Non-arm''s length. IRS Form 709 gift tax reporting requires arm''s length market evidence regardless of how close the sale price is to market.","C8":"Acceptable — historic restoration quality (Q6), 1 mo. before transfer, arm''s length. Farther at 2.1 mi in an adjacent historic market; C1–C3 provide more direct support."},"justification":"For a National Register Victorian, comparable quality and market segment matter most. C1 (22 mo., same district, Q6), C2 (19 mo., Q6, minor adj), and C3 (21 mo., same district, Q6, concession adj) all match the historic restoration market. C4 — post-transfer current sale (+10%). C5 — the key lesson: Q4 modern colonial in the suburbs serves a completely different buyer pool. Despite similar GLA and price, Q4 tract construction never competes with Q6 historic restoration; quality and character govern market segment in this context. C6 — same district and style but C4 condition creates an unbridgeable gap. C7 — intra-family transfer, non-arm''s length. C8 acceptable as adjacent historic market support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"814 Victorian Court","prox":"0.5 mi","sub":"Historic District","price":698000,"date":"22 months ago","style":"Victorian","bed":4,"bath":3,"gla":3050,"site":"0.38 acres","yr":1895,"cond":"C2","qual":"Q6 historic","conc":"None","gar":"2-car detached","txn":"Arm''s length — MLS","warn":false},{"id":"C2","addr":"421 Heritage Row","prox":"0.8 mi","sub":"Historic District","price":715000,"date":"19 months ago","style":"Victorian","bed":4,"bath":"3.5","gla":3220,"site":"0.42 acres","yr":1889,"cond":"C2","qual":"Q6 historic","conc":"None","gar":"2-car detached","txn":"Arm''s length — MLS","warn":false},{"id":"C3","addr":"219 Heritage Lane","prox":"0.7 mi","sub":"Historic District","price":682000,"date":"21 months ago","style":"Victorian","bed":4,"bath":3,"gla":3080,"site":"0.39 acres","yr":1898,"cond":"C2","qual":"Q6 historic","conc":"$5,000 seller paid","gar":"2-car detached","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"510 Heritage Blvd","prox":"0.6 mi","sub":"Historic District","price":782000,"date":"2 months ago","style":"Victorian","bed":4,"bath":3,"gla":3120,"site":"0.41 acres","yr":1891,"cond":"C2","qual":"Q6 historic","conc":"None","gar":"2-car detached","txn":"Arm''s length — MLS","warn":false},{"id":"C5","addr":"218 Suburban Way","prox":"3.0 mi","sub":"Suburban Estates","price":695000,"date":"20 months ago","style":"Colonial","bed":4,"bath":3,"gla":3100,"site":"0.50 acres","yr":2015,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C6","addr":"712 Victorian Row","prox":"0.5 mi","sub":"Historic District","price":485000,"date":"20 months ago","style":"Victorian","bed":4,"bath":3,"gla":3050,"site":"0.36 acres","yr":1893,"cond":"C4 (deteriorating, partial inhabit.)","qual":"Q6 (historic bones)","conc":"None","gar":"1-car detached","txn":"Arm''s length — MLS","warn":false},{"id":"C7","addr":"119 Heritage Way","prox":"0.7 mi","sub":"Historic District","price":703000,"date":"20 months ago","style":"Victorian","bed":4,"bath":3,"gla":3080,"site":"0.40 acres","yr":1890,"cond":"C2","qual":"Q6 historic","conc":"None","gar":"2-car detached","txn":"Parent-to-sibling transfer — per deed","warn":true},{"id":"C8","addr":"317 Millbrook Drive","prox":"2.1 mi","sub":"Adjacent historic area","price":692000,"date":"21 months ago","style":"Victorian","bed":4,"bath":3,"gla":3150,"site":"0.42 acres","yr":1896,"cond":"C2","qual":"Q6 historic","conc":"None","gar":"2-car detached","txn":"Arm''s length — MLS","warn":false}],"rejection_reasons":["Sale post-dates retrospective effective date","Sale too old — pre-dates effective date","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Reflects encumbered / restricted-use value","Insufficient physical similarity","Outside subject market area","Inadequate verification / data","Other"],"subject":{"address":"1128 Victorian Lane","subdivision":"Historic District","style":"Victorian","bed":4,"bath":3,"gla":3100,"site":"0.40 acres","yr":1892,"cond":"C2 (historic restoration)","qual":"Q6 (historic)","garage":"2-car detached","bsmt":"Partial","pool":"None"}}'::jsonb
FROM ins,
  module_sections ms
  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- Scenario 3.9: Estate — Lakefront Vacation Property
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 9, 'advanced', 'Estate — Lakefront Vacation Property', 'The estate of Margaret R. Whitmore includes a lakefront vacation home on Crystal Lake. Fair market value must be established as of the date of death (18 months ago) for IRS Form 706. The Crystal Lake lakefront market is seasonal with peak activity in spring and summer; the date of death was in February. Comparable selection must reflect properties with similar lakefront access and frontage.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 3
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'For this lakefront estate appraisal, comps must have (1) direct lakefront access with similar frontage, (2) conditions as of date of death (18 months ago), and (3) arm''s length. C1 (same area, 80 ft, 2 mo. before death), C2 (east shore, 90 ft, 1 mo. after with no change), and C3 (same area, 82 ft, 1 mo. before death) all qualify. C4 — post-death current sale. C5 — non-lakefront; cannot support a lakefront value regardless of GLA or lot size similarity. C6 — relocation buyout at death date, non-arm''s length. C7 — 30 months old, pre-dates death by 12 months. C8 acceptable as north-shore lakefront support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"reject","C8":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same area, lakefront (80 ft), similar GLA (50 SF less), sold 2 mo. before death, arm''s length.","C2":"Strong comp — Crystal Lake east shore, lakefront (90 ft), 17 mo. ago (1 mo. after death, no change), arm''s length. GLA (+60 SF) and frontage adjustments needed.","C3":"Good comp — same area, lakefront (82 ft), sold 1 mo. before death, arm''s length. Near-identical GLA and frontage. Lacks boathouse; minor amenity adjustment needed.","C4":"Reject — sold 3 mo. ago, 15 months post-death. Reflects post-death market appreciation on a seasonal lakefront property; not appropriate for the date-of-death estate value.","C5":"Reject — non-lakefront property with no direct water access, 200 feet from the lake. The lakefront premium (direct access, frontage, dock ability) is a fundamental value component of this estate asset; non-lakefront sales cannot support it.","C6":"Reject — relocation/employer buyout at the death date. Non-arm''s length. Estate tax appraisals require arm''s length market evidence; this sale does not meet the IRS fair market value definition.","C7":"Reject — 30 mo. old; sold 12 months before the date of death. Seasonal lakefront markets can shift significantly year-to-year; this pre-death sale is too distant from the retrospective date.","C8":"Acceptable — lakefront (88 ft), 2 mo. before death, arm''s length. Slightly farther at 1.0 mi with larger GLA; C1–C3 more directly comparable but this confirms the lakefront value range."},"justification":"For this lakefront estate appraisal, comps must have (1) direct lakefront access with similar frontage, (2) conditions as of date of death (18 months ago), and (3) arm''s length. C1 (same area, 80 ft, 2 mo. before death), C2 (east shore, 90 ft, 1 mo. after with no change), and C3 (same area, 82 ft, 1 mo. before death) all qualify. C4 — post-death current sale. C5 — non-lakefront; cannot support a lakefront value regardless of GLA or lot size similarity. C6 — relocation buyout at death date, non-arm''s length. C7 — 30 months old, pre-dates death by 12 months. C8 acceptable as north-shore lakefront support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"2814 Lakeshore Court","prox":"0.6 mi","sub":"Crystal Lake Estates","price":548000,"date":"20 months ago","style":"Ranch","bed":3,"bath":2,"gla":1900,"site":"0.55 acres lakefront (80 ft)","yr":2008,"cond":"C2","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C2","addr":"591 Waterfront Drive","prox":"0.9 mi","sub":"Crystal Lake — east shore","price":558000,"date":"17 months ago","style":"Ranch","bed":3,"bath":2,"gla":2010,"site":"0.65 acres lakefront (90 ft)","yr":2010,"cond":"C2","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C3","addr":"109 Lakeview Lane","prox":"0.7 mi","sub":"Crystal Lake Estates","price":535000,"date":"19 months ago","style":"Ranch","bed":3,"bath":2,"gla":1960,"site":"0.58 acres lakefront (82 ft)","yr":2009,"cond":"C2","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"428 Lakeside Pkwy","prox":"0.8 mi","sub":"Crystal Lake Estates","price":612000,"date":"3 months ago","style":"Ranch","bed":3,"bath":2,"gla":1975,"site":"0.60 acres lakefront (85 ft)","yr":2010,"cond":"C2","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C5","addr":"712 Bluewater Drive","prox":"1.5 mi","sub":"Crystal Lake — west shore","price":389000,"date":"18 months ago","style":"Ranch","bed":3,"bath":2,"gla":1920,"site":"0.55 acres (non-lakefront, 200 ft setback)","yr":2009,"cond":"C2","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C6","addr":"88 Lakeshore Drive","prox":"0.4 mi","sub":"Crystal Lake Estates","price":541000,"date":"18 months ago","style":"Ranch","bed":3,"bath":2,"gla":1940,"site":"0.58 acres lakefront (80 ft)","yr":2008,"cond":"C2","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Relocation company purchase","warn":true},{"id":"C7","addr":"319 Crystal Court","prox":"0.7 mi","sub":"Crystal Lake Estates","price":528000,"date":"30 months ago","style":"Ranch","bed":3,"bath":2,"gla":1935,"site":"0.60 acres lakefront (83 ft)","yr":2009,"cond":"C2","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C8","addr":"544 Waterfront Court","prox":"1.0 mi","sub":"Crystal Lake — north shore","price":545000,"date":"20 months ago","style":"Ranch","bed":3,"bath":2,"gla":2040,"site":"0.62 acres lakefront (88 ft)","yr":2010,"cond":"C2","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false}],"rejection_reasons":["Sale post-dates retrospective effective date","Sale too old — pre-dates effective date","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Reflects encumbered / restricted-use value","Insufficient physical similarity","Outside subject market area","Inadequate verification / data","Other"],"subject":{"address":"4821 Lakeshore Drive","subdivision":"Crystal Lake Estates","style":"Ranch","bed":3,"bath":2,"gla":1950,"site":"0.60 acres lakefront (85 ft)","yr":2009,"cond":"C2","qual":"Q4","garage":"2-car attached","bsmt":"None","pool":"Dock & boathouse"}}'::jsonb
FROM ins,
  module_sections ms
  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- Scenario 3.10: IRS Challenge — Estate Appraisal Review
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 10, 'advanced', 'IRS Challenge — Estate Appraisal Review', 'You are serving as a neutral review appraiser in an IRS estate tax dispute (Form 706). The executor''s appraiser (seeking low value to minimize estate tax) and the IRS''s appraiser (seeking high value to maximize tax) each submitted 4 comparable sales. You have the combined pool of 8 sales and must independently evaluate all on their merits. Effective date: 22 months ago. Market has risen ~12% since then.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 3
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'As a neutral review appraiser, the standard is consistent: arm''s length sales contemporaneous with the date of death (22 months ago) in the subject''s competing market. C1 (executor''s, 24 mo.), C2 (IRS''s, 21 mo.), and C3 (executor''s, 22 mo.) all qualify, producing a balanced range of $528k–$541k. The estate tried to anchor low with C6 (REO, C3 condition) and distorted by proximity alone. The IRS tried to anchor high with C4 (current market, +12%), C5 (superior market area), and C7 (related-party LLC sale). A neutral review appraiser rejects both sides'' cherry-picks: the answer lies in the contemporaneous, arm''s length sales that both sides had available but selectively de-emphasized.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"reject","C8":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, 24 mo. ago (2 mo. before death), arm''s length, pool. Submitted by executor''s appraiser; appropriate on its own merits.","C2":"Strong comp — adjacent competing sub, 21 mo. ago (1 mo. after death, no change), arm''s length, pool. GLA adj (+60 SF). Submitted by IRS; appropriate on its own merits.","C3":"Good comp — adjacent sub, at death date (22 mo.), arm''s length, pool. Half-bath adjustment needed. Submitted by executor; appropriate on its own merits.","C4":"Reject — current market sale, 20 months post-death, with ~12% appreciation. Submitted by IRS appraiser; using current-market comps to establish a higher estate value overstates date-of-death FMV.","C5":"Reject — Grandview Estates is a demonstrably superior luxury enclave with a different buyer pool. Submitted by IRS appraiser to anchor the estate value high; using a superior market area inflates the date-of-death FMV.","C6":"Reject — bank-owned REO at the death date; C3 condition vs subject''s C2. Submitted by executor''s appraiser to anchor value low. Distressed pricing and inferior condition both work to understate the estate''s date-of-death FMV.","C7":"Reject — builder sold to a related family LLC; non-arm''s length per deed records. Submitted by IRS appraiser as a high-end comp, but it fails the arm''s length test required by the IRS fair market value definition regardless of price.","C8":"Acceptable — adjacent sub, 24 mo. ago, arm''s length, pool. Larger lot and GLA; C1–C3 provide more direct comparisons, but this sale supports the value range."},"justification":"As a neutral review appraiser, the standard is consistent: arm''s length sales contemporaneous with the date of death (22 months ago) in the subject''s competing market. C1 (executor''s, 24 mo.), C2 (IRS''s, 21 mo.), and C3 (executor''s, 22 mo.) all qualify, producing a balanced range of $528k–$541k. The estate tried to anchor low with C6 (REO, C3 condition) and distorted by proximity alone. The IRS tried to anchor high with C4 (current market, +12%), C5 (superior market area), and C7 (related-party LLC sale). A neutral review appraiser rejects both sides'' cherry-picks: the answer lies in the contemporaneous, arm''s length sales that both sides had available but selectively de-emphasized."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"512 Heritage Court","prox":"0.5 mi","sub":"Heritage Estates","price":528000,"date":"24 months ago","style":"Two-Story","bed":4,"bath":3,"gla":2430,"site":"0.58 acres","yr":2010,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS (executor''s appraiser)","warn":false},{"id":"C2","addr":"814 Ridgewood Manor","prox":"0.8 mi","sub":"Ridgewood Manor","price":541000,"date":"21 months ago","style":"Two-Story","bed":4,"bath":3,"gla":2540,"site":"0.62 acres","yr":2012,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS (IRS''s appraiser)","warn":false},{"id":"C3","addr":"109 Crestview Circle","prox":"0.7 mi","sub":"Crestview Estates","price":535000,"date":"22 months ago","style":"Two-Story","bed":4,"bath":"2.5","gla":2460,"site":"0.57 acres","yr":2011,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS (executor''s appraiser)","warn":false},{"id":"C4","addr":"721 Heritage Way","prox":"0.5 mi","sub":"Heritage Estates","price":635000,"date":"2 months ago","style":"Two-Story","bed":4,"bath":3,"gla":2470,"site":"0.60 acres","yr":2012,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS (IRS''s appraiser)","warn":false},{"id":"C5","addr":"88 Grandview Place","prox":"2.2 mi","sub":"Grandview Estates (luxury enclave)","price":618000,"date":"22 months ago","style":"Two-Story","bed":4,"bath":3,"gla":2490,"site":"0.61 acres","yr":2011,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS (IRS''s appraiser)","warn":false},{"id":"C6","addr":"312 Heritage Drive","prox":"0.5 mi","sub":"Heritage Estates","price":468000,"date":"22 months ago","style":"Two-Story","bed":4,"bath":3,"gla":2410,"site":"0.57 acres","yr":2010,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Bank-owned REO (executor''s appraiser)","warn":true},{"id":"C7","addr":"419 Heritage Blvd","prox":"0.6 mi","sub":"Heritage Estates","price":553000,"date":"22 months ago","style":"Two-Story","bed":4,"bath":3,"gla":2380,"site":"0.59 acres","yr":2011,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Builder sold to related family LLC — per deed (IRS''s appraiser)","warn":true},{"id":"C8","addr":"617 Ridgewood Circle","prox":"0.9 mi","sub":"Ridgewood Manor","price":538000,"date":"24 months ago","style":"Two-Story","bed":4,"bath":3,"gla":2550,"site":"0.64 acres","yr":2010,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS (executor''s appraiser)","warn":false}],"rejection_reasons":["Sale post-dates retrospective effective date","Sale too old — pre-dates effective date","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Reflects encumbered / restricted-use value","Insufficient physical similarity","Outside subject market area","Inadequate verification / data","Other"],"subject":{"address":"3214 Heritage Estates Drive","subdivision":"Heritage Estates","style":"Two-Story","bed":4,"bath":3,"gla":2480,"site":"0.60 acres","yr":2011,"cond":"C2","qual":"Q4","garage":"3-car attached","bsmt":"Finished","pool":"Pool"}}'::jsonb
FROM ins,
  module_sections ms
  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- ─────────────── Category 4: Private/Consulting ───────────────
-- Scenario 4.1: Pre-Listing Pricing Consultation
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 1, 'basic', 'Pre-Listing Pricing Consultation', 'A homeowner has retained you as a private consultant to provide an objective market value opinion before listing their home. There is no lender involved. The purpose is to help the seller price the home correctly — neither too high (languishing inventory) nor too low (leaving money on the table). Scope: exterior-only inspection with MLS data review.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 4
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'For a pre-listing consultation, the most current arm''s length closed sales are critical. C1 (same sub, 2 mo., 30 SF less), C2 (adjacent sub, most recent at 1 mo.), and C3 (same sub, concession adj) establish a market range of ~$308k–$319k (adjusted). C4 rejected — active listing; a seller needs SOLD data, not competing asks. C5 — 18 months old, stale for current pricing. C6 — REO distressed sale; not achievable by a motivated open-market seller. C7 acceptable but less comparable geographically.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, recent arm''s length sale (2 mo.), close GLA match (30 SF less), no concessions. Sets the current market floor.","C2":"Strong comp — adjacent sub, most recent sale (1 mo.), arm''s length. Minor GLA adj (+50 SF) needed.","C3":"Good comp — same sub, 4 mo. ago, arm''s length. Seller concession adj required; adjusted price supports the value range.","C4":"Reject — active listing, not a closed sale. For a pre-listing consultation, the seller wants to know what properties actually SOLD for — not what other sellers are asking. Listings only reveal competition, not confirmed market value.","C5":"Reject — 18 months old; outside the 12-month guideline for a current market value opinion. Stale data would understate the current market for a seller trying to price correctly.","C6":"Reject — bank-owned REO. For a pre-listing consultation, REO sales reflect distressed liquidation, not the open-market price a motivated seller can realistically achieve.","C7":"Acceptable — recent arm''s length sale, physically similar. Located in Ridgecrest Heights (1.4 mi), a less comparable subdivision. C1–C3 provide stronger market-area support."},"justification":"For a pre-listing consultation, the most current arm''s length closed sales are critical. C1 (same sub, 2 mo., 30 SF less), C2 (adjacent sub, most recent at 1 mo.), and C3 (same sub, concession adj) establish a market range of ~$308k–$319k (adjusted). C4 rejected — active listing; a seller needs SOLD data, not competing asks. C5 — 18 months old, stale for current pricing. C6 — REO distressed sale; not achievable by a motivated open-market seller. C7 acceptable but less comparable geographically."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"412 Fernwood Court","prox":"0.4 mi","sub":"Fernwood Commons","price":312000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1510,"site":"7,000 SF","yr":2005,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C2","addr":"818 Greenway Drive","prox":"0.7 mi","sub":"Greenway Estates","price":319000,"date":"1 month ago","style":"Ranch","bed":3,"bath":2,"gla":1590,"site":"7,500 SF","yr":2007,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C3","addr":"109 Fernwood Lane","prox":"0.5 mi","sub":"Fernwood Commons","price":308000,"date":"4 months ago","style":"Ranch","bed":3,"bath":2,"gla":1525,"site":"7,100 SF","yr":2005,"cond":"C3","qual":"Q4","conc":"$2,500 seller paid","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"721 Fernwood Way","prox":"0.6 mi","sub":"Fernwood Commons","price":349000,"date":"Active listing","style":"Ranch","bed":3,"bath":2,"gla":1550,"site":"7,200 SF","yr":2007,"cond":"C3","qual":"Q4","conc":"N/A","gar":"2-car attached","txn":"Active listing — asking price only","warn":true},{"id":"C5","addr":"88 Fernwood Court","prox":"0.4 mi","sub":"Fernwood Commons","price":298000,"date":"18 months ago","style":"Ranch","bed":3,"bath":2,"gla":1530,"site":"7,000 SF","yr":2006,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C6","addr":"412 Greenway Court","prox":"0.7 mi","sub":"Greenway Estates","price":287000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1520,"site":"7,100 SF","yr":2005,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Bank-owned REO","warn":true},{"id":"C7","addr":"515 Ridgecrest Drive","prox":"1.4 mi","sub":"Ridgecrest Heights","price":314000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1560,"site":"7,400 SF","yr":2006,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Different property type or style","Outside subject market area","Inadequate verification / data","Reflects post-renovation value (subject pre-renovation)","Reflects encumbered / restricted-use conditions","Other"],"subject":{"address":"2841 Fernwood Drive","subdivision":"Fernwood Commons","style":"Ranch","bed":3,"bath":2,"gla":1540,"site":"7,200 SF","yr":2006,"cond":"C3","qual":"Q4","garage":"2-car attached","bsmt":"None","pool":"None"}}'::jsonb
FROM ins,
  module_sections ms
  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- Scenario 4.2: Investment Purchase Analysis
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 2, 'basic', 'Investment Purchase Analysis', 'A real estate investor has retained you to provide an independent opinion of market value for a single-family rental property they are considering purchasing at $287,000. The investor wants to know whether the asking price is supported by market evidence before committing. Scope: exterior inspection with public records review.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 4
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'C1 ($278k), C2 ($284k), and C3 ($274k adjusted) establish a value range of approximately $274k–$284k, below the $287k asking price. This is the core advisory value of the consultation. C4 rejected — REO distressed pricing; an investor using REO comps would understate what a fairly priced property is worth, leading to bad comparisons. C5 — 20 months old. C6 — C4 condition introduces unnecessary adjustment uncertainty when C3 comps are available. C7 acceptable as supporting evidence.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, 2 mo. ago, arm''s length. 30 SF less GLA. Establishes market benchmark just below the asking price.","C2":"Strong comp — adjacent sub, arm''s length 3 mo. ago. Minor GLA adj (+30 SF). Supports asking price range.","C3":"Good comp — same sub, 5 mo. ago, arm''s length. Seller concession adj required; adjusted price supports the value range.","C4":"Reject — bank-owned REO. Even for an investor, the standard is market value — what a typically motivated buyer/seller would agree to. REO pricing reflects forced liquidation and would mislead the investor about achievable open-market value.","C5":"Reject — 20 months old; outside the 12-month guideline. For an investment purchase, the client needs to know today''s market value, not what the market supported over a year ago.","C6":"Reject — C4 condition vs subject''s C3. The condition difference would introduce an adjustment that is difficult to support. Adequate C3 comps are available; a condition-inferior comp is unnecessary.","C7":"Acceptable — recent arm''s length, similar physical characteristics. Farther at 0.9 mi; C1–C3 are more comparable but this confirms the value range."},"justification":"C1 ($278k), C2 ($284k), and C3 ($274k adjusted) establish a value range of approximately $274k–$284k, below the $287k asking price. This is the core advisory value of the consultation. C4 rejected — REO distressed pricing; an investor using REO comps would understate what a fairly priced property is worth, leading to bad comparisons. C5 — 20 months old. C6 — C4 condition introduces unnecessary adjustment uncertainty when C3 comps are available. C7 acceptable as supporting evidence."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"514 Commerce Avenue","prox":"0.5 mi","sub":"Commerce Park","price":278000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1320,"site":"5,800 SF","yr":1997,"cond":"C3","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C2","addr":"821 Franklin Drive","prox":"0.8 mi","sub":"Franklin Park","price":284000,"date":"3 months ago","style":"Ranch","bed":3,"bath":2,"gla":1380,"site":"6,200 SF","yr":1999,"cond":"C3","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C3","addr":"218 Commerce Court","prox":"0.4 mi","sub":"Commerce Park","price":274000,"date":"5 months ago","style":"Ranch","bed":3,"bath":2,"gla":1335,"site":"5,900 SF","yr":1998,"cond":"C3","qual":"Q4","conc":"$2,000 seller paid","gar":"1-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"714 Commerce Blvd","prox":"0.6 mi","sub":"Commerce Park","price":261000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1340,"site":"5,900 SF","yr":1998,"cond":"C3","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Bank-owned REO","warn":true},{"id":"C5","addr":"88 Franklin Court","prox":"0.8 mi","sub":"Franklin Park","price":282000,"date":"20 months ago","style":"Ranch","bed":3,"bath":2,"gla":1360,"site":"6,100 SF","yr":1997,"cond":"C3","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C6","addr":"315 Commerce Lane","prox":"0.5 mi","sub":"Commerce Park","price":271000,"date":"3 months ago","style":"Ranch","bed":3,"bath":2,"gla":1345,"site":"5,800 SF","yr":1997,"cond":"C4","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C7","addr":"619 Franklin Way","prox":"0.9 mi","sub":"Franklin Park","price":281000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1370,"site":"6,100 SF","yr":1999,"cond":"C3","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length — MLS","warn":false}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Different property type or style","Outside subject market area","Inadequate verification / data","Reflects post-renovation value (subject pre-renovation)","Reflects encumbered / restricted-use conditions","Other"],"subject":{"address":"1842 Commerce Street","subdivision":"Commerce Park","style":"Ranch","bed":3,"bath":2,"gla":1350,"site":"6,000 SF","yr":1998,"cond":"C3","qual":"Q4","garage":"1-car attached","bsmt":"None","pool":"None"}}'::jsonb
FROM ins,
  module_sections ms
  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- Scenario 4.3: Partnership Dissolution — Buyout Price
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 3, 'intermediate', 'Partnership Dissolution — Buyout Price', 'Two business partners co-own an investment single-family property and are dissolving their partnership. Partner A is buying out Partner B''s 50% interest. They have mutually agreed to obtain an independent appraisal to establish FMV for the buyout calculation. Neither party is under financial pressure to sell. The appraiser must be strictly independent — no relationship with either party.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 4
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'C1 (same sub, 2 mo.), C2 (adjacent sub, 3 mo.), and C3 (same sub, 5 mo., concession and half-bath adj) are recent arm''s length sales in the competing market. C4 — the appraiser''s own family member bought this property; it must be rejected AND it raises an independence red flag for the appraiser. C5 — 22 months old. C6 — the most instructive rejection: sold between LLCs owned by the two dissolving partners. Using a transaction between the very parties to the dispute is circular and impermissible; it cannot establish an independent arms-length value. C7 acceptable as secondary support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, 2 mo. ago, arm''s length. 40 SF less GLA. Current market, no concessions.","C2":"Strong comp — adjacent sub, arm''s length 3 mo. ago. Minor GLA adj (+60 SF) needed.","C3":"Good comp — same sub, 5 mo., arm''s length. Seller concession and half-bath adjustments needed.","C4":"Reject — sold to the appraiser''s family member per deed records. This disqualifies the comp AND raises an independence conflict. In a partnership dissolution appraisal, the appraiser''s independence is paramount; any sale involving a party related to the appraiser is impermissible.","C5":"Reject — 22 months old; outside the 12-month guideline for a current market value opinion.","C6":"Reject — sold between LLCs controlled by the same two dissolving partners. A circular, non-arm''s length transaction; using a sale between the very parties whose interest is being valued is a fundamental conflict.","C7":"Acceptable — arm''s length 4 mo. ago, adjacent sub. Minor GLA adj. C1–C3 are more directly comparable but this confirms the value range."},"justification":"C1 (same sub, 2 mo.), C2 (adjacent sub, 3 mo.), and C3 (same sub, 5 mo., concession and half-bath adj) are recent arm''s length sales in the competing market. C4 — the appraiser''s own family member bought this property; it must be rejected AND it raises an independence red flag for the appraiser. C5 — 22 months old. C6 — the most instructive rejection: sold between LLCs owned by the two dissolving partners. Using a transaction between the very parties to the dispute is circular and impermissible; it cannot establish an independent arms-length value. C7 acceptable as secondary support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"812 Ridgemont Court","prox":"0.5 mi","sub":"Ridgemont Estates","price":428000,"date":"2 months ago","style":"Two-Story","bed":4,"bath":3,"gla":2140,"site":"9,200 SF","yr":2006,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C2","addr":"421 Stonegate Drive","prox":"0.7 mi","sub":"Stonegate Estates","price":434000,"date":"3 months ago","style":"Two-Story","bed":4,"bath":3,"gla":2240,"site":"9,800 SF","yr":2008,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C3","addr":"109 Ridgemont Lane","prox":"0.4 mi","sub":"Ridgemont Estates","price":421000,"date":"5 months ago","style":"Two-Story","bed":4,"bath":"2.5","gla":2160,"site":"9,300 SF","yr":2007,"cond":"C3","qual":"Q4","conc":"$3,500 seller paid","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"714 Ridgemont Blvd","prox":"0.5 mi","sub":"Ridgemont Estates","price":419000,"date":"2 months ago","style":"Two-Story","bed":4,"bath":3,"gla":2150,"site":"9,100 SF","yr":2007,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Sold to appraiser''s family member — per deed","warn":true},{"id":"C5","addr":"88 Stonegate Court","prox":"0.8 mi","sub":"Stonegate Estates","price":411000,"date":"22 months ago","style":"Two-Story","bed":4,"bath":3,"gla":2170,"site":"9,400 SF","yr":2007,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C6","addr":"312 Ridgemont Drive","prox":"0.5 mi","sub":"Ridgemont Estates","price":398000,"date":"3 months ago","style":"Two-Story","bed":4,"bath":3,"gla":2120,"site":"9,000 SF","yr":2006,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Sold between the two partners'' LLCs — related parties","warn":true},{"id":"C7","addr":"618 Stonegate Way","prox":"0.7 mi","sub":"Stonegate Estates","price":431000,"date":"4 months ago","style":"Two-Story","bed":4,"bath":3,"gla":2200,"site":"9,600 SF","yr":2008,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Different property type or style","Outside subject market area","Inadequate verification / data","Reflects post-renovation value (subject pre-renovation)","Reflects encumbered / restricted-use conditions","Other"],"subject":{"address":"3214 Ridgemont Way","subdivision":"Ridgemont Estates","style":"Two-Story","bed":4,"bath":3,"gla":2180,"site":"9,500 SF","yr":2007,"cond":"C3","qual":"Q4","garage":"2-car attached","bsmt":"Unfinished","pool":"None"}}'::jsonb
FROM ins,
  module_sections ms
  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- Scenario 4.4: Pre-Renovation Value Consultation
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 4, 'intermediate', 'Pre-Renovation Value Consultation', 'A homeowner wants to know the current as-is market value of their property BEFORE beginning a major renovation. They plan to add 400 SF, update the kitchen and baths, and convert the unfinished basement. The purpose is to establish a baseline for calculating the cost vs. value of the renovation investment. Comparables must reflect PRE-renovation, as-is conditions similar to the subject — not post-renovation finished properties.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 4
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'The entire purpose of this appraisal is the pre-renovation ''before'' baseline; condition-matching is the critical filter. C1, C2, and C3 are all C4/Q3 condition properties — matching the subject''s as-is state. Their range of $214k–$224k (adjusted) provides the baseline the client needs to evaluate whether a planned renovation investment makes financial sense. C4 and C5 rejected — post-renovation C2 properties; using them as pre-renovation comps would overstate the baseline and make the renovation look less profitable than it actually is. C6 — C5 condition (worse than subject); using inferior condition comps understates the pre-renovation value. C7 acceptable as most-recent secondary support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, C4 condition (matching subject''s as-is state), 3 mo. ago, arm''s length. Establishes the pre-renovation market floor.","C2":"Strong comp — C4 condition, adjacent sub, arm''s length 4 mo. ago. Half-bath and minor GLA adj (+35 SF) needed.","C3":"Good comp — same sub, C4 condition, arm''s length 5 mo. ago. Seller concession adj required.","C4":"Reject — fully renovated C2/Q4 condition with added GLA. This represents the post-renovation ''after'' value, not the pre-renovation ''before'' value the client needs. Using this would overstate the current as-is baseline.","C5":"Reject — recently renovated C2 condition. The client specifically needs the pre-renovation baseline. Post-renovation comps inflate the as-is value and would distort the cost-vs-value analysis.","C6":"Reject — C5 condition (below the subject''s C4). This property has more serious deferred maintenance; using it would understate the subject''s as-is value. Condition-matching is critical for pre-renovation baseline analysis.","C7":"Acceptable — C4 condition, arm''s length 2 mo. ago. Most recent sale in the pool. Farther at 0.8 mi; C1–C3 provide stronger sub support but this confirms the as-is range."},"justification":"The entire purpose of this appraisal is the pre-renovation ''before'' baseline; condition-matching is the critical filter. C1, C2, and C3 are all C4/Q3 condition properties — matching the subject''s as-is state. Their range of $214k–$224k (adjusted) provides the baseline the client needs to evaluate whether a planned renovation investment makes financial sense. C4 and C5 rejected — post-renovation C2 properties; using them as pre-renovation comps would overstate the baseline and make the renovation look less profitable than it actually is. C6 — C5 condition (worse than subject); using inferior condition comps understates the pre-renovation value. C7 acceptable as most-recent secondary support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"812 Oakdale Court","prox":"0.4 mi","sub":"Oakdale Heights","price":218000,"date":"3 months ago","style":"Ranch","bed":3,"bath":1,"gla":1210,"site":"7,800 SF","yr":1970,"cond":"C4","qual":"Q3","conc":"None","gar":"1-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C2","addr":"421 Hillside Lane","prox":"0.7 mi","sub":"Hillside Estates","price":224000,"date":"4 months ago","style":"Ranch","bed":3,"bath":"1.5","gla":1275,"site":"8,200 SF","yr":1974,"cond":"C4","qual":"Q3","conc":"None","gar":"1-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C3","addr":"119 Oakdale Lane","prox":"0.5 mi","sub":"Oakdale Heights","price":214000,"date":"5 months ago","style":"Ranch","bed":3,"bath":1,"gla":1230,"site":"7,900 SF","yr":1971,"cond":"C4","qual":"Q3","conc":"$1,500 seller paid","gar":"1-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"714 Oakdale Blvd","prox":"0.5 mi","sub":"Oakdale Heights","price":298000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1640,"site":"8,100 SF","yr":1972,"cond":"C2","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C5","addr":"88 Hillside Court","prox":"0.7 mi","sub":"Hillside Estates","price":289000,"date":"3 months ago","style":"Ranch","bed":3,"bath":2,"gla":1580,"site":"8,000 SF","yr":1973,"cond":"C2 (renovated)","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C6","addr":"312 Oakdale Way","prox":"0.4 mi","sub":"Oakdale Heights","price":188000,"date":"4 months ago","style":"Ranch","bed":3,"bath":1,"gla":1220,"site":"7,700 SF","yr":1970,"cond":"C5","qual":"Q3","conc":"None","gar":"1-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C7","addr":"618 Hillside Drive","prox":"0.8 mi","sub":"Hillside Estates","price":221000,"date":"2 months ago","style":"Ranch","bed":3,"bath":1,"gla":1250,"site":"8,100 SF","yr":1973,"cond":"C4","qual":"Q3","conc":"None","gar":"1-car attached","txn":"Arm''s length — MLS","warn":false}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Different property type or style","Outside subject market area","Inadequate verification / data","Reflects post-renovation value (subject pre-renovation)","Reflects encumbered / restricted-use conditions","Other"],"subject":{"address":"4421 Oakdale Drive","subdivision":"Oakdale Heights","style":"Ranch","bed":3,"bath":1,"gla":1240,"site":"8,000 SF","yr":1972,"cond":"C4 (dated, original)","qual":"Q3","garage":"1-car attached","bsmt":"Unfinished","pool":"None"}}'::jsonb
FROM ins,
  module_sections ms
  JOIN section_fields sf ON sf.section_id = ms.id
