-- Scenario 4.5: Seller Financing — Note Valuation Support
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 5, 'intermediate', 'Seller Financing — Note Valuation Support', 'The seller of a single-family home has agreed to carry a $275,000 purchase money mortgage at a below-market interest rate (4.5% vs current market of 7%). A financial advisor retained you to establish the cash equivalent market value of the property, which may differ from the stated contract price due to seller financing at a below-market rate. Comparables should reflect arm''s length cash or market-rate financed sales only.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 4
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'For a seller financing cash-equivalency analysis, only cash or market-rate financed sales produce reliable market-value benchmarks. C1, C2, and C3 are all conventional-financing arm''s length sales in the competing market ($378k–$389k). This establishes a cash equivalent range against which the stated $275,000 seller-financed price (plus the financing premium) can be evaluated. C4 — the most important rejection: another below-market seller-financed sale. Using it would embed the same financing premium being analyzed, producing a circular result. C5 — 21 months old. C6 — REO distressed sale. C7 (FHA at market rate) is acceptable as secondary support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, 2 mo. ago, conventional financing arm''s length. Cash equivalent sale; reflects true market rate. Minor GLA adj (40 SF less).","C2":"Strong comp — adjacent sub, conventional financing, arm''s length. Minor GLA adj (+50 SF).","C3":"Good comp — same sub, conventional financing, arm''s length. Seller concession and extra bath adjustments needed.","C4":"Reject — seller-financed sale at a below-market rate. The below-market financing inflates the stated sale price above cash equivalent value; this comp has the same problem as the subject transaction. Using it would embed the financing premium into the value conclusion.","C5":"Reject — 21 months old; outside the 12-month guideline for a current market value opinion.","C6":"Reject — bank-owned REO. Distressed pricing neither reflects cash equivalent market value nor appropriate conventional-market evidence for this analysis.","C7":"Acceptable — FHA financing at market rate is arm''s length cash equivalent. Arm''s length and current; minor GLA adj. C1–C3 (conventional) are preferred, but FHA at market rate is an acceptable comp."},"justification":"For a seller financing cash-equivalency analysis, only cash or market-rate financed sales produce reliable market-value benchmarks. C1, C2, and C3 are all conventional-financing arm''s length sales in the competing market ($378k–$389k). This establishes a cash equivalent range against which the stated $275,000 seller-financed price (plus the financing premium) can be evaluated. C4 — the most important rejection: another below-market seller-financed sale. Using it would embed the same financing premium being analyzed, producing a circular result. C5 — 21 months old. C6 — REO distressed sale. C7 (FHA at market rate) is acceptable as secondary support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"814 Lakeview Drive","prox":"0.5 mi","sub":"Lakeview Heights","price":382000,"date":"2 months ago","style":"Two-Story","bed":4,"bath":"2.5","gla":2010,"site":"8,800 SF","yr":2004,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Conventional financing — arm''s length MLS","warn":false},{"id":"C2","addr":"421 Ridgeview Blvd","prox":"0.7 mi","sub":"Ridgeview Estates","price":389000,"date":"3 months ago","style":"Two-Story","bed":4,"bath":"2.5","gla":2100,"site":"9,300 SF","yr":2006,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Conventional financing — arm''s length MLS","warn":false},{"id":"C3","addr":"108 Lakeview Court","prox":"0.4 mi","sub":"Lakeview Heights","price":378000,"date":"5 months ago","style":"Two-Story","bed":4,"bath":3,"gla":2070,"site":"9,100 SF","yr":2005,"cond":"C3","qual":"Q4","conc":"$3,000 seller paid","gar":"2-car attached","txn":"Conventional financing — arm''s length MLS","warn":false},{"id":"C4","addr":"714 Lakeview Way","prox":"0.5 mi","sub":"Lakeview Heights","price":415000,"date":"4 months ago","style":"Two-Story","bed":4,"bath":"2.5","gla":2040,"site":"8,900 SF","yr":2006,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Seller financing — 3.5% below-market rate per deed","warn":true},{"id":"C5","addr":"88 Ridgeview Court","prox":"0.7 mi","sub":"Ridgeview Estates","price":371000,"date":"21 months ago","style":"Two-Story","bed":4,"bath":"2.5","gla":2030,"site":"8,800 SF","yr":2004,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Conventional financing — arm''s length MLS","warn":false},{"id":"C6","addr":"315 Lakeview Blvd","prox":"0.5 mi","sub":"Lakeview Heights","price":361000,"date":"3 months ago","style":"Two-Story","bed":4,"bath":"2.5","gla":2020,"site":"8,700 SF","yr":2004,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Bank-owned REO","warn":true},{"id":"C7","addr":"618 Ridgeview Way","prox":"0.8 mi","sub":"Ridgeview Estates","price":385000,"date":"4 months ago","style":"Two-Story","bed":4,"bath":"2.5","gla":2080,"site":"9,200 SF","yr":2005,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"FHA financing — arm''s length MLS","warn":false}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Different property type or style","Outside subject market area","Inadequate verification / data","Reflects post-renovation value (subject pre-renovation)","Reflects encumbered / restricted-use conditions","Other"],"subject":{"address":"3518 Lakeview Court","subdivision":"Lakeview Heights","style":"Two-Story","bed":4,"bath":"2.5","gla":2050,"site":"9,000 SF","yr":2005,"cond":"C3","qual":"Q4","garage":"2-car attached","bsmt":"Unfinished","pool":"None"}}'::jsonb
FROM ins,
