  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- Scenario 4.6: Pre-Foreclosure Default Consultation
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 6, 'advanced', 'Pre-Foreclosure Default Consultation', 'A homeowner facing potential foreclosure has retained you to establish fair market value so they can evaluate options: short sale, deed-in-lieu, or loan modification. The lender also needs this opinion to evaluate a short sale approval. The value must reflect open-market arm''s length conditions — what the property would genuinely fetch from a motivated but non-distressed seller — not the distressed price typical of a foreclosure auction.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 4
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'The purpose requires strictly open-market arm''s length evidence — not distressed pricing. C1, C2, and C3 establish a range of ~$311k–$325k, which is the achievable open-market value the lender and homeowner need to evaluate short sale feasibility. C4 rejected — REO by the same lender; circular and distressed. C5 — another short sale; using short sales to value a short sale creates a self-reinforcing spiral of undervaluation that fails the open-market standard. C6 — relocation buyout, non-arm''s length. C7 — 24 months old. C8 acceptable as secondary support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"reject","C8":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, 2 mo. ago, arm''s length. Reflects the open-market value the lender and homeowner both need.","C2":"Strong comp — adjacent sub, most recent sale (1 mo.), arm''s length. Minor GLA adj (+40 SF).","C3":"Good comp — same sub, 4 mo., arm''s length. Seller concession adj needed. Combined with C1 and C2, establishes the achievable open-market range.","C4":"Reject — REO by the same lender holding the subject''s mortgage. Circular and distressed; the lender cannot use its own REO dispositions to establish the open-market value of another borrower''s default. This also fails the arm''s length test.","C5":"Reject — lender-approved short sale (pre-foreclosure). A short sale reflects distressed seller motivation; the lender is approving a discounted payoff, not an open-market transaction. Using short sales to value another short sale creates a spiral of undervaluation.","C6":"Reject — relocation/employer buyout. Non-arm''s length; for a short sale or loan modification analysis, the lender requires strictly arm''s length market evidence to confirm open-market value.","C7":"Reject — 24 months old; outside the 12-month guideline. The lender needs current market evidence for a short sale or loan modification decision.","C8":"Acceptable — arm''s length 3 mo. ago, adjacent sub. Minor GLA adj. C1–C3 more directly comparable but this confirms the open-market range."},"justification":"The purpose requires strictly open-market arm''s length evidence — not distressed pricing. C1, C2, and C3 establish a range of ~$311k–$325k, which is the achievable open-market value the lender and homeowner need to evaluate short sale feasibility. C4 rejected — REO by the same lender; circular and distressed. C5 — another short sale; using short sales to value a short sale creates a self-reinforcing spiral of undervaluation that fails the open-market standard. C6 — relocation buyout, non-arm''s length. C7 — 24 months old. C8 acceptable as secondary support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"414 Heritage Court","prox":"0.4 mi","sub":"Heritage Park","price":318000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1650,"site":"7,600 SF","yr":2001,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C2","addr":"821 Parkview Drive","prox":"0.7 mi","sub":"Parkview Estates","price":325000,"date":"1 month ago","style":"Ranch","bed":3,"bath":2,"gla":1720,"site":"8,100 SF","yr":2003,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C3","addr":"109 Heritage Lane","prox":"0.5 mi","sub":"Heritage Park","price":311000,"date":"4 months ago","style":"Ranch","bed":3,"bath":2,"gla":1660,"site":"7,700 SF","yr":2001,"cond":"C3","qual":"Q4","conc":"$2,000 seller paid","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"715 Heritage Blvd","prox":"0.5 mi","sub":"Heritage Park","price":278000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1665,"site":"7,700 SF","yr":2002,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Bank-owned REO — same lender holding subject mortgage","warn":true},{"id":"C5","addr":"88 Parkview Court","prox":"0.6 mi","sub":"Parkview Estates","price":281000,"date":"3 months ago","style":"Ranch","bed":3,"bath":2,"gla":1670,"site":"7,800 SF","yr":2002,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Short sale — lender-approved pre-foreclosure","warn":true},{"id":"C6","addr":"312 Heritage Way","prox":"0.4 mi","sub":"Heritage Park","price":294000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1655,"site":"7,500 SF","yr":2001,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Relocation company buyout — employer purchase","warn":true},{"id":"C7","addr":"618 Heritage Drive","prox":"0.5 mi","sub":"Heritage Park","price":315000,"date":"24 months ago","style":"Ranch","bed":3,"bath":2,"gla":1670,"site":"7,800 SF","yr":2002,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C8","addr":"514 Parkview Way","prox":"0.8 mi","sub":"Parkview Estates","price":319000,"date":"3 months ago","style":"Ranch","bed":3,"bath":2,"gla":1700,"site":"8,000 SF","yr":2003,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Different property type or style","Outside subject market area","Inadequate verification / data","Reflects post-renovation value (subject pre-renovation)","Reflects encumbered / restricted-use conditions","Other"],"subject":{"address":"2841 Heritage Drive","subdivision":"Heritage Park","style":"Ranch","bed":3,"bath":2,"gla":1680,"site":"7,800 SF","yr":2002,"cond":"C3","qual":"Q4","garage":"2-car attached","bsmt":"None","pool":"None"}}'::jsonb
FROM ins,
  module_sections ms
  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- Scenario 4.7: Bankruptcy — Asset Liquidation Valuation
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 7, 'advanced', 'Bankruptcy — Asset Liquidation Valuation', 'A bankruptcy trustee has retained you to establish the fair market value of a residential property that is an asset of the bankruptcy estate. The trustee needs a reliable FMV opinion to evaluate whether to liquidate (sell) the property and at what price, or abandon it to the secured lender. Bankruptcy courts require strict arm''s length market evidence; distressed sales are generally not admissible.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 4
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'Bankruptcy courts require open-market arm''s length evidence; only verifiable arm''s length MLS sales qualify. C1, C2, and C3 establish a value range of ~$461k–$475k (adjusted) — the FMV the trustee needs to evaluate liquidation vs abandonment. C4 — another bankruptcy trustee sale; distressed trustee pricing is inadmissible as FMV in bankruptcy proceedings. C5 — 23 months old. C6 — sold to the debtor''s family member; non-arm''s length and potentially a fraudulent conveyance — a particularly critical rejection in a bankruptcy context. C7 acceptable as secondary court-admissible evidence.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, 2 mo. ago, arm''s length. 40 SF less GLA. Court-admissible open-market evidence.","C2":"Strong comp — adjacent sub, arm''s length 3 mo. ago. Minor GLA adj (+60 SF).","C3":"Good comp — same sub, 5 mo., arm''s length. Seller concession and half-bath adjustments needed.","C4":"Reject — another bankruptcy trustee sale. Distressed liquidation pricing is not admissible as FMV evidence in bankruptcy proceedings. The court requires open-market evidence; using distressed trustee sales to value a distressed trustee asset creates circular, inadmissible analysis.","C5":"Reject — 23 months old; outside the 12-month guideline. Bankruptcy courts expect current market evidence.","C6":"Reject — sold to a family member of the bankruptcy debtor. Non-arm''s length and potentially a fraudulent conveyance; the bankruptcy trustee cannot use transactions involving the debtor''s associates as market evidence.","C7":"Acceptable — arm''s length 4 mo. ago, adjacent sub. Minor GLA adj (+40 SF). Supports the open-market value range with court-admissible evidence."},"justification":"Bankruptcy courts require open-market arm''s length evidence; only verifiable arm''s length MLS sales qualify. C1, C2, and C3 establish a value range of ~$461k–$475k (adjusted) — the FMV the trustee needs to evaluate liquidation vs abandonment. C4 — another bankruptcy trustee sale; distressed trustee pricing is inadmissible as FMV in bankruptcy proceedings. C5 — 23 months old. C6 — sold to the debtor''s family member; non-arm''s length and potentially a fraudulent conveyance — a particularly critical rejection in a bankruptcy context. C7 acceptable as secondary court-admissible evidence."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"512 Elmwood Court","prox":"0.5 mi","sub":"Elmwood Park","price":468000,"date":"2 months ago","style":"Colonial","bed":4,"bath":3,"gla":2280,"site":"9,700 SF","yr":2009,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C2","addr":"821 Ridgecrest Drive","prox":"0.7 mi","sub":"Ridgecrest Estates","price":475000,"date":"3 months ago","style":"Colonial","bed":4,"bath":3,"gla":2380,"site":"10,200 SF","yr":2011,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C3","addr":"218 Elmwood Lane","prox":"0.4 mi","sub":"Elmwood Park","price":461000,"date":"5 months ago","style":"Colonial","bed":4,"bath":"2.5","gla":2290,"site":"9,800 SF","yr":2010,"cond":"C3","qual":"Q4","conc":"$4,000 seller paid","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"714 Elmwood Blvd","prox":"0.5 mi","sub":"Elmwood Park","price":421000,"date":"3 months ago","style":"Colonial","bed":4,"bath":3,"gla":2300,"site":"9,900 SF","yr":2010,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Bankruptcy auction / trustee sale — different estate","warn":true},{"id":"C5","addr":"88 Ridgecrest Court","prox":"0.8 mi","sub":"Ridgecrest Estates","price":447000,"date":"23 months ago","style":"Colonial","bed":4,"bath":3,"gla":2340,"site":"10,100 SF","yr":2010,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C6","addr":"315 Elmwood Way","prox":"0.5 mi","sub":"Elmwood Park","price":438000,"date":"3 months ago","style":"Colonial","bed":4,"bath":3,"gla":2270,"site":"9,600 SF","yr":2009,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Sold to debtor''s family member — per deed","warn":true},{"id":"C7","addr":"618 Ridgecrest Way","prox":"0.7 mi","sub":"Ridgecrest Estates","price":471000,"date":"4 months ago","style":"Colonial","bed":4,"bath":3,"gla":2360,"site":"10,300 SF","yr":2011,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Different property type or style","Outside subject market area","Inadequate verification / data","Reflects post-renovation value (subject pre-renovation)","Reflects encumbered / restricted-use conditions","Other"],"subject":{"address":"1128 Elmwood Avenue","subdivision":"Elmwood Park","style":"Colonial","bed":4,"bath":3,"gla":2320,"site":"10,000 SF","yr":2010,"cond":"C3","qual":"Q4","garage":"2-car attached","bsmt":"Finished","pool":"None"}}'::jsonb
