-- Scenario 4.8: Charitable Donation — Non-Cash Asset Appraisal
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 8, 'advanced', 'Charitable Donation — Non-Cash Asset Appraisal', 'A donor is gifting a residential property to a university housing foundation. The property is currently rented to a student on a below-market lease ($700/month vs market $1,400/month) with 8 months remaining. For IRS Form 8283 the appraisal must reflect the fee simple market value — the value unencumbered, as if the lease did not exist. Comparables must reflect properties with market-rate tenancy or owner-occupancy, not below-market encumbered conditions.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 4
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'For an IRS Form 8283 donation, the required standard is fee simple market value — unencumbered, as if the below-market lease did not exist. C1, C2, and C3 are all fee simple or effectively fee simple transactions ($282k–$291k). C4 and C5 are the critical rejections: both were sold encumbered by below-market student leases. The $30k–$35k discount on those properties demonstrates the encumbrance penalty — the very amount that must be excluded from the fee simple donation value. Using leased-fee comps would understate the charitable deduction, which is the IRS-required standard. C6 — 24 months old. C7 acceptable as secondary fee simple support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, owner-occupant, 2 mo. ago, arm''s length. Reflects fee simple unencumbered market value.","C2":"Strong comp — adjacent sub, sold with tenant vacating at closing (effectively fee simple), arm''s length. Minor GLA adj.","C3":"Good comp — same sub, owner-occupant, arm''s length 5 mo. ago. Seller concession adj required.","C4":"Reject — sold encumbered by a below-market lease with 14 months remaining. This reflects a leased-fee (encumbered) value, not the fee simple unencumbered value required for Form 8283. The $34k discount to C1 represents the lease encumbrance — exactly what the appraisal must exclude.","C5":"Reject — sold with a below-market student lease in place. Another leased-fee comp that embeds the encumbrance discount. Using it would understate the fee simple market value for the Form 8283 donation deduction.","C6":"Reject — 24 months old; outside the 12-month guideline. IRS qualified appraisals require current market evidence.","C7":"Acceptable — fee simple owner-occupant sale, 2 mo. ago, arm''s length. Garage adj needed (2-car vs 1-car). C1–C3 more directly comparable but this confirms the unencumbered value range."},"justification":"For an IRS Form 8283 donation, the required standard is fee simple market value — unencumbered, as if the below-market lease did not exist. C1, C2, and C3 are all fee simple or effectively fee simple transactions ($282k–$291k). C4 and C5 are the critical rejections: both were sold encumbered by below-market student leases. The $30k–$35k discount on those properties demonstrates the encumbrance penalty — the very amount that must be excluded from the fee simple donation value. Using leased-fee comps would understate the charitable deduction, which is the IRS-required standard. C6 — 24 months old. C7 acceptable as secondary fee simple support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"814 University Court","prox":"0.4 mi","sub":"University Heights","price":285000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1390,"site":"6,300 SF","yr":2002,"cond":"C3","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length — owner-occupant sale MLS","warn":false},{"id":"C2","addr":"421 Campus Drive","prox":"0.7 mi","sub":"Campus Estates","price":291000,"date":"3 months ago","style":"Ranch","bed":3,"bath":2,"gla":1455,"site":"6,700 SF","yr":2004,"cond":"C3","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length — tenant vacated at sale MLS","warn":false},{"id":"C3","addr":"109 University Lane","prox":"0.5 mi","sub":"University Heights","price":282000,"date":"5 months ago","style":"Ranch","bed":3,"bath":2,"gla":1405,"site":"6,400 SF","yr":2003,"cond":"C3","qual":"Q4","conc":"$2,000 seller paid","gar":"1-car attached","txn":"Arm''s length — owner-occupant sale MLS","warn":false},{"id":"C4","addr":"714 College Blvd","prox":"0.6 mi","sub":"College Park","price":251000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1410,"site":"6,400 SF","yr":2002,"cond":"C3","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Sold subject to below-market lease — 14 months remaining","warn":true},{"id":"C5","addr":"88 Campus Court","prox":"0.7 mi","sub":"Campus Estates","price":257000,"date":"3 months ago","style":"Ranch","bed":3,"bath":2,"gla":1430,"site":"6,500 SF","yr":2003,"cond":"C3","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Sold with below-market student lease in place","warn":true},{"id":"C6","addr":"312 University Way","prox":"0.4 mi","sub":"University Heights","price":271000,"date":"24 months ago","style":"Ranch","bed":3,"bath":2,"gla":1415,"site":"6,300 SF","yr":2002,"cond":"C3","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length — owner-occupant MLS","warn":false},{"id":"C7","addr":"618 Campus Way","prox":"0.8 mi","sub":"Campus Estates","price":288000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1445,"site":"6,600 SF","yr":2004,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — owner-occupant MLS","warn":false}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Different property type or style","Outside subject market area","Inadequate verification / data","Reflects post-renovation value (subject pre-renovation)","Reflects encumbered / restricted-use conditions","Other"],"subject":{"address":"2417 University Drive","subdivision":"University Heights","style":"Ranch","bed":3,"bath":2,"gla":1420,"site":"6,500 SF","yr":2003,"cond":"C3","qual":"Q4","garage":"1-car attached","bsmt":"None","pool":"None"}}'::jsonb
