-- Scenario 4.9: Post-Divorce — Property Settlement Equalization
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 9, 'advanced', 'Post-Divorce — Property Settlement Equalization', 'In a divorce property settlement, the marital home was awarded to one spouse (Spouse A). Spouse B must receive an equalization payment equal to half the home''s fair market value as of the settlement date (today — a current date). A private appraiser (not a litigation appraiser) has been mutually agreed upon. The appraisal must reflect an unencumbered fee simple interest in current market conditions.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 4
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'For a divorce equalization payment, the standard is current open-market fee simple FMV. C1, C2, and C3 are recent arm''s length sales with pools in the competing market ($538k–$558k). C4 rejected — C2 condition would inflate the settlement value above what the C3 subject property supports; adequate C3 comps are available. C5 — sold between another divorcing couple''s LLCs; non-arm''s length, potentially negotiated below market. C6 — short sale/distressed, not open-market. C7 acceptable as secondary support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, 2 mo. ago, arm''s length, pool. 40 SF less GLA. Most directly comparable for settlement equalization.","C2":"Strong comp — adjacent sub, most recent (1 mo.), arm''s length, pool. GLA adj (+60 SF) needed.","C3":"Good comp — adjacent sub, arm''s length 4 mo. ago, pool. Half-bath adj needed.","C4":"Reject — C2 (recently renovated) vs subject''s C3. The condition premium of ~$45k over otherwise similar properties would require an adjustment that inflates the settlement value. C3 condition comps are adequate; using a renovated comp introduces unnecessary upward pressure on the equalization amount.","C5":"Reject — sold between two LLCs owned by another divorcing couple; the price may reflect a negotiated settlement figure rather than open-market conditions. Non-arm''s length; divorce settlement appraisals require the highest independence standard.","C6":"Reject — lender-approved short sale. Distressed seller motivation; short sale pricing does not represent the open-market value relevant to a fair property settlement equalization.","C7":"Acceptable — arm''s length 5 mo. ago, pool, adjacent sub. Slightly larger GLA (+40 SF); C1–C3 are more directly comparable but this confirms the open-market range."},"justification":"For a divorce equalization payment, the standard is current open-market fee simple FMV. C1, C2, and C3 are recent arm''s length sales with pools in the competing market ($538k–$558k). C4 rejected — C2 condition would inflate the settlement value above what the C3 subject property supports; adequate C3 comps are available. C5 — sold between another divorcing couple''s LLCs; non-arm''s length, potentially negotiated below market. C6 — short sale/distressed, not open-market. C7 acceptable as secondary support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"512 Crestwood Court","prox":"0.5 mi","sub":"Crestwood Heights","price":548000,"date":"2 months ago","style":"Two-Story","bed":4,"bath":3,"gla":2340,"site":"10,200 SF","yr":2007,"cond":"C3","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C2","addr":"814 Ridgewood Manor","prox":"0.8 mi","sub":"Ridgewood Heights","price":558000,"date":"1 month ago","style":"Two-Story","bed":4,"bath":3,"gla":2440,"site":"10,700 SF","yr":2009,"cond":"C3","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C3","addr":"109 Crestview Circle","prox":"0.6 mi","sub":"Crestview Estates","price":538000,"date":"4 months ago","style":"Two-Story","bed":4,"bath":"2.5","gla":2360,"site":"10,300 SF","yr":2008,"cond":"C3","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"721 Crestwood Way","prox":"0.5 mi","sub":"Crestwood Heights","price":595000,"date":"2 months ago","style":"Two-Story","bed":4,"bath":3,"gla":2395,"site":"10,400 SF","yr":2009,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C5","addr":"88 Ridgewood Drive","prox":"0.8 mi","sub":"Ridgewood Heights","price":521000,"date":"2 months ago","style":"Two-Story","bed":4,"bath":3,"gla":2360,"site":"10,200 SF","yr":2008,"cond":"C3","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Sold between divorcing spouses'' LLCs","warn":true},{"id":"C6","addr":"312 Crestwood Lane","prox":"0.4 mi","sub":"Crestwood Heights","price":489000,"date":"3 months ago","style":"Two-Story","bed":4,"bath":3,"gla":2350,"site":"10,100 SF","yr":2007,"cond":"C3","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Short sale — lender-approved","warn":true},{"id":"C7","addr":"617 Ridgewood Court","prox":"0.9 mi","sub":"Ridgewood Heights","price":544000,"date":"5 months ago","style":"Two-Story","bed":4,"bath":3,"gla":2420,"site":"10,600 SF","yr":2008,"cond":"C3","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS","warn":false}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Different property type or style","Outside subject market area","Inadequate verification / data","Reflects post-renovation value (subject pre-renovation)","Reflects encumbered / restricted-use conditions","Other"],"subject":{"address":"4821 Crestwood Drive","subdivision":"Crestwood Heights","style":"Two-Story","bed":4,"bath":3,"gla":2380,"site":"10,500 SF","yr":2008,"cond":"C3","qual":"Q4","garage":"3-car attached","bsmt":"Finished","pool":"Pool"}}'::jsonb
