-- Scenario 4.10: Fractional Interest — Tenancy in Common
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 10, 'advanced', 'Fractional Interest — Tenancy in Common', 'You have been retained to appraise a 40% undivided tenancy-in-common (TIC) interest in a residential property for a private sale between co-owners. The assignment has two steps: (1) establish the fee simple market value of the whole property, then (2) apply a marketability/control discount to the TIC interest. Comparables must reflect the whole property''s fee simple value — not encumbered or partial-interest sales.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 4
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'Step 1 requires establishing the fee simple whole-property value. C1, C2, and C3 are all fee simple arm''s length sales in the competing market ($605k–$629k). The TIC discount is applied separately after this baseline is established. C4 — the critical rejection: a partial TIC interest sale embeds the very discount being analyzed; using it as a fee simple comp would understate the whole-property baseline and distort the TIC discount calculation. C5 — estate auction, non-arm''s length. C6 — 27 months old. C7 acceptable as secondary fee simple support. After establishing the ~$615k–$625k fee simple value, a marketability/control discount (typically 10–30% for residential TIC interests) is then applied to the 40% interest.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, fee simple sale, 2 mo. ago, arm''s length. 40 SF less GLA and pool. Minor GLA adj.","C2":"Strong comp — adjacent high-end sub, fee simple, arm''s length 3 mo. ago. GLA adj (+80 SF) and site adj needed.","C3":"Good comp — same sub, fee simple, arm''s length 5 mo. ago. Seller concession and half-bath adj needed.","C4":"Reject — partial TIC interest sale, not a fee simple transaction. The $498k reflects a 50% undivided interest with its associated discount for lack of control and marketability. Using a partial-interest sale to establish whole-property fee simple value would incorrectly embed the TIC discount in the baseline.","C5":"Reject — estate auction sale; non-arm''s length. Auction pricing reflects compressed marketing time and buyer pool; not an appropriate benchmark for the fee simple market value baseline.","C6":"Reject — 27 months old; outside the 12-month guideline for a current value opinion.","C7":"Acceptable — fee simple, arm''s length 4 mo. ago. Slightly larger GLA and site; C1–C3 are more comparable but this confirms the fee simple value range."},"justification":"Step 1 requires establishing the fee simple whole-property value. C1, C2, and C3 are all fee simple arm''s length sales in the competing market ($605k–$629k). The TIC discount is applied separately after this baseline is established. C4 — the critical rejection: a partial TIC interest sale embeds the very discount being analyzed; using it as a fee simple comp would understate the whole-property baseline and distort the TIC discount calculation. C5 — estate auction, non-arm''s length. C6 — 27 months old. C7 acceptable as secondary fee simple support. After establishing the ~$615k–$625k fee simple value, a marketability/control discount (typically 10–30% for residential TIC interests) is then applied to the 40% interest."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"812 Lakeshore Court","prox":"0.5 mi","sub":"Lakeshore Estates","price":618000,"date":"2 months ago","style":"Colonial","bed":4,"bath":3,"gla":2560,"site":"0.78 acres","yr":2005,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — fee simple MLS","warn":false},{"id":"C2","addr":"421 Maplewood Manor","prox":"0.8 mi","sub":"Maplewood Manor","price":629000,"date":"3 months ago","style":"Colonial","bed":4,"bath":3,"gla":2680,"site":"0.85 acres","yr":2007,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — fee simple MLS","warn":false},{"id":"C3","addr":"119 Lakeshore Lane","prox":"0.6 mi","sub":"Lakeshore Estates","price":605000,"date":"5 months ago","style":"Colonial","bed":4,"bath":"2.5","gla":2580,"site":"0.79 acres","yr":2006,"cond":"C2","qual":"Q4","conc":"$5,000 seller paid","gar":"3-car attached","txn":"Arm''s length — fee simple MLS","warn":false},{"id":"C4","addr":"714 Lakeshore Blvd","prox":"0.5 mi","sub":"Lakeshore Estates","price":498000,"date":"3 months ago","style":"Colonial","bed":4,"bath":3,"gla":2590,"site":"0.80 acres","yr":2006,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"50% TIC interest sold to co-owner","warn":true},{"id":"C5","addr":"88 Maplewood Court","prox":"0.8 mi","sub":"Maplewood Manor","price":489000,"date":"2 months ago","style":"Colonial","bed":4,"bath":3,"gla":2570,"site":"0.77 acres","yr":2006,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Sold at estate auction — non-arm''s length","warn":true},{"id":"C6","addr":"312 Lakeshore Way","prox":"0.5 mi","sub":"Lakeshore Estates","price":595000,"date":"27 months ago","style":"Colonial","bed":4,"bath":3,"gla":2620,"site":"0.82 acres","yr":2005,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — fee simple MLS","warn":false},{"id":"C7","addr":"618 Maplewood Drive","prox":"0.9 mi","sub":"Maplewood Manor","price":622000,"date":"4 months ago","style":"Colonial","bed":4,"bath":3,"gla":2640,"site":"0.83 acres","yr":2007,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — fee simple MLS","warn":false}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Different property type or style","Outside subject market area","Inadequate verification / data","Reflects post-renovation value (subject pre-renovation)","Reflects encumbered / restricted-use conditions","Other"],"subject":{"address":"3214 Lakeshore Drive","subdivision":"Lakeshore Estates","style":"Colonial","bed":4,"bath":3,"gla":2600,"site":"0.80 acres","yr":2006,"cond":"C2","qual":"Q4","garage":"3-car attached","bsmt":"Finished","pool":"Pool & spa"}}'::jsonb
