WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- ─────────────── Category 5: Government & Public Use ───────────────
-- Scenario 5.1: VA Purchase Loan — MPR Compliance
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 1, 'basic', 'VA Purchase Loan — MPR Compliance', 'You have been assigned by Veterans United Home Loans to appraise a single-family residence for a VA-guaranteed purchase loan. Contract price: $318,000. The scope requires a VA appraisal (VA Form 26-1805) with full interior inspection. VA Minimum Property Requirements (MPRs) apply. VA guidelines require the appraiser to use the most recent, most proximate, and most similar arm''s length sales.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 5
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'VA guidelines require the most recent, most proximate, arm''s length comparable sales. C1 (same sub, 2 mo., 30 SF less GLA), C2 (adjacent sub, most recent at 1 mo.), and C3 (same sub, 4 mo., concession adj) form a range of ~$305k–$315k (adjusted), supporting the $318k contract price with modest positive adjustments. C4 rejected — REO; VA appraisals must use market-rate sales. C5 — 19 months, outside VA recency standard. C6 is acceptable but less proximate. C7 — family transfer, non-arm''s length.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"accept","C7":"reject"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, 2 mo. ago, arm''s length. 30 SF less GLA, no concessions. Meets VA recency and proximity priority.","C2":"Strong comp — adjacent sub, most recent (1 mo.), arm''s length. Minor GLA adj. Meets VA recency priority.","C3":"Good comp — same sub, 4 mo., arm''s length. Seller concession adj required.","C4":"Reject — bank-owned REO. VA appraisals must use market-rate arm''s length sales. REO pricing does not reflect conditions a veteran borrower faces as a typical buyer. VA guidelines specifically caution against distressed sale reliance.","C5":"Reject — 19 months old; exceeds the 12-month guideline. VA guidelines prioritize the most recent comparable sales to support current market conditions.","C6":"Acceptable — recent arm''s length, physically similar. Located 1.3 mi away; VA guidelines favor proximity, so C1–C3 are preferred. This sale supports the value range but is the weakest of the pool.","C7":"Reject — parent-to-child transfer; non-arm''s length. VA guidelines require arm''s length transactions; a family transfer at the contract price creates a false impression of value support."},"justification":"VA guidelines require the most recent, most proximate, arm''s length comparable sales. C1 (same sub, 2 mo., 30 SF less GLA), C2 (adjacent sub, most recent at 1 mo.), and C3 (same sub, 4 mo., concession adj) form a range of ~$305k–$315k (adjusted), supporting the $318k contract price with modest positive adjustments. C4 rejected — REO; VA appraisals must use market-rate sales. C5 — 19 months, outside VA recency standard. C6 is acceptable but less proximate. C7 — family transfer, non-arm''s length."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"412 Liberty Court","prox":"0.4 mi","sub":"Liberty Heights","price":309000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1590,"site":"7,200 SF","yr":2005,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C2","addr":"818 Patriot Drive","prox":"0.7 mi","sub":"Patriot Estates","price":315000,"date":"1 month ago","style":"Ranch","bed":3,"bath":2,"gla":1660,"site":"7,700 SF","yr":2007,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C3","addr":"109 Liberty Lane","prox":"0.5 mi","sub":"Liberty Heights","price":305000,"date":"4 months ago","style":"Ranch","bed":3,"bath":2,"gla":1605,"site":"7,300 SF","yr":2005,"cond":"C3","qual":"Q4","conc":"$2,500 seller paid","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"721 Liberty Blvd","prox":"0.5 mi","sub":"Liberty Heights","price":298000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1610,"site":"7,300 SF","yr":2006,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Bank-owned REO","warn":true},{"id":"C5","addr":"88 Patriot Court","prox":"0.7 mi","sub":"Patriot Estates","price":311000,"date":"19 months ago","style":"Ranch","bed":3,"bath":2,"gla":1630,"site":"7,500 SF","yr":2006,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C6","addr":"415 Ridgecrest Way","prox":"1.3 mi","sub":"Ridgecrest Park","price":312000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1640,"site":"7,600 SF","yr":2007,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C7","addr":"312 Liberty Way","prox":"0.5 mi","sub":"Liberty Heights","price":318000,"date":"3 months ago","style":"Ranch","bed":3,"bath":2,"gla":1615,"site":"7,400 SF","yr":2007,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Parent-to-child transfer — per deed","warn":true}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Outside subject market area","Different property type or style","Reflects project influence — must be excluded","Reflects post-acquisition/post-taking conditions","Reflects government-restricted value, not fee simple","Inadequate verification / data","Other"],"subject":{"address":"2847 Liberty Drive","subdivision":"Liberty Heights","style":"Ranch","bed":3,"bath":2,"gla":1620,"site":"7,500 SF","yr":2006,"cond":"C3","qual":"Q4","garage":"2-car attached","bsmt":"None","pool":"None"}}'::jsonb
FROM ins,
  module_sections ms
  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- Scenario 5.2: HUD REO Disposition — As-Is Value
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 2, 'basic', 'HUD REO Disposition — As-Is Value', 'HUD has assigned you to appraise a HUD-owned (REO) single-family property for disposition pricing. The subject is an FHA-foreclosed property that will be sold ''as-is'' to the public through HUD''s online bidding system. HUD requires an as-is FMV opinion per HUD Handbook 4150.2. Comparables must reflect the subject''s actual as-is condition — neither inflated by renovated comps nor deflated by using other HUD/REO distressed sales as comps.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 5
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'HUD Handbook 4150.2 requires an as-is FMV opinion using condition-matched arm''s length sales. C1, C2, and C3 are C4/C3-C4 condition properties ($219k–$231k). C4 rejected — renovated C2 comp would overstate the as-is value; HUD bidders need an accurate as-is price. C5 — HUD''s own REO disposition; circular reasoning prohibited. C6 — C5 condition understates the as-is value. C7 acceptable as secondary C4 support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, C4 condition confirmed, 3 mo. ago, arm''s length. Directly reflects the subject''s as-is market segment.","C2":"Strong comp — C3-C4 straddle condition, most recent (2 mo.), arm''s length. Minor GLA adj (+35 SF). Small downward condition adj toward C4.","C3":"Good comp — same sub, C4 condition, arm''s length 5 mo. ago. Seller concession adj required.","C4":"Reject — fully renovated C2 vs subject''s C4 as-is. HUD Handbook 4150.2 requires as-is value; using a renovated comp would overstate the disposition price and misrepresent the as-is condition to HUD bidders.","C5":"Reject — another HUD REO disposition. HUD''s own disposition sales cannot be used to establish HUD disposition pricing; it is circular. HUD REO pricing reflects programmatic factors (online bidding format, as-is disclosure, FHA buyer pool) that distort market value.","C6":"Reject — C5 condition is below the subject''s C4. HUD requires the comp to match the subject''s as-is condition; a C5 comp would understate the disposition value.","C7":"Acceptable — C4 condition, arm''s length 4 mo. ago. Farther at 0.8 mi; C1–C3 more directly comparable but confirms the as-is value range."},"justification":"HUD Handbook 4150.2 requires an as-is FMV opinion using condition-matched arm''s length sales. C1, C2, and C3 are C4/C3-C4 condition properties ($219k–$231k). C4 rejected — renovated C2 comp would overstate the as-is value; HUD bidders need an accurate as-is price. C5 — HUD''s own REO disposition; circular reasoning prohibited. C6 — C5 condition understates the as-is value. C7 acceptable as secondary C4 support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"514 Greenfield Court","prox":"0.4 mi","sub":"Greenfield Heights","price":224000,"date":"3 months ago","style":"Ranch","bed":3,"bath":2,"gla":1380,"site":"6,500 SF","yr":1994,"cond":"C4","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length MLS — sold as-is, condition confirmed","warn":false},{"id":"C2","addr":"821 Maplewood Drive","prox":"0.7 mi","sub":"Maplewood Estates","price":231000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1445,"site":"7,000 SF","yr":1996,"cond":"C3-C4","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C3","addr":"218 Greenfield Lane","prox":"0.5 mi","sub":"Greenfield Heights","price":219000,"date":"5 months ago","style":"Ranch","bed":3,"bath":2,"gla":1395,"site":"6,600 SF","yr":1994,"cond":"C4","qual":"Q4","conc":"$1,500 seller paid","gar":"1-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"715 Greenfield Blvd","prox":"0.4 mi","sub":"Greenfield Heights","price":281000,"date":"3 months ago","style":"Ranch","bed":3,"bath":2,"gla":1420,"site":"6,800 SF","yr":1995,"cond":"C2 (fully renovated)","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C5","addr":"88 Maplewood Court","prox":"0.7 mi","sub":"Maplewood Estates","price":192000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1405,"site":"6,700 SF","yr":1993,"cond":"C4","qual":"Q4","conc":"None","gar":"1-car attached","txn":"HUD REO — another FHA foreclosure disposition","warn":true},{"id":"C6","addr":"312 Greenfield Way","prox":"0.4 mi","sub":"Greenfield Heights","price":188000,"date":"4 months ago","style":"Ranch","bed":3,"bath":2,"gla":1400,"site":"6,500 SF","yr":1994,"cond":"C5","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C7","addr":"618 Maplewood Lane","prox":"0.8 mi","sub":"Maplewood Estates","price":226000,"date":"4 months ago","style":"Ranch","bed":3,"bath":2,"gla":1430,"site":"6,900 SF","yr":1996,"cond":"C4","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length — MLS","warn":false}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Outside subject market area","Different property type or style","Reflects project influence — must be excluded","Reflects post-acquisition/post-taking conditions","Reflects government-restricted value, not fee simple","Inadequate verification / data","Other"],"subject":{"address":"1842 Greenfield Drive","subdivision":"Greenfield Heights","style":"Ranch","bed":3,"bath":2,"gla":1410,"site":"6,800 SF","yr":1995,"cond":"C4 (deferred maint.)","qual":"Q4","garage":"1-car attached","bsmt":"None","pool":"None"}}'::jsonb
FROM ins,
  module_sections ms
  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- Scenario 5.3: FEMA Disaster Assistance — Pre-Disaster Value
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 3, 'intermediate', 'FEMA Disaster Assistance — Pre-Disaster Value', 'FEMA''s Individual Assistance program has commissioned you to establish the pre-disaster fair market value of a flood-damaged residence as of the date of the declared disaster (8 months ago). The property sustained major structural damage. The pre-disaster value establishes the baseline for FEMA''s maximum assistance calculation. Comparables must reflect pre-disaster, unaffected market conditions.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 5
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'FEMA pre-disaster value requires sales contemporaneous with and reflective of pre-disaster conditions. C1 (10 mo., same sub), C2 (7 mo., unaffected adjacent sub), and C3 (11 mo., same sub) bracket the disaster date at $311k–$324k. C4 and C5 — the critical rejections: post-disaster sales embed flood damage and market stigma. Using them would understate the pre-disaster baseline and reduce FEMA assistance below the actual loss. The purpose is to capture what the property was worth before the event — any post-disaster sale in the affected zone fails this test. C6 — 24 months old. C7 acceptable as pre-disaster secondary support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, 10 mo. ago (2 mo. before disaster), arm''s length. Reflects pre-disaster market conditions.","C2":"Strong comp — adjacent sub outside the flood zone, 7 mo. ago (1 mo. post-disaster but property unaffected), arm''s length. Minor GLA adj. Creekside did not flood; this reflects unaffected market conditions.","C3":"Good comp — same sub, 11 mo. ago (3 mo. before disaster), arm''s length. Seller concession adj required. Pre-disaster conditions.","C4":"Reject — post-disaster sale reflecting flood damage and market stigma. FEMA requires the pre-disaster value; post-disaster sales in the affected area embed the damage discount. Using them understates the FMV baseline and reduces FEMA assistance below what the disaster actually cost.","C5":"Reject — post-disaster distressed sale with flood damage. Reflects both the physical damage and buyer hesitation in a post-flood market; neither reflects pre-disaster market value.","C6":"Reject — 24 months old; sold 16 months before the disaster. Does not adequately reflect pre-disaster market conditions.","C7":"Acceptable — adjacent unaffected sub, 9 mo. ago (1 mo. before disaster), arm''s length. Slightly larger GLA; C1–C3 more directly comparable but confirms pre-disaster range."},"justification":"FEMA pre-disaster value requires sales contemporaneous with and reflective of pre-disaster conditions. C1 (10 mo., same sub), C2 (7 mo., unaffected adjacent sub), and C3 (11 mo., same sub) bracket the disaster date at $311k–$324k. C4 and C5 — the critical rejections: post-disaster sales embed flood damage and market stigma. Using them would understate the pre-disaster baseline and reduce FEMA assistance below the actual loss. The purpose is to capture what the property was worth before the event — any post-disaster sale in the affected zone fails this test. C6 — 24 months old. C7 acceptable as pre-disaster secondary support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"814 Riverside Court","prox":"0.5 mi","sub":"Riverside Meadows","price":318000,"date":"10 months ago","style":"Ranch","bed":3,"bath":2,"gla":1650,"site":"7,800 SF","yr":2000,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C2","addr":"421 Creekside Drive","prox":"0.7 mi","sub":"Creekside Estates","price":324000,"date":"7 months ago","style":"Ranch","bed":3,"bath":2,"gla":1720,"site":"8,200 SF","yr":2002,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS (outside flood zone)","warn":false},{"id":"C3","addr":"108 Riverside Lane","prox":"0.4 mi","sub":"Riverside Meadows","price":311000,"date":"11 months ago","style":"Ranch","bed":3,"bath":2,"gla":1660,"site":"7,900 SF","yr":2001,"cond":"C3","qual":"Q4","conc":"$2,000 seller paid","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"519 Riverside Blvd","prox":"0.5 mi","sub":"Riverside Meadows","price":261000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1670,"site":"8,000 SF","yr":2001,"cond":"C4 (post-flood damage)","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — post-disaster sale","warn":true},{"id":"C5","addr":"712 Riverside Way","prox":"0.4 mi","sub":"Riverside Meadows","price":249000,"date":"3 months ago","style":"Ranch","bed":3,"bath":2,"gla":1655,"site":"7,900 SF","yr":2001,"cond":"C4 (flood-damaged)","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Post-disaster distressed sale","warn":true},{"id":"C6","addr":"215 Riverside Court","prox":"0.5 mi","sub":"Riverside Meadows","price":298000,"date":"24 months ago","style":"Ranch","bed":3,"bath":2,"gla":1665,"site":"7,900 SF","yr":2000,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C7","addr":"88 Creekside Court","prox":"0.7 mi","sub":"Creekside Estates","price":316000,"date":"9 months ago","style":"Ranch","bed":3,"bath":2,"gla":1695,"site":"8,100 SF","yr":2002,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Outside subject market area","Different property type or style","Reflects project influence — must be excluded","Reflects post-acquisition/post-taking conditions","Reflects government-restricted value, not fee simple","Inadequate verification / data","Other"],"subject":{"address":"3214 Riverside Road","subdivision":"Riverside Meadows","style":"Ranch","bed":3,"bath":2,"gla":1680,"site":"8,000 SF","yr":2001,"cond":"C3 (pre-disaster)","qual":"Q4","garage":"2-car attached","bsmt":"None","pool":"None"}}'::jsonb
FROM ins,
  module_sections ms
  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- Scenario 5.4: Highway Right-of-Way — Before Value
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 4, 'intermediate', 'Highway Right-of-Way — Before Value', 'The State DOT retained you as part of a highway widening project. The subject will lose a 20-foot strip from the front yard, reducing site area from 0.35 acres to 0.27 acres. You are establishing the ''before'' market value as of the date of take (14 months ago). Under the Uniform Relocation Act and FHWA guidelines, comparables must be free of project influence — sales near the project corridor whose prices were affected by the announcement or construction must be excluded.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 5
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'FHWA guidelines add a filter that USPAP alone does not require: project influence exclusion. C1, C2, and C3 are all free of project influence, within 3 months of the take date, and arm''s length ($341k–$355k). C4 and C5 — the defining rejections: both are in the project impact corridor with prices likely reflecting buyer hesitation from the widening announcement. FHWA guidelines mandate their exclusion even if they are otherwise physically and temporally comparable. C6 — non-competing market area. C7 — relocation buyout, non-arm''s length. C8 acceptable as secondary project-free support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"reject","C8":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same area, full unencumbered lot (0.34 ac.), 2 mo. before take, arm''s length. Free of project influence (seller not aware of project at time of sale).","C2":"Strong comp — adjacent sub away from project corridor, 1 mo. after take with no influence, arm''s length. Minor GLA and site adj.","C3":"Good comp — same area, matching lot size (0.35 ac.), 1 mo. before take, arm''s length. Near-identical GLA.","C4":"Reject — this property is immediately adjacent to the highway ROW corridor. FHWA guidelines require exclusion of sales influenced by project announcement or construction. The lower price likely reflects buyer hesitation due to the pending widening — project influence disqualifies this comp for establishing pre-take before value.","C5":"Reject — within the project impact corridor; sold after project was publicly announced. FHWA guidelines mandate exclusion of project-influenced sales whether they are depressed (buyer hesitation) or inflated (benefit area). This sale cannot establish pre-take unaffected value.","C6":"Reject — 3.5 miles away in Oak Valley, a non-competing market. Despite physical and temporal similarity, buyers for State Highway 31 frontage properties would not consider Oak Valley an alternative location.","C7":"Reject — relocation buyout at take date; non-arm''s length. Federal right-of-way appraisals under the Uniform Relocation Act require the strictest arm''s length standard.","C8":"Acceptable — free of project influence, 2 mo. before take, arm''s length. Slightly farther and larger; C1–C3 are more comparable but this confirms the before-value range."},"justification":"FHWA guidelines add a filter that USPAP alone does not require: project influence exclusion. C1, C2, and C3 are all free of project influence, within 3 months of the take date, and arm''s length ($341k–$355k). C4 and C5 — the defining rejections: both are in the project impact corridor with prices likely reflecting buyer hesitation from the widening announcement. FHWA guidelines mandate their exclusion even if they are otherwise physically and temporally comparable. C6 — non-competing market area. C7 — relocation buyout, non-arm''s length. C8 acceptable as secondary project-free support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"2814 Northside Court","prox":"0.5 mi","sub":"Northside Heights","price":348000,"date":"16 months ago","style":"Ranch","bed":3,"bath":2,"gla":1790,"site":"0.34 acres","yr":2003,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C2","addr":"591 Westfield Drive","prox":"0.8 mi","sub":"Westfield Estates","price":355000,"date":"13 months ago","style":"Ranch","bed":3,"bath":2,"gla":1860,"site":"0.36 acres","yr":2005,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C3","addr":"109 Northside Blvd","prox":"0.6 mi","sub":"Northside Heights","price":341000,"date":"15 months ago","style":"Ranch","bed":3,"bath":2,"gla":1805,"site":"0.35 acres","yr":2004,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"428 Hwy 31 Frontage Road","prox":"0.3 mi","sub":"Northside Heights","price":298000,"date":"14 months ago","style":"Ranch","bed":3,"bath":2,"gla":1810,"site":"0.35 acres","yr":2004,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS, adjacent to project ROW","warn":true},{"id":"C5","addr":"712 Hwy 31 Service Rd","prox":"0.2 mi","sub":"Northside Heights","price":312000,"date":"12 months ago","style":"Ranch","bed":3,"bath":2,"gla":1815,"site":"0.35 acres","yr":2003,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS, within project impact corridor","warn":true},{"id":"C6","addr":"2241 Oak Valley Road","prox":"3.5 mi","sub":"Oak Valley","price":352000,"date":"14 months ago","style":"Ranch","bed":3,"bath":2,"gla":1830,"site":"0.36 acres","yr":2004,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C7","addr":"311 Northside Court","prox":"0.4 mi","sub":"Northside Heights","price":347000,"date":"14 months ago","style":"Ranch","bed":3,"bath":2,"gla":1795,"site":"0.33 acres","yr":2004,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Relocation company buyout — employer purchase","warn":true},{"id":"C8","addr":"544 Westfield Court","prox":"0.9 mi","sub":"Westfield Estates","price":349000,"date":"16 months ago","style":"Ranch","bed":3,"bath":2,"gla":1870,"site":"0.37 acres","yr":2003,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Outside subject market area","Different property type or style","Reflects project influence — must be excluded","Reflects post-acquisition/post-taking conditions","Reflects government-restricted value, not fee simple","Inadequate verification / data","Other"],"subject":{"address":"4418 State Highway 31","subdivision":"Northside Heights","style":"Ranch","bed":3,"bath":2,"gla":1820,"site":"0.35 acres (before)","yr":2004,"cond":"C3","qual":"Q4","garage":"2-car attached","bsmt":"None","pool":"None"}}'::jsonb
FROM ins,
  module_sections ms
  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- Scenario 5.5: Section 8 Housing Voucher — HCV Rent Reasonableness
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 5, 'intermediate', 'Section 8 Housing Voucher — HCV Rent Reasonableness', 'A public housing authority (PHA) retained you to establish market rent and market value for a single-family home that a Section 8 Housing Choice Voucher (HCV) holder wishes to lease. The PHA must confirm the rent is ''reasonable'' compared to unsubsidized market rents. Your appraisal must reflect fee simple market value and current market rent for the property type — not subsidized or below-market rents.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 5
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'HCV rent reasonableness requires unencumbered fee simple market value — what the property would sell for without any HUD or affordability restrictions. C1, C2, C3 are unencumbered arm''s length sales ($261k–$271k). C4 — sold with a Section 8 lease in place; the restricted rental income reduces the investor''s price below fee simple value. C5 — community land trust affordable restriction; same problem. These two comps reflect exactly the restricted-use value that the PHA''s rent reasonableness analysis is designed to detect and exclude. C6 — 23 months old. C7 acceptable as secondary fee simple support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, 2 mo., arm''s length owner-occupant. Reflects fee simple unencumbered market value.","C2":"Strong comp — adjacent sub, arm''s length 3 mo. Minor GLA adj (+35 SF).","C3":"Good comp — same sub, 5 mo., arm''s length. Seller concession adj required.","C4":"Reject — sold with a Section 8 lease in place. The below-market HCV contract rent encumbers this sale; buyer paid a discounted price reflecting the rental income restriction. Using it as a fee simple comp understates unencumbered market value — the exact standard the PHA needs.","C5":"Reject — subject to a community land trust affordable restriction. Like the Section 8-encumbered sale, this price reflects a restricted-use value, not fee simple market value. Government rent-reasonableness analysis must use unencumbered fee simple evidence.","C6":"Reject — 23 months old; outside the 12-month guideline for a current market value opinion.","C7":"Acceptable — arm''s length 4 mo. ago, adjacent sub. Minor GLA adj. C1–C3 more directly comparable but confirms the unencumbered market value range."},"justification":"HCV rent reasonableness requires unencumbered fee simple market value — what the property would sell for without any HUD or affordability restrictions. C1, C2, C3 are unencumbered arm''s length sales ($261k–$271k). C4 — sold with a Section 8 lease in place; the restricted rental income reduces the investor''s price below fee simple value. C5 — community land trust affordable restriction; same problem. These two comps reflect exactly the restricted-use value that the PHA''s rent reasonableness analysis is designed to detect and exclude. C6 — 23 months old. C7 acceptable as secondary fee simple support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"514 Elm Court","prox":"0.4 mi","sub":"Elmwood Park","price":264000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1355,"site":"6,000 SF","yr":1998,"cond":"C3","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length — MLS owner-occupant sale","warn":false},{"id":"C2","addr":"821 Maple Drive","prox":"0.7 mi","sub":"Maple Heights","price":271000,"date":"3 months ago","style":"Ranch","bed":3,"bath":2,"gla":1415,"site":"6,400 SF","yr":2000,"cond":"C3","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C3","addr":"218 Elm Lane","prox":"0.5 mi","sub":"Elmwood Park","price":261000,"date":"5 months ago","style":"Ranch","bed":3,"bath":2,"gla":1365,"site":"6,100 SF","yr":1998,"cond":"C3","qual":"Q4","conc":"$2,000 seller paid","gar":"1-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"714 Elm Blvd","prox":"0.5 mi","sub":"Elmwood Park","price":221000,"date":"3 months ago","style":"Ranch","bed":3,"bath":2,"gla":1370,"site":"6,000 SF","yr":1999,"cond":"C3","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Sold subject to Section 8 lease in place","warn":true},{"id":"C5","addr":"88 Maple Court","prox":"0.7 mi","sub":"Maple Heights","price":215000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1390,"site":"6,300 SF","yr":1998,"cond":"C3","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Sold subject to affordably-restricted land trust lease","warn":true},{"id":"C6","addr":"312 Elm Way","prox":"0.5 mi","sub":"Elmwood Park","price":253000,"date":"23 months ago","style":"Ranch","bed":3,"bath":2,"gla":1375,"site":"6,000 SF","yr":1998,"cond":"C3","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C7","addr":"618 Maple Way","prox":"0.8 mi","sub":"Maple Heights","price":267000,"date":"4 months ago","style":"Ranch","bed":3,"bath":2,"gla":1400,"site":"6,400 SF","yr":2000,"cond":"C3","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length — MLS","warn":false}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Outside subject market area","Different property type or style","Reflects project influence — must be excluded","Reflects post-acquisition/post-taking conditions","Reflects government-restricted value, not fee simple","Inadequate verification / data","Other"],"subject":{"address":"2841 Elm Street","subdivision":"Elmwood Park","style":"Ranch","bed":3,"bath":2,"gla":1380,"site":"6,200 SF","yr":1999,"cond":"C3","qual":"Q4","garage":"1-car attached","bsmt":"None","pool":"None"}}'::jsonb
