-- Scenario 5.6: Eminent Domain — Project Influence Exclusion (Advanced)
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 6, 'advanced', 'Eminent Domain — Project Influence Exclusion (Advanced)', 'A municipal redevelopment authority retained you to appraise a residential property for acquisition in connection with a public transit hub project. The date of take is 12 months ago. Sales within the project influence area — where prices were affected (up or down) by the project announcement — must be excluded under the Uniform Relocation Act. The project was publicly announced 30 months ago; its influence zone extends approximately 0.75 miles from the hub site.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 5
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'The controlling rule for this federal acquisition: comps must be outside the project influence zone regardless of proximity or physical similarity. C1, C2, and C3 are all confirmed outside the 0.75-mi influence zone ($332k–$345k). The extended search distances (0.6–1.1 mi) are not only acceptable but necessary under the Uniform Relocation Act. C4 and C5 — the key lesson: these are actually more proximate and physically similar than the accepted comps, but their transit-premium prices embed exactly the project influence that must be excluded. The federal appraiser must use more distant comps rather than compromise the influence-free standard. C6 — double disqualification (non-arm''s length AND in influence zone). C7 acceptable as secondary influence-free support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same general area but confirmed outside the 0.75-mi influence zone. 2 mo. before take, arm''s length. Free of project influence.","C2":"Strong comp — outside influence zone, 1 mo. after take (no change), arm''s length. Minor GLA adj (+40 SF).","C3":"Good comp — outside influence zone, 1 mo. before take, arm''s length. Extended distance of 1.1 mi is necessary because sales within the influence zone must be excluded.","C4":"Reject — within the 0.75-mi project influence zone. This inflated price likely reflects transit proximity premiums from buyers anticipating walk-to-transit access. Uniform Relocation Act requires exclusion of both negative and positive project influence. Using transit-premium comps would overcompensate the property owner above true pre-project market value.","C5":"Reject — very close to transit hub (0.3 mi), within influence zone. Sold post-announcement with significant transit premium. Federal guidelines are clear: project-influenced sales — positive or negative — must be excluded to establish unaffected before-take value.","C6":"Reject — relocation buyout within the influence zone. Double disqualification: non-arm''s length AND within the project influence zone. Federal appraisal standards require arm''s length, project-influence-free evidence.","C7":"Acceptable — outside influence zone, 2 mo. before take, arm''s length. Extended distance of 1.3 mi required because available nearby comps are influence-zone contaminated. C1–C3 more comparable but this confirms the influence-free value range."},"justification":"The controlling rule for this federal acquisition: comps must be outside the project influence zone regardless of proximity or physical similarity. C1, C2, and C3 are all confirmed outside the 0.75-mi influence zone ($332k–$345k). The extended search distances (0.6–1.1 mi) are not only acceptable but necessary under the Uniform Relocation Act. C4 and C5 — the key lesson: these are actually more proximate and physically similar than the accepted comps, but their transit-premium prices embed exactly the project influence that must be excluded. The federal appraiser must use more distant comps rather than compromise the influence-free standard. C6 — double disqualification (non-arm''s length AND in influence zone). C7 acceptable as secondary influence-free support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"812 Central Court","prox":"0.6 mi","sub":"Central Heights (outside influence zone)","price":338000,"date":"14 months ago","style":"Ranch","bed":3,"bath":2,"gla":1690,"site":"7,600 SF","yr":2002,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS, confirmed outside influence zone","warn":false},{"id":"C2","addr":"421 Westpark Drive","prox":"0.9 mi","sub":"Westpark Estates (outside influence zone)","price":345000,"date":"11 months ago","style":"Ranch","bed":3,"bath":2,"gla":1760,"site":"8,000 SF","yr":2004,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS, confirmed outside influence zone","warn":false},{"id":"C3","addr":"119 Ferndale Road","prox":"1.1 mi","sub":"Ferndale Heights (outside influence zone)","price":332000,"date":"13 months ago","style":"Ranch","bed":3,"bath":2,"gla":1705,"site":"7,700 SF","yr":2003,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS, confirmed outside influence zone","warn":false},{"id":"C4","addr":"428 Transit Blvd","prox":"0.2 mi","sub":"Central Heights (in influence zone)","price":388000,"date":"12 months ago","style":"Ranch","bed":3,"bath":2,"gla":1710,"site":"7,800 SF","yr":2004,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS, within influence zone","warn":true},{"id":"C5","addr":"712 Hub Circle","prox":"0.3 mi","sub":"Central Heights (in influence zone)","price":401000,"date":"10 months ago","style":"Ranch","bed":3,"bath":2,"gla":1730,"site":"8,000 SF","yr":2003,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS, within influence zone","warn":true},{"id":"C6","addr":"311 Transit Way","prox":"0.5 mi","sub":"Central Heights (edge of influence zone)","price":354000,"date":"12 months ago","style":"Ranch","bed":3,"bath":2,"gla":1715,"site":"7,700 SF","yr":2003,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Relocation buyout — displaced tenant owner","warn":true},{"id":"C7","addr":"219 Oak Terrace","prox":"1.3 mi","sub":"Oakdale Heights (outside influence zone)","price":336000,"date":"14 months ago","style":"Ranch","bed":3,"bath":2,"gla":1745,"site":"8,100 SF","yr":2004,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Outside subject market area","Different property type or style","Reflects project influence — must be excluded","Reflects post-acquisition/post-taking conditions","Reflects government-restricted value, not fee simple","Inadequate verification / data","Other"],"subject":{"address":"3518 Transit Avenue","subdivision":"Central Heights","style":"Ranch","bed":3,"bath":2,"gla":1720,"site":"7,800 SF","yr":2003,"cond":"C3","qual":"Q4","garage":"2-car attached","bsmt":"None","pool":"None"}}'::jsonb
FROM ins,
  module_sections ms
  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- Scenario 5.7: Yellow Book — Partial Acquisition, Agricultural Strip
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 7, 'advanced', 'Yellow Book — Partial Acquisition, Agricultural Strip', 'The Army Corps of Engineers retained you under the Uniform Appraisal Standards for Federal Land Acquisitions (Yellow Book) to appraise a residential property from which a 0.50-acre strip is being acquired for a flood control levee easement. You must establish the ''before'' fee simple value of the whole property. Yellow Book standards impose stricter requirements than USPAP alone: extraordinary care in comparable verification, explicit rejection of project-influenced sales, and extended search if necessary.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 5
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'Yellow Book standards add two requirements above USPAP: (1) extraordinary verification of arm''s length and (2) mandatory exclusion of project-influenced sales. C1, C2, C3 are all outside the levee influence zone, arm''s length, and within 3 months of the take date ($498k–$525k). C4 and C5 — the defining lesson: even though they are the closest and most physically similar sales, Yellow Book mandates their exclusion because they are within the levee influence corridor. Extended search distances (1.8–3.1 mi) are not a weakness — they are the correct response when nearby comps are contaminated by project influence. C6 — too far downstream with potential market differences. C7 acceptable as secondary outside-influence support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — rural residential, comparable acreage, outside levee influence, 3 mo. before take date, arm''s length. Yellow Book allows extended search in rural markets.","C2":"Strong comp — rural, comparable acreage, outside influence area, 1 mo. after take with no change, arm''s length. GLA and acreage adjustments needed. 3.1 mi acceptable under Yellow Book for rural markets with limited sales.","C3":"Good comp — rural, outside influence, 1 mo. before take, arm''s length. Slightly less acreage (5.0 ac.) requires site adj. Near-identical GLA.","C4":"Reject — within the levee project influence corridor. Yellow Book is explicit: sales influenced by project announcement (price depression from levee proximity/easement concerns) must be excluded. Despite being the most proximate and physically similar sale, project influence disqualifies it. Yellow Book''s higher standard makes this rejection mandatory.","C5":"Reject — within levee influence corridor, price likely depressed by easement corridor announcement. Yellow Book standard requires exclusion regardless of how well it matches physically.","C6":"Reject — 5.8 miles downstream; while physically similar and outside the influence zone, Yellow Book guidance suggests that river-corridor rural properties can have different market characteristics at this distance due to flood stage, access, and amenity differences.","C7":"Acceptable — rural, outside levee influence zone, 2 mo. before take, arm''s length. 2.0 mi acceptable for rural market. C1–C3 more directly comparable; confirms the pre-take fee simple range."},"justification":"Yellow Book standards add two requirements above USPAP: (1) extraordinary verification of arm''s length and (2) mandatory exclusion of project-influenced sales. C1, C2, C3 are all outside the levee influence zone, arm''s length, and within 3 months of the take date ($498k–$525k). C4 and C5 — the defining lesson: even though they are the closest and most physically similar sales, Yellow Book mandates their exclusion because they are within the levee influence corridor. Extended search distances (1.8–3.1 mi) are not a weakness — they are the correct response when nearby comps are contaminated by project influence. C6 — too far downstream with potential market differences. C7 acceptable as secondary outside-influence support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"5214 River Lane","prox":"1.8 mi","sub":"Rural residential","price":512000,"date":"15 months ago","style":"Ranch","bed":3,"bath":2,"gla":2060,"site":"5.2 acres","yr":2004,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car detached","txn":"Arm''s length — deed/MLS verified, outside levee influence area","warn":false},{"id":"C2","addr":"11042 County Road 18","prox":"3.1 mi","sub":"Rural residential","price":525000,"date":"11 months ago","style":"Ranch","bed":3,"bath":2,"gla":2180,"site":"5.8 acres","yr":2006,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car detached","txn":"Arm''s length — deed/MLS verified, outside levee influence","warn":false},{"id":"C3","addr":"2871 River Road","prox":"2.4 mi","sub":"Rural residential","price":498000,"date":"13 months ago","style":"Ranch","bed":3,"bath":2,"gla":2090,"site":"5.0 acres","yr":2004,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car detached","txn":"Arm''s length — deed/MLS verified, outside levee influence","warn":false},{"id":"C4","addr":"9200 River Road","prox":"0.4 mi","sub":"Rural — within levee influence area","price":455000,"date":"14 months ago","style":"Ranch","bed":3,"bath":2,"gla":2080,"site":"5.3 acres","yr":2005,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car detached","txn":"Arm''s length — deed verified, within levee project corridor","warn":true},{"id":"C5","addr":"8100 River Road","prox":"0.8 mi","sub":"Rural — within levee influence","price":441000,"date":"12 months ago","style":"Ranch","bed":3,"bath":2,"gla":2095,"site":"5.4 acres","yr":2006,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car detached","txn":"Arm''s length — deed verified, within levee influence corridor","warn":true},{"id":"C6","addr":"4500 River Rd (downstream)","prox":"5.8 mi","sub":"Rural residential","price":515000,"date":"13 months ago","style":"Ranch","bed":3,"bath":2,"gla":2140,"site":"5.7 acres","yr":2005,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car detached","txn":"Arm''s length — deed verified, outside influence","warn":false},{"id":"C7","addr":"3100 River Road","prox":"2.0 mi","sub":"Rural residential","price":508000,"date":"14 months ago","style":"Ranch","bed":3,"bath":2,"gla":2070,"site":"5.1 acres","yr":2004,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car detached","txn":"Arm''s length — deed/MLS verified, outside influence","warn":false}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Outside subject market area","Different property type or style","Reflects project influence — must be excluded","Reflects post-acquisition/post-taking conditions","Reflects government-restricted value, not fee simple","Inadequate verification / data","Other"],"subject":{"address":"8842 River Road","subdivision":"Rural residential","style":"Ranch","bed":3,"bath":2,"gla":2100,"site":"5.5 acres","yr":2005,"cond":"C3","qual":"Q4","garage":"2-car detached","bsmt":"Partial","pool":"None"}}'::jsonb
