-- Scenario 5.8: Uniform Relocation Act — Replacement Housing Payment
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 8, 'advanced', 'Uniform Relocation Act — Replacement Housing Payment', 'A residential property owner is being displaced by a federally assisted highway project. Under the Uniform Relocation Act (URA), the displacing agency must provide a Replacement Housing Payment (RHP) equal to the difference between the acquisition price and the cost of a comparable replacement dwelling. You are the agency appraiser establishing the ''comparable replacement dwelling'' standard. This requires finding the least costly decent, safe, and sanitary (DSS) dwelling comparable to the acquired property in a comparable area.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 5
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'URA replacement housing comparables must meet three additional filters beyond standard appraisal requirements: (1) Decent, Safe, and Sanitary condition, (2) comparable area (same school district/neighborhood services), and (3) least costly comparable — the RHP standard prevents overpayment at public expense. C1 ($298k, DSS, comparable area), C2 ($305k), and C3 ($291k adjusted) meet all three. C4 — different school district fails the comparable-area standard. C5 — C4 condition fails the DSS habitability standard. C6 — subsidized HUD sale is not available to general buyers. C7 — 4BR/3BA upgraded; URA requires the least costly comparable, not an upgrade. Recommending C7 would overstate the RHP at taxpayer expense.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"reject"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best replacement comp — meets DSS standards, comparable area, 2 mo. ago. As the least costly comparable DSS dwelling in this group, it establishes the URA RHP baseline.","C2":"Strong replacement comp — DSS comparable, slightly larger GLA (+30 SF). Arms length 3 mo. ago. Slightly above minimum comparable cost.","C3":"Good replacement comp — DSS comparable, slightly smaller GLA (−35 SF), concession adj needed. Arm''s length 4 mo. ago.","C4":"Reject — Riverside is a different school district and municipality from the subject''s Central District. URA requires replacement housing in a ''comparable area'' — same or comparable neighborhood services, school access, and amenities. Displacing an owner to a different district may not satisfy the comparable-area standard.","C5":"Reject — C4 condition does not meet URA Decent, Safe, and Sanitary (DSS) standards. URA requires replacement housing to be DSS; a C4 property with deferred maintenance fails the habitability standard regardless of price.","C6":"Reject — sold under an HUD Section 8 program at a subsidized price. URA replacement housing must be available to the displacee at market price; a government-subsidized sale is not available to general public purchasers and cannot establish the replacement cost.","C7":"Reject — 4BR/3BA, 1,820 SF, C2 condition. Under URA, the RHP is based on the least costly ''comparable'' replacement — not the most favorable. This upgraded property exceeds what the URA requires and would generate an unnecessarily high replacement housing payment at taxpayer expense."},"justification":"URA replacement housing comparables must meet three additional filters beyond standard appraisal requirements: (1) Decent, Safe, and Sanitary condition, (2) comparable area (same school district/neighborhood services), and (3) least costly comparable — the RHP standard prevents overpayment at public expense. C1 ($298k, DSS, comparable area), C2 ($305k), and C3 ($291k adjusted) meet all three. C4 — different school district fails the comparable-area standard. C5 — C4 condition fails the DSS habitability standard. C6 — subsidized HUD sale is not available to general buyers. C7 — 4BR/3BA upgraded; URA requires the least costly comparable, not an upgrade. Recommending C7 would overstate the RHP at taxpayer expense."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"821 Freedom Drive","prox":"0.7 mi","sub":"Freedom Park","price":298000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1455,"site":"5,600 SF","yr":1997,"cond":"C3","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C2","addr":"412 Heritage Boulevard","prox":"0.8 mi","sub":"Heritage Heights","price":305000,"date":"3 months ago","style":"Ranch","bed":3,"bath":2,"gla":1510,"site":"6,000 SF","yr":1999,"cond":"C3","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C3","addr":"109 Liberty Lane","prox":"0.6 mi","sub":"Liberty Heights","price":291000,"date":"4 months ago","style":"Ranch","bed":3,"bath":2,"gla":1445,"site":"5,700 SF","yr":1996,"cond":"C3","qual":"Q4","conc":"$2,000 seller paid","gar":"1-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"510 Riverside Road","prox":"2.5 mi","sub":"Riverside (different school district)","price":281000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1460,"site":"5,800 SF","yr":1998,"cond":"C3","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C5","addr":"88 Heritage Court","prox":"0.7 mi","sub":"Heritage Heights","price":245000,"date":"3 months ago","style":"Ranch","bed":3,"bath":2,"gla":1450,"site":"5,700 SF","yr":1996,"cond":"C4","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C6","addr":"312 Congress Boulevard","prox":"0.5 mi","sub":"Central District","price":258000,"date":"3 months ago","style":"Ranch","bed":3,"bath":2,"gla":1465,"site":"5,900 SF","yr":1997,"cond":"C3","qual":"Q4","conc":"None","gar":"1-car attached","txn":"HUD Section 8 subsidized sale","warn":true},{"id":"C7","addr":"618 Freedom Way","prox":"0.8 mi","sub":"Freedom Park","price":312000,"date":"2 months ago","style":"Ranch","bed":4,"bath":3,"gla":1820,"site":"6,500 SF","yr":2000,"cond":"C2","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Outside subject market area","Different property type or style","Reflects project influence — must be excluded","Reflects post-acquisition/post-taking conditions","Reflects government-restricted value, not fee simple","Inadequate verification / data","Other"],"subject":{"address":"714 Congress Street","subdivision":"Central District","style":"Ranch","bed":3,"bath":2,"gla":1480,"site":"5,800 SF","yr":1998,"cond":"C3","qual":"Q4","garage":"1-car attached","bsmt":"None","pool":"None"}}'::jsonb
FROM ins,
  module_sections ms
  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- Scenario 5.9: Community Development Block Grant — Affordable Housing Acquisition
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 9, 'advanced', 'Community Development Block Grant — Affordable Housing Acquisition', 'A local government using CDBG funds (HUD Community Development Block Grant) is acquiring residential properties for an affordable housing land assembly project. You must establish fee simple market value for each acquisition. HUD regulations require that CDBG acquisitions use appraisals meeting USPAP and URA standards. The subject is currently occupied by a tenant under a below-market rent agreement with the city''s housing authority. The appraisal must reflect fee simple unencumbered value, not the encumbered leased-fee value.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 5
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'CDBG/HUD acquisitions require fee simple unencumbered market value under USPAP/URA. C1, C2, C3 are unencumbered arm''s length owner-occupant sales ($244k–$254k). This fee simple range is significantly above the encumbered leased-fee value of the subject, which is exactly the point. C4 — another CDBG acquisition in the same land assembly; government-project acquisition prices cannot establish the independent FMV for the same project. C5 — sold with a below-market city housing authority lease; the same type of encumbrance as the subject. C6 — 22 months old. C7 acceptable as secondary unencumbered support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, owner-occupant (fee simple), 2 mo. ago, arm''s length. Directly reflects unencumbered fee simple market value.","C2":"Strong comp — adjacent sub, fee simple arm''s length 3 mo. ago. Minor GLA adj (+35 SF).","C3":"Good comp — same sub, 5 mo., arm''s length. Seller concession adj required.","C4":"Reject — another CDBG government acquisition in the same land assembly project. Government acquisition prices may reflect negotiated or condemnation-award pricing, project influence, or public-benefit discount. Using government-to-government or project-influenced acquisition prices in the same program is circular and violates URA requirements.","C5":"Reject — sold encumbered by a below-market city housing authority lease. The lease encumbrance discounts the price below fee simple value. HUD/CDBG requires fee simple unencumbered appraisals; the encumbered sale reflects the same type of restriction as the subject property.","C6":"Reject — 22 months old; outside the 12-month guideline. HUD/CDBG acquisitions require current market evidence.","C7":"Acceptable — fee simple arm''s length 4 mo. ago, adjacent sub. Minor GLA adj. C1–C3 more directly comparable but confirms the unencumbered fee simple range."},"justification":"CDBG/HUD acquisitions require fee simple unencumbered market value under USPAP/URA. C1, C2, C3 are unencumbered arm''s length owner-occupant sales ($244k–$254k). This fee simple range is significantly above the encumbered leased-fee value of the subject, which is exactly the point. C4 — another CDBG acquisition in the same land assembly; government-project acquisition prices cannot establish the independent FMV for the same project. C5 — sold with a below-market city housing authority lease; the same type of encumbrance as the subject. C6 — 22 months old. C7 acceptable as secondary unencumbered support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"512 Elm Court","prox":"0.4 mi","sub":"Westside District","price":248000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1315,"site":"5,300 SF","yr":1984,"cond":"C3","qual":"Q3","conc":"None","gar":"1-car attached","txn":"Arm''s length — owner-occupant MLS sale","warn":false},{"id":"C2","addr":"821 Westside Drive","prox":"0.7 mi","sub":"Westside Estates","price":254000,"date":"3 months ago","style":"Ranch","bed":3,"bath":2,"gla":1375,"site":"5,700 SF","yr":1986,"cond":"C3","qual":"Q3","conc":"None","gar":"1-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C3","addr":"218 Elm Lane","prox":"0.5 mi","sub":"Westside District","price":244000,"date":"5 months ago","style":"Ranch","bed":3,"bath":2,"gla":1325,"site":"5,400 SF","yr":1985,"cond":"C3","qual":"Q3","conc":"$1,500 seller paid","gar":"1-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"714 Elm Blvd","prox":"0.5 mi","sub":"Westside District","price":198000,"date":"3 months ago","style":"Ranch","bed":3,"bath":2,"gla":1330,"site":"5,200 SF","yr":1984,"cond":"C3","qual":"Q3","conc":"None","gar":"1-car attached","txn":"CDBG acquisition — government purchase for land assembly","warn":true},{"id":"C5","addr":"88 Westside Court","prox":"0.6 mi","sub":"Westside Estates","price":211000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1345,"site":"5,400 SF","yr":1985,"cond":"C3","qual":"Q3","conc":"None","gar":"1-car attached","txn":"Sold subject to below-market city housing authority lease","warn":true},{"id":"C6","addr":"312 Elm Way","prox":"0.5 mi","sub":"Westside District","price":238000,"date":"22 months ago","style":"Ranch","bed":3,"bath":2,"gla":1320,"site":"5,200 SF","yr":1984,"cond":"C3","qual":"Q3","conc":"None","gar":"1-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C7","addr":"618 Westside Way","prox":"0.8 mi","sub":"Westside Estates","price":251000,"date":"4 months ago","style":"Ranch","bed":3,"bath":2,"gla":1360,"site":"5,600 SF","yr":1986,"cond":"C3","qual":"Q3","conc":"None","gar":"1-car attached","txn":"Arm''s length — MLS","warn":false}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Outside subject market area","Different property type or style","Reflects project influence — must be excluded","Reflects post-acquisition/post-taking conditions","Reflects government-restricted value, not fee simple","Inadequate verification / data","Other"],"subject":{"address":"1128 Elm Avenue","subdivision":"Westside District","style":"Ranch","bed":3,"bath":2,"gla":1340,"site":"5,500 SF","yr":1985,"cond":"C3","qual":"Q3","garage":"1-car attached","bsmt":"None","pool":"None"}}'::jsonb
