-- Scenario 5.10: Federal Land Exchange — Residential Parcel
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 10, 'advanced', 'Federal Land Exchange — Residential Parcel', 'The U.S. Forest Service is exchanging a federally-owned residential lot for a privately-owned residential lot of comparable value as part of a land consolidation. Under the Federal Land Policy and Management Act (FLPMA) and Yellow Book standards, both parcels must be appraised at fair market value. You are appraising the federal lot to be transferred to private ownership. Yellow Book requires extraordinary rigor, documentation, and exclusion of all project-influenced or related-party sales.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 5
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'Federal land exchanges under FLPMA require Yellow Book standards: extraordinary verification and exclusion of any exchange-related or federally-connected transactions. C1, C2, C3 are all independent arm''s length sales with no federal connection, within 3 months of the effective date ($409k–$425k). C4 — prior exchange transaction; FLPMA prohibits using exchange prices to value current exchange parcels. C5 — sold to a Forest Service contractor; Yellow Book''s related-party exclusion captures indirect federal relationships. C6 — 6.5 miles, non-competing mountain community. C7 — 35 months old. The Yellow Book appraiser must search further geographically rather than compromise the independence standard.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"reject"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same enclave, no federal involvement, 2 mo. before take, arm''s length. Near-identical acreage. Confirmed independent transaction with no land exchange connection.","C2":"Strong comp — adjacent enclave, no federal involvement, 1 mo. after effective date, arm''s length. GLA and acreage adj needed. 2.1 mi acceptable for rural enclave market.","C3":"Good comp — same enclave, no federal involvement, 1 mo. before effective date, arm''s length. Near-identical GLA and similar acreage.","C4":"Reject — sold as part of a prior federal land exchange transaction. Under FLPMA and Yellow Book, prices from related or prior exchange transactions cannot be used to value the current exchange parcel. The exchange pricing may reflect negotiated program values rather than open market conditions.","C5":"Reject — sold to a contractor who regularly performs work for the Forest Service. Yellow Book requires exclusion of related-party transactions; even indirect relationships with the federal agency or its contractors constitute a conflict.","C6":"Reject — 6.5 miles away in Pine Ridge Estates, a different mountain community with different access, amenity, and proximity characteristics. Buyers for Timber Ridge properties would not consider Pine Ridge a competing alternative location.","C7":"Reject — 35 months old; outside the 12-month guideline. Even under Yellow Book''s flexibility for limited-market properties, a 35-month sale requires a speculative time adjustment when more recent comps are available."},"justification":"Federal land exchanges under FLPMA require Yellow Book standards: extraordinary verification and exclusion of any exchange-related or federally-connected transactions. C1, C2, C3 are all independent arm''s length sales with no federal connection, within 3 months of the effective date ($409k–$425k). C4 — prior exchange transaction; FLPMA prohibits using exchange prices to value current exchange parcels. C5 — sold to a Forest Service contractor; Yellow Book''s related-party exclusion captures indirect federal relationships. C6 — 6.5 miles, non-competing mountain community. C7 — 35 months old. The Yellow Book appraiser must search further geographically rather than compromise the independence standard."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"5214 Forest Road 18","prox":"1.4 mi","sub":"Timber Ridge","price":418000,"date":"14 months ago","style":"Ranch","bed":3,"bath":2,"gla":1910,"site":"2.1 acres","yr":2007,"cond":"C2","qual":"Q4","conc":"None","gar":"2-car detached","txn":"Arm''s length — deed/MLS, no federal involvement","warn":false},{"id":"C2","addr":"8821 Ridgeline Road","prox":"2.1 mi","sub":"Ridgeline Enclave","price":425000,"date":"11 months ago","style":"Ranch","bed":3,"bath":2,"gla":2020,"site":"2.3 acres","yr":2009,"cond":"C2","qual":"Q4","conc":"None","gar":"2-car detached","txn":"Arm''s length — deed/MLS, no federal involvement","warn":false},{"id":"C3","addr":"3105 Forest Road 22","prox":"1.8 mi","sub":"Timber Ridge","price":409000,"date":"13 months ago","style":"Ranch","bed":3,"bath":2,"gla":1965,"site":"1.9 acres","yr":2007,"cond":"C2","qual":"Q4","conc":"None","gar":"2-car detached","txn":"Arm''s length — deed/MLS, no federal involvement","warn":false},{"id":"C4","addr":"6240 Forest Road 22","prox":"0.6 mi","sub":"Timber Ridge","price":388000,"date":"12 months ago","style":"Ranch","bed":3,"bath":2,"gla":1940,"site":"2.0 acres","yr":2008,"cond":"C2","qual":"Q4","conc":"None","gar":"2-car detached","txn":"Sold as part of federal land exchange — related transaction","warn":true},{"id":"C5","addr":"2180 Timber Road","prox":"1.1 mi","sub":"Timber Ridge","price":395000,"date":"12 months ago","style":"Ranch","bed":3,"bath":2,"gla":1930,"site":"1.8 acres","yr":2007,"cond":"C2","qual":"Q4","conc":"None","gar":"2-car detached","txn":"Sold to forest service contractor — related party","warn":true},{"id":"C6","addr":"9100 Pine Ridge Road","prox":"6.5 mi","sub":"Pine Ridge Estates","price":421000,"date":"14 months ago","style":"Ranch","bed":3,"bath":2,"gla":1975,"site":"2.2 acres","yr":2008,"cond":"C2","qual":"Q4","conc":"None","gar":"2-car detached","txn":"Arm''s length — deed/MLS, no federal involvement","warn":false},{"id":"C7","addr":"7441 Ridgeline Court","prox":"2.5 mi","sub":"Ridgeline Enclave","price":414000,"date":"35 months ago","style":"Ranch","bed":3,"bath":2,"gla":1990,"site":"2.0 acres","yr":2008,"cond":"C2","qual":"Q4","conc":"None","gar":"2-car detached","txn":"Arm''s length — deed/MLS, no federal involvement","warn":false}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Outside subject market area","Different property type or style","Reflects project influence — must be excluded","Reflects post-acquisition/post-taking conditions","Reflects government-restricted value, not fee simple","Inadequate verification / data","Other"],"subject":{"address":"4821 Forest Service Road 22","subdivision":"Timber Ridge (residential enclave)","style":"Ranch","bed":3,"bath":2,"gla":1950,"site":"2.0 acres","yr":2008,"cond":"C2","qual":"Q4","garage":"2-car detached","bsmt":"Partial","pool":"None"}}'::jsonb
FROM ins,
  module_sections ms
  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- ─────────────── Category 6: Specialty Situations ───────────────
-- Scenario 6.1: Manufactured Home on Owned Land
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 1, 'basic', 'Manufactured Home on Owned Land', 'First National Bank engaged you to appraise a manufactured home on a permanent foundation with owned land for a conventional chattel-free mortgage. Contract price: $218,000. The scope requires a 1004/URAR with full inspection and the Manufactured Home Appraisal Report addendum. Per Fannie Mae guidelines, comparables must be other manufactured homes — site-built homes are never appropriate comps regardless of price similarity.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 6
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'Fannie Mae guidelines require manufactured home comparables on owned land. C1, C2, C3 are all manufactured homes on owned land in the same or adjacent market ($205k–$214k). C4 — site-built home; the most common mistake in manufactured home appraisals. Regardless of similar GLA and price, site-built and manufactured homes are different markets with different buyers, financing, and resale characteristics. C5 — manufactured on a leased lot; the $60k–$80k gap to owned-land comps demonstrates the ownership-structure difference. C6 — 22 months old. C7 acceptable as secondary manufactured/owned-land support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, manufactured home on owned land, 3 mo. ago, arm''s length. 30 SF less GLA. Directly reflects the manufactured home market segment.","C2":"Strong comp — adjacent area, manufactured on owned land, most recent (2 mo.), arm''s length. Minor GLA and site adj.","C3":"Good comp — same sub, manufactured on owned land, 5 mo. ago, arm''s length. Seller concession adj required.","C4":"Reject — site-built home. Fannie Mae guidelines are unambiguous: manufactured home appraisals require manufactured home comparables. Site-built homes reflect a different construction method, buyer pool, financing options, and resale market. They cannot be used regardless of price similarity.","C5":"Reject — manufactured home on a leased lot (land-lease community). The subject has owned land; a leased-lot manufactured home has a fundamentally different ownership structure, financing availability, and market value. The lot lease obligation depresses value by approximately $60k–$80k vs the owned-land market.","C6":"Reject — 22 months old; outside the 12-month guideline. Manufactured home values can shift more quickly than site-built; a stale comp understates the current market.","C7":"Acceptable — manufactured on owned land, arm''s length 4 mo. ago. Farther at 1.3 mi; C1–C3 are more comparable but this confirms the manufactured home owned-land value range."},"justification":"Fannie Mae guidelines require manufactured home comparables on owned land. C1, C2, C3 are all manufactured homes on owned land in the same or adjacent market ($205k–$214k). C4 — site-built home; the most common mistake in manufactured home appraisals. Regardless of similar GLA and price, site-built and manufactured homes are different markets with different buyers, financing, and resale characteristics. C5 — manufactured on a leased lot; the $60k–$80k gap to owned-land comps demonstrates the ownership-structure difference. C6 — 22 months old. C7 acceptable as secondary manufactured/owned-land support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"2814 Pinecrest Court","prox":"0.4 mi","sub":"Pinecrest Estates","price":208000,"date":"3 months ago","style":"Manufactured — Ranch","bed":3,"bath":2,"gla":1590,"site":"0.42 acres","yr":2011,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS, mfg. on owned land","warn":false},{"id":"C2","addr":"8821 Valley Road","prox":"0.9 mi","sub":"Valley Estates","price":214000,"date":"2 months ago","style":"Manufactured — Ranch","bed":3,"bath":2,"gla":1660,"site":"0.50 acres","yr":2013,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS, mfg. on owned land","warn":false},{"id":"C3","addr":"3105 Pinecrest Lane","prox":"0.6 mi","sub":"Pinecrest Estates","price":205000,"date":"5 months ago","style":"Manufactured — Ranch","bed":3,"bath":2,"gla":1605,"site":"0.44 acres","yr":2010,"cond":"C3","qual":"Q4","conc":"$2,000 seller paid","gar":"2-car attached","txn":"Arm''s length — MLS, mfg. on owned land","warn":false},{"id":"C4","addr":"512 Elmwood Drive","prox":"0.7 mi","sub":"Elmwood Heights","price":218000,"date":"2 months ago","style":"Ranch (site-built)","bed":3,"bath":2,"gla":1580,"site":"0.40 acres","yr":2005,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C5","addr":"9200 Valley Court","prox":"1.1 mi","sub":"Valley Mobile Park","price":142000,"date":"3 months ago","style":"Manufactured — Ranch","bed":3,"bath":2,"gla":1550,"site":"Leased lot","yr":2010,"cond":"C3","qual":"Q4","conc":"None","gar":"None","txn":"Arm''s length — MLS, mfg. on LEASED lot","warn":true},{"id":"C6","addr":"4140 Pinecrest Blvd","prox":"0.5 mi","sub":"Pinecrest Estates","price":188000,"date":"22 months ago","style":"Manufactured — Ranch","bed":3,"bath":2,"gla":1600,"site":"0.43 acres","yr":2009,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS, mfg. on owned land","warn":false},{"id":"C7","addr":"7441 Ridge Road","prox":"1.3 mi","sub":"Ridge Estates","price":211000,"date":"4 months ago","style":"Manufactured — Ranch","bed":3,"bath":2,"gla":1640,"site":"0.48 acres","yr":2012,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS, mfg. on owned land","warn":false}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Different property type or construction","Different ownership structure / interest","Outside subject market area","Reflects different buyer pool / age restriction","Reflects encumbered or restricted-use value","Inadequate verification / data","Other"],"subject":{"address":"4821 Pinecrest Drive","subdivision":"Pinecrest Estates","style":"Manufactured — Ranch","bed":3,"bath":2,"gla":1620,"site":"0.45 acres","yr":2012,"cond":"C3","qual":"Q4","garage":"2-car attached","bsmt":"None","pool":"None"}}'::jsonb
FROM ins,
  module_sections ms
  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- Scenario 6.2: Age-Restricted 55+ Community
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 2, 'basic', 'Age-Restricted 55+ Community', 'American Mortgage engaged you to appraise a home in a 55+ age-restricted community for a purchase loan. Contract price: $312,000. Fannie Mae guidelines require that comparables be primarily from the same 55+ community or from similar age-restricted communities. Sales from non-restricted neighborhoods are generally not appropriate because the 55+ restriction creates a distinct buyer pool.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 6
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'Fannie Mae guidelines prioritize 55+ community comps. C1 (same community, 2 mo.), C2 (adjacent 55+ community, 3 mo.), and C3 (same community, 5 mo.) all reflect the age-restricted buyer pool ($298k–$308k). C4 and C5 — unrestricted neighborhood sales. The typically higher unrestricted prices demonstrate that the 55+ restriction narrows the buyer pool and generally constrains value; using them would overstate the restricted-community value. C6 — 21 months old. C7 acceptable as secondary 55+ support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same 55+ community, 2 mo. ago, arm''s length. 25 SF less GLA. Directly reflects the age-restricted buyer pool and community amenities.","C2":"Strong comp — adjacent 55+ community, 3 mo. ago, arm''s length. Minor GLA adj. 55+ restriction creates a comparable buyer pool.","C3":"Good comp — same 55+ community, 5 mo. ago, arm''s length. Seller concession adj required.","C4":"Reject — unrestricted neighborhood with no age requirement. The 55+ restriction creates a different buyer pool (only 55+ qualified purchasers), different community amenities, and different HOA structures. Non-restricted comps typically price higher due to the broader buyer pool; using them would overstate the age-restricted value.","C5":"Reject — unrestricted neighborhood. Fannie Mae guidelines are specific: 55+ community appraisals should use age-restricted comps. The narrower buyer pool in a 55+ community generally constrains value relative to unrestricted comparable properties.","C6":"Reject — 21 months old; outside the 12-month guideline for a current market value opinion.","C7":"Acceptable — adjacent 55+ community, arm''s length 4 mo. ago. Slightly farther; C1–C3 more directly comparable but confirms the age-restricted value range."},"justification":"Fannie Mae guidelines prioritize 55+ community comps. C1 (same community, 2 mo.), C2 (adjacent 55+ community, 3 mo.), and C3 (same community, 5 mo.) all reflect the age-restricted buyer pool ($298k–$308k). C4 and C5 — unrestricted neighborhood sales. The typically higher unrestricted prices demonstrate that the 55+ restriction narrows the buyer pool and generally constrains value; using them would overstate the restricted-community value. C6 — 21 months old. C7 acceptable as secondary 55+ support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"814 Heritage Village Court","prox":"0.3 mi","sub":"Heritage Village (55+)","price":302000,"date":"2 months ago","style":"Ranch","bed":2,"bath":2,"gla":1455,"site":"5,300 SF","yr":2009,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS, 55+ community","warn":false},{"id":"C2","addr":"421 Sunrise Estates Dr","prox":"1.2 mi","sub":"Sunrise Estates (55+)","price":308000,"date":"3 months ago","style":"Ranch","bed":2,"bath":2,"gla":1510,"site":"5,700 SF","yr":2011,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS, 55+ community","warn":false},{"id":"C3","addr":"109 Heritage Village Lane","prox":"0.5 mi","sub":"Heritage Village (55+)","price":298000,"date":"5 months ago","style":"Ranch","bed":2,"bath":2,"gla":1465,"site":"5,400 SF","yr":2009,"cond":"C3","qual":"Q4","conc":"$2,500 seller paid","gar":"2-car attached","txn":"Arm''s length — MLS, 55+ community","warn":false},{"id":"C4","addr":"712 Clearfield Drive","prox":"0.8 mi","sub":"Clearfield Estates (unrestricted)","price":318000,"date":"2 months ago","style":"Ranch","bed":2,"bath":2,"gla":1490,"site":"5,600 SF","yr":2010,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C5","addr":"88 Ridgemont Way","prox":"0.9 mi","sub":"Ridgemont Park (unrestricted)","price":325000,"date":"1 month ago","style":"Ranch","bed":2,"bath":2,"gla":1475,"site":"5,500 SF","yr":2011,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C6","addr":"412 Heritage Village Blvd","prox":"0.4 mi","sub":"Heritage Village (55+)","price":289000,"date":"21 months ago","style":"Ranch","bed":2,"bath":2,"gla":1470,"site":"5,300 SF","yr":2009,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS, 55+ community","warn":false},{"id":"C7","addr":"618 Sunrise Court","prox":"1.3 mi","sub":"Sunrise Estates (55+)","price":304000,"date":"4 months ago","style":"Ranch","bed":2,"bath":2,"gla":1495,"site":"5,600 SF","yr":2010,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS, 55+ community","warn":false}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Different property type or construction","Different ownership structure / interest","Outside subject market area","Reflects different buyer pool / age restriction","Reflects encumbered or restricted-use value","Inadequate verification / data","Other"],"subject":{"address":"2417 Heritage Village Drive","subdivision":"Heritage Village (55+ community)","style":"Ranch","bed":2,"bath":2,"gla":1480,"site":"5,500 SF","yr":2010,"cond":"C3","qual":"Q4","garage":"2-car attached","bsmt":"None","pool":"Community pool"}}'::jsonb
FROM ins,
  module_sections ms
  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- Scenario 6.3: Short-Term Rental Property — Market Value Basis
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 3, 'intermediate', 'Short-Term Rental Property — Market Value Basis', 'Coastal Lending engaged you to appraise a single-family home operating as a licensed Airbnb/VRBO short-term rental (STR) for a refinance. The owners report STR gross revenue of $72,000/year. However, for a Fannie Mae conforming loan, the appraisal must reflect the property''s market value as a single-family residence — not as an income-producing investment. Comparables should be residential sales, not investment-basis transactions.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 6
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'For a Fannie Mae conforming loan, the value standard is residential market value — what an owner-occupant would pay, not what an STR investor would capitalize. C1, C2, C3 are owner-occupant or residential-basis arm''s length sales ($535k–$558k). C4 and C5 — the critical rejections: STR income-basis investor purchases priced at $695k–$712k, reflecting capitalized revenue far above residential value. Using them would inflate the appraisal by ~$140k–$160k and misstate the residential market value standard required for the conforming loan. C6 — 22 months old. C7 acceptable as secondary residential support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, C2 condition, pool, owner-occupant sale (residential market), 2 mo. ago. Reflects fee simple residential market value, not STR investment value.","C2":"Strong comp — adjacent sub, C2 condition, pool, most recent (1 mo.), arm''s length. Minor GLA and site adj. Reflects residential buyer motivation.","C3":"Good comp — same sub, pool, 4 mo. ago, arm''s length. Seller concession adj required.","C4":"Reject — purchased by an investor on an STR income basis with STR revenue disclosed. The $695k price reflects capitalized STR income, not residential owner-occupant market value. Fannie Mae conforming loans require residential market value; income-basis investor transactions overstate the residential value.","C5":"Reject — another investor STR acquisition priced on income capitalization. Using STR income-basis sales to establish residential market value inflates the conforming loan appraisal and misrepresents the value standard required by Fannie Mae.","C6":"Reject — 22 months old; outside the 12-month guideline for a current market value opinion.","C7":"Acceptable — owner-occupant residential sale, C2 condition, pool, arm''s length. Farther at 0.9 mi; C1–C3 more directly comparable but confirms the residential value range."},"justification":"For a Fannie Mae conforming loan, the value standard is residential market value — what an owner-occupant would pay, not what an STR investor would capitalize. C1, C2, C3 are owner-occupant or residential-basis arm''s length sales ($535k–$558k). C4 and C5 — the critical rejections: STR income-basis investor purchases priced at $695k–$712k, reflecting capitalized revenue far above residential value. Using them would inflate the appraisal by ~$140k–$160k and misstate the residential market value standard required for the conforming loan. C6 — 22 months old. C7 acceptable as secondary residential support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"512 Beachview Court","prox":"0.4 mi","sub":"Beachview Heights","price":548000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1650,"site":"0.24 acres","yr":2007,"cond":"C2","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — owner-occupant MLS","warn":false},{"id":"C2","addr":"821 Coastal Drive","prox":"0.7 mi","sub":"Coastal Estates","price":558000,"date":"1 month ago","style":"Ranch","bed":3,"bath":2,"gla":1720,"site":"0.27 acres","yr":2009,"cond":"C2","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C3","addr":"108 Beachview Lane","prox":"0.5 mi","sub":"Beachview Heights","price":535000,"date":"4 months ago","style":"Ranch","bed":3,"bath":2,"gla":1660,"site":"0.25 acres","yr":2008,"cond":"C2","qual":"Q4","conc":"$5,000 seller paid","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"714 Beachview Blvd","prox":"0.5 mi","sub":"Beachview Heights","price":695000,"date":"3 months ago","style":"Ranch","bed":3,"bath":2,"gla":1690,"site":"0.26 acres","yr":2009,"cond":"C2","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Investor purchase — STR basis (STR revenue $84k/yr disclosed in MLS)","warn":true},{"id":"C5","addr":"88 Coastal Court","prox":"0.8 mi","sub":"Coastal Estates","price":712000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1700,"site":"0.28 acres","yr":2008,"cond":"C2","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Investor purchase — STR income basis noted in deed transfer docs","warn":true},{"id":"C6","addr":"312 Beachview Way","prox":"0.4 mi","sub":"Beachview Heights","price":529000,"date":"22 months ago","style":"Ranch","bed":3,"bath":2,"gla":1670,"site":"0.25 acres","yr":2007,"cond":"C2","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C7","addr":"618 Coastal Way","prox":"0.9 mi","sub":"Coastal Estates","price":541000,"date":"5 months ago","style":"Ranch","bed":3,"bath":2,"gla":1705,"site":"0.27 acres","yr":2008,"cond":"C2","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — owner-occupant MLS","warn":false}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Different property type or construction","Different ownership structure / interest","Outside subject market area","Reflects different buyer pool / age restriction","Reflects encumbered or restricted-use value","Inadequate verification / data","Other"],"subject":{"address":"1128 Beachview Drive","subdivision":"Beachview Heights","style":"Ranch","bed":3,"bath":2,"gla":1680,"site":"0.25 acres","yr":2008,"cond":"C2","qual":"Q4","garage":"2-car attached","bsmt":"None","pool":"Pool"}}'::jsonb
FROM ins,
  module_sections ms
  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- Scenario 6.4: Property with Leased Solar Panels
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 4, 'intermediate', 'Property with Leased Solar Panels', 'Tri-County Credit Union engaged you for a purchase appraisal. The subject has a rooftop solar array under a 20-year lease agreement (not owned). The lease transfers with the property and obligates the buyer to a $215/month payment for the remaining 14 years. The leased solar system does NOT add value — it is a liability. Comps should ideally be properties with owned solar (to extract the owned-solar premium) or properties with no solar (as the baseline), but NOT properties with other leased solar systems.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 6
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'For a leased-solar property, the correct strategy is to establish the no-solar baseline, then adjust downward for the lease liability. C1 and C2 (no solar) establish the baseline; C3 (owned solar) provides a paired-sale to extract the owned-solar premium (the opposite of the subject''s liability). The no-solar baseline range is ~$368k–$375k; the subject''s lease liability (NPV of 14 years × $215/month at market discount rate) is then subtracted. C4 and C5 — leased-solar sales are circular: they embed an unknown market reaction to the lease liability that cannot be isolated or controlled for. C6 — 24 months old. C7 acceptable as secondary no-solar support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, no solar (baseline), 2 mo. ago, arm''s length. Establishes the no-solar market value from which any solar adjustment is made.","C2":"Strong comp — adjacent sub, no solar, 3 mo. ago, arm''s length. Minor GLA adj (+40 SF). Confirms the no-solar baseline.","C3":"Good comp — same sub, OWNED solar. Allows paired-sale analysis: if adjusted for the owned solar premium (typically $10k–$20k), this sale supports the value range as of the no-solar baseline adjusted downward for the subject''s solar lease liability.","C4":"Reject — sold with a similar leased solar system in place. The lease obligation is embedded in this sale price, but market acceptance of the lease liability varies. Using a leased-solar comp to value another leased-solar property produces a circular result; it cannot isolate whether the market penalized or ignored the lease obligation.","C5":"Reject — leased solar system (different provider). Solar lease terms vary significantly; different providers have different rates, escalators, and assumability clauses. Mixing leased-solar comps with different lease terms introduces unquantifiable variation.","C6":"Reject — 24 months old; outside the 12-month guideline. Solar market acceptance can change; a stale no-solar comp may not reflect current market conditions.","C7":"Acceptable — no solar, arm''s length 4 mo. ago. Minor GLA adj. C1–C3 provide stronger direct support but this confirms the no-solar baseline."},"justification":"For a leased-solar property, the correct strategy is to establish the no-solar baseline, then adjust downward for the lease liability. C1 and C2 (no solar) establish the baseline; C3 (owned solar) provides a paired-sale to extract the owned-solar premium (the opposite of the subject''s liability). The no-solar baseline range is ~$368k–$375k; the subject''s lease liability (NPV of 14 years × $215/month at market discount rate) is then subtracted. C4 and C5 — leased-solar sales are circular: they embed an unknown market reaction to the lease liability that cannot be isolated or controlled for. C6 — 24 months old. C7 acceptable as secondary no-solar support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"812 Sunridge Court","prox":"0.5 mi","sub":"Sunridge Estates","price":368000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1690,"site":"7,800 SF","yr":2014,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS, no solar system","warn":false},{"id":"C2","addr":"421 Clearfield Drive","prox":"0.7 mi","sub":"Clearfield Estates","price":375000,"date":"3 months ago","style":"Ranch","bed":3,"bath":2,"gla":1760,"site":"8,200 SF","yr":2015,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS, no solar","warn":false},{"id":"C3","addr":"108 Sunridge Lane","prox":"0.4 mi","sub":"Sunridge Estates","price":381000,"date":"5 months ago","style":"Ranch","bed":3,"bath":2,"gla":1730,"site":"8,100 SF","yr":2015,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS, owned solar system (5.2 kW)","warn":false},{"id":"C4","addr":"714 Sunridge Blvd","prox":"0.5 mi","sub":"Sunridge Estates","price":395000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1715,"site":"7,900 SF","yr":2016,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS, leased solar (same provider, similar lease terms)","warn":true},{"id":"C5","addr":"88 Clearfield Court","prox":"0.8 mi","sub":"Clearfield Estates","price":389000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1735,"site":"8,200 SF","yr":2015,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS, leased solar (different provider)","warn":true},{"id":"C6","addr":"312 Sunridge Way","prox":"0.4 mi","sub":"Sunridge Estates","price":362000,"date":"24 months ago","style":"Ranch","bed":3,"bath":2,"gla":1705,"site":"7,800 SF","yr":2014,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS, no solar","warn":false},{"id":"C7","addr":"618 Clearfield Way","prox":"0.9 mi","sub":"Clearfield Estates","price":372000,"date":"4 months ago","style":"Ranch","bed":3,"bath":2,"gla":1750,"site":"8,300 SF","yr":2015,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS, no solar","warn":false}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Different property type or construction","Different ownership structure / interest","Outside subject market area","Reflects different buyer pool / age restriction","Reflects encumbered or restricted-use value","Inadequate verification / data","Other"],"subject":{"address":"3214 Sunridge Drive","subdivision":"Sunridge Estates","style":"Ranch","bed":3,"bath":2,"gla":1720,"site":"8,000 SF","yr":2015,"cond":"C3","qual":"Q4","garage":"2-car attached","bsmt":"None","pool":"None"}}'::jsonb
FROM ins,
  module_sections ms
  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- Scenario 6.5: ADU (Accessory Dwelling Unit) — Residential Appraisal
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 5, 'intermediate', 'ADU (Accessory Dwelling Unit) — Residential Appraisal', 'Pacific Savings Bank engaged you to appraise a single-family residence with a permitted detached ADU (400 SF, 1BR/1BA) for a purchase loan on a 1004/URAR. The ADU is legally permitted and occupied by a paying tenant ($950/month). For a conforming residential loan on a 1-unit property with an ADU, Fannie Mae requires the appraisal to value the property as a single-family residence, acknowledging the ADU. Comparables should ideally include properties with ADUs; absent those, the ADU contribution must be analyzed and supported.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 6
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'Fannie Mae requires residential comps for a 1-unit SFR with ADU appraisal. C1 and C2 are direct ADU-to-ADU comparisons in the same and adjacent subdivisions. C3 (no ADU) is a critical paired-sale that isolates the $36k ADU contribution, providing quantitative support for the ADU adjustment. C4 — unpermitted ADU conversion; Fannie Mae requires legally permitted ADUs, and mixing permitted and unpermitted units is a compliance violation. C5 — legal duplex; different property type, ownership structure, and buyer pool. C6 — 25 months old. C7 acceptable as secondary permitted-ADU support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, identical configuration (SFR + detached ADU), 2 mo. ago, arm''s length. Directly reflects the ADU-inclusive residential market.","C2":"Strong comp — adjacent sub, permitted ADU, 3 mo. ago, arm''s length. Minor GLA and site adj. ADU configuration directly comparable.","C3":"Good comp — same sub, no ADU. Essential paired-sale: comparing to C1 isolates the ADU contribution ($498k–$462k = ~$36k premium). This supports quantifying the ADU adjustment.","C4":"Reject — unpermitted ADU conversion. Fannie Mae requires ADUs to be legally permitted; an unpermitted unit cannot be valued or relied upon in the analysis. Using it as a comp for the subject''s permitted ADU would blur the critical distinction between legal and illegal accessory units.","C5":"Reject — legal 2-unit duplex. A duplex is a different property type with separate legal units, different ownership/financing, and a different buyer pool than a single-family home with an ADU. Fannie Mae requires the 1-unit SFR classification with permitted ADU to use residential comparables.","C6":"Reject — 25 months old; outside the 12-month guideline.","C7":"Acceptable — permitted ADU, arm''s length 5 mo. ago. Slightly smaller combined GLA; C1–C3 provide stronger direct support but this confirms the permitted-ADU value range."},"justification":"Fannie Mae requires residential comps for a 1-unit SFR with ADU appraisal. C1 and C2 are direct ADU-to-ADU comparisons in the same and adjacent subdivisions. C3 (no ADU) is a critical paired-sale that isolates the $36k ADU contribution, providing quantitative support for the ADU adjustment. C4 — unpermitted ADU conversion; Fannie Mae requires legally permitted ADUs, and mixing permitted and unpermitted units is a compliance violation. C5 — legal duplex; different property type, ownership structure, and buyer pool. C6 — 25 months old. C7 acceptable as secondary permitted-ADU support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"514 Garden Court","prox":"0.4 mi","sub":"Garden Heights","price":498000,"date":"2 months ago","style":"Ranch + detached ADU","bed":"3+1","bath":"2+1","gla":"1,560 SF + 380 SF ADU","site":"7,200 SF","yr":2004,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS, permitted ADU","warn":false},{"id":"C2","addr":"821 Fernwood Drive","prox":"0.7 mi","sub":"Fernwood Estates","price":505000,"date":"3 months ago","style":"Ranch + detached ADU","bed":"3+1","bath":"2+1","gla":"1,620 SF + 420 SF ADU","site":"7,700 SF","yr":2006,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS, permitted ADU","warn":false},{"id":"C3","addr":"218 Garden Lane","prox":"0.5 mi","sub":"Garden Heights","price":462000,"date":"4 months ago","style":"Ranch (no ADU)","bed":3,"bath":2,"gla":"1,595 SF (no ADU)","site":"7,400 SF","yr":2005,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"715 Garden Blvd","prox":"0.5 mi","sub":"Garden Heights","price":488000,"date":"3 months ago","style":"Ranch + garage conversion (unpermitted ADU)","bed":"3+1","bath":"2+1","gla":"1,570 SF + 350 SF (unpermitted)","site":"7,300 SF","yr":2004,"cond":"C3","qual":"Q4","conc":"None","gar":"None","txn":"Arm''s length — MLS","warn":true},{"id":"C5","addr":"88 Fernwood Court","prox":"0.7 mi","sub":"Fernwood Estates","price":521000,"date":"2 months ago","style":"Duplex (2-unit legal)","bed":"2+2","bath":"1+1","gla":"2,100 SF (total)","site":"7,800 SF","yr":2005,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C6","addr":"312 Garden Way","prox":"0.4 mi","sub":"Garden Heights","price":478000,"date":"25 months ago","style":"Ranch + detached ADU","bed":"3+1","bath":"2+1","gla":"1,575 SF + 395 SF ADU","site":"7,300 SF","yr":2005,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS, permitted ADU","warn":false},{"id":"C7","addr":"618 Fernwood Way","prox":"0.8 mi","sub":"Fernwood Estates","price":492000,"date":"5 months ago","style":"Ranch + detached ADU","bed":"3+1","bath":"2+1","gla":"1,540 SF + 360 SF ADU","site":"7,500 SF","yr":2005,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS, permitted ADU","warn":false}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Different property type or construction","Different ownership structure / interest","Outside subject market area","Reflects different buyer pool / age restriction","Reflects encumbered or restricted-use value","Inadequate verification / data","Other"],"subject":{"address":"2841 Garden Street","subdivision":"Garden Heights","style":"Ranch + detached ADU","bed":"3+1","bath":"2+1","gla":"1,580 SF + 400 SF ADU","site":"7,500 SF","yr":2005,"cond":"C3","qual":"Q4","garage":"2-car attached","bsmt":"None","pool":"None"}}'::jsonb
FROM ins,
  module_sections ms
  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- Scenario 6.6: Flood Zone AE — High-Risk Flood Area
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 6, 'advanced', 'Flood Zone AE — High-Risk Flood Area', 'Regional Savings engaged you to appraise a home located within FEMA Flood Zone AE (high-risk, base flood elevation established). The subject has NFIP flood insurance at $3,200/year and is elevated on a stem-wall foundation to one foot above BFE. FEMA flood zone designation significantly affects marketability and buyer pool. For meaningful comparisons, comps should ideally be in the same or similar flood zone — non-flood-zone comps require major unexplainable adjustments.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 6
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'For a Zone AE elevated property, flood zone classification is a fundamental selection criterion. C1, C2, C3 are all Zone AE, elevated construction, arm''s length ($341k–$355k). Flood zone costs and market stigma are already embedded; no flood adjustment needed within the group. C4 and C5 — Zone X properties at $408k–$412k, roughly $60k above Zone AE; the flood zone difference is quantitatively significant but not reliably adjustable. C6 — Zone AE but non-elevated; lower NFIP compliance and higher future premiums make it a different sub-segment. C7 acceptable as secondary Zone AE elevated support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, Zone AE, elevated construction, 2 mo. ago, arm''s length. NFIP insurance costs and flood zone stigma are already reflected in this price; no flood adjustment needed.","C2":"Strong comp — adjacent area, Zone AE, elevated (pier foundation), 3 mo. ago, arm''s length. Minor GLA adj (+40 SF). Flood zone conditions are shared.","C3":"Good comp — same sub, Zone AE, elevated, 5 mo. ago, arm''s length. Seller concession adj required.","C4":"Reject — Zone X (no flood insurance required). The $64k premium vs comparable Zone AE properties reflects no NFIP cost, no elevated foundation premium, and no flood stigma. An adjustment for flood zone designation is qualitatively significant but extremely difficult to support quantitatively; Zone X comps are inappropriate for Zone AE properties.","C5":"Reject — Zone X non-flood property. The flood zone is a fundamental value influence; buyers, lenders, and insurers treat Zone AE and Zone X properties as distinct markets. Using Zone X comps for a Zone AE property requires a large, speculative flood-zone adjustment.","C6":"Reject — Zone AE but NOT elevated to BFE. This property carries higher NFIP premiums and potential FEMA non-compliance penalties. Its lower price reflects its non-elevated status; using it as a comp for the subject''s properly elevated property would understate the value of the elevation investment.","C7":"Acceptable — Zone AE, elevated, arm''s length 4 mo. ago. Slightly larger GLA and site; C1–C3 more directly comparable but confirms the Zone AE elevated value range."},"justification":"For a Zone AE elevated property, flood zone classification is a fundamental selection criterion. C1, C2, C3 are all Zone AE, elevated construction, arm''s length ($341k–$355k). Flood zone costs and market stigma are already embedded; no flood adjustment needed within the group. C4 and C5 — Zone X properties at $408k–$412k, roughly $60k above Zone AE; the flood zone difference is quantitatively significant but not reliably adjustable. C6 — Zone AE but non-elevated; lower NFIP compliance and higher future premiums make it a different sub-segment. C7 acceptable as secondary Zone AE elevated support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"2814 Bayou Court","prox":"0.5 mi","sub":"Bayou Estates","price":348000,"date":"2 months ago","style":"Ranch (elevated — stem wall)","bed":3,"bath":2,"gla":1790,"site":"0.38 acres","yr":2011,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car under","txn":"Arm''s length — MLS, Zone AE, elevated","warn":false},{"id":"C2","addr":"591 Waterway Drive","prox":"0.8 mi","sub":"Waterway Estates","price":355000,"date":"3 months ago","style":"Ranch (elevated — piers)","bed":3,"bath":2,"gla":1860,"site":"0.42 acres","yr":2013,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car under","txn":"Arm''s length — MLS, Zone AE, elevated","warn":false},{"id":"C3","addr":"109 Bayou Lane","prox":"0.6 mi","sub":"Bayou Estates","price":341000,"date":"5 months ago","style":"Ranch (elevated — stem wall)","bed":3,"bath":2,"gla":1805,"site":"0.39 acres","yr":2012,"cond":"C3","qual":"Q4","conc":"$3,000 seller paid","gar":"2-car under","txn":"Arm''s length — MLS, Zone AE, elevated","warn":false},{"id":"C4","addr":"428 Highland Drive","prox":"0.7 mi","sub":"Highland Estates (Zone X — no flood req.)","price":412000,"date":"2 months ago","style":"Ranch (slab foundation)","bed":3,"bath":2,"gla":1830,"site":"0.40 acres","yr":2012,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached (grade level)","txn":"Arm''s length — MLS, Zone X — no flood insurance required","warn":false},{"id":"C5","addr":"712 Highland Court","prox":"0.8 mi","sub":"Highland Estates (Zone X)","price":408000,"date":"3 months ago","style":"Ranch (slab foundation)","bed":3,"bath":2,"gla":1845,"site":"0.41 acres","yr":2013,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached (grade level)","txn":"Arm''s length — MLS, Zone X","warn":false},{"id":"C6","addr":"311 Bayou Court","prox":"0.4 mi","sub":"Bayou Estates","price":328000,"date":"2 months ago","style":"Ranch (not elevated — slab, Zone AE non-compliant)","bed":3,"bath":2,"gla":1795,"site":"0.37 acres","yr":2006,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car attached (grade level)","txn":"Arm''s length — MLS, Zone AE — non-elevated","warn":true},{"id":"C7","addr":"544 Waterway Court","prox":"0.9 mi","sub":"Waterway Estates","price":351000,"date":"4 months ago","style":"Ranch (elevated — stem wall)","bed":3,"bath":2,"gla":1875,"site":"0.43 acres","yr":2012,"cond":"C3","qual":"Q4","conc":"None","gar":"2-car under","txn":"Arm''s length — MLS, Zone AE, elevated","warn":false}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Different property type or construction","Different ownership structure / interest","Outside subject market area","Reflects different buyer pool / age restriction","Reflects encumbered or restricted-use value","Inadequate verification / data","Other"],"subject":{"address":"4821 Bayou Drive","subdivision":"Bayou Estates","style":"Ranch (elevated — stem wall)","bed":3,"bath":2,"gla":1820,"site":"0.40 acres","yr":2012,"cond":"C3","qual":"Q4","garage":"2-car under (ground level)","bsmt":"None","pool":"None"}}'::jsonb
FROM ins,
  module_sections ms
  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- Scenario 6.7: Deed-Restricted Affordable Housing — Fee Simple vs Restricted Value
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 7, 'advanced', 'Deed-Restricted Affordable Housing — Fee Simple vs Restricted Value', 'A community land trust (CLT) is selling a deed-restricted affordable home to an income-qualified buyer who is obtaining an FHA loan. The deed restriction limits future resale to income-qualified buyers at a formula-based restricted price. For the FHA loan, HUD requires the appraisal to reflect the RESTRICTED market value — the value within the income-qualified buyer pool subject to the resale restriction — not the unrestricted open-market fee simple value.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 6
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'HUD requires restricted market value for an FHA loan on a CLT deed-restricted property. C1, C2, C3 are all restricted resales within the income-qualified CLT or comparable affordable program buyer pool ($215k–$224k). C4 and C5 — fee simple unrestricted sales at $291k–$298k, approximately $75k above restricted value. This delta precisely illustrates the restriction''s impact. Using fee simple comps would overstate the HUD restricted value by ~35%, producing an FHA appraisal that violates HUD''s own standard. C6 — 27 months old. C7 acceptable as secondary restricted-pool support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same CLT program, same resale restriction, income-qualified resale 3 mo. ago. Directly reflects the restricted market value within the CLT buyer pool.","C2":"Strong comp — same CLT program, income-qualified resale 5 mo. ago, arm''s length within the restricted pool. Minor GLA adj (+30 SF).","C3":"Good comp — adjacent affordable housing authority program with similar income and resale restrictions, income-qualified resale 4 mo. ago. Different administering organization but comparable restriction structure.","C4":"Reject — unrestricted fee simple sale. The $80k difference between the restricted ($218k) and unrestricted ($298k) market reflects the restriction''s impact on value. HUD requires restricted market value for this FHA loan; using fee simple comps would dramatically overstate the restricted value and produce an unsupportable appraisal.","C5":"Reject — unrestricted fee simple. Using open-market comps for a deed-restricted CLT property overstates the restricted value by approximately $70k–$80k, creates an FHA appraisal that the income-qualified buyer cannot support, and violates HUD''s restricted-value appraisal standard.","C6":"Reject — 27 months old; outside the 12-month guideline for a current restricted-value opinion.","C7":"Acceptable — income-qualified affordable program resale, arm''s length 6 mo. ago. C1–C3 provide stronger restricted-pool comps but this confirms the restricted value range."},"justification":"HUD requires restricted market value for an FHA loan on a CLT deed-restricted property. C1, C2, C3 are all restricted resales within the income-qualified CLT or comparable affordable program buyer pool ($215k–$224k). C4 and C5 — fee simple unrestricted sales at $291k–$298k, approximately $75k above restricted value. This delta precisely illustrates the restriction''s impact. Using fee simple comps would overstate the HUD restricted value by ~35%, producing an FHA appraisal that violates HUD''s own standard. C6 — 27 months old. C7 acceptable as secondary restricted-pool support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"814 Community Drive","prox":"0.3 mi","sub":"Community Land Trust","price":218000,"date":"3 months ago","style":"Ranch","bed":3,"bath":2,"gla":1355,"site":"0.28 acres (CLT lease)","yr":2009,"cond":"C3","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length — CLT resale, income-qualified buyer","warn":false},{"id":"C2","addr":"421 Community Court","prox":"0.5 mi","sub":"Community Land Trust","price":224000,"date":"5 months ago","style":"Ranch","bed":3,"bath":2,"gla":1410,"site":"0.31 acres (CLT lease)","yr":2011,"cond":"C3","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length — CLT resale, income-qualified buyer","warn":false},{"id":"C3","addr":"108 Parkside Lane","prox":"0.8 mi","sub":"Affordable Housing Authority","price":215000,"date":"4 months ago","style":"Ranch","bed":3,"bath":2,"gla":1365,"site":"0.28 acres","yr":2009,"cond":"C3","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length — AHA program resale, income-qualified","warn":false},{"id":"C4","addr":"714 Ridgewood Drive","prox":"0.7 mi","sub":"Ridgewood Estates (unrestricted)","price":298000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1390,"site":"0.32 acres","yr":2010,"cond":"C3","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length — MLS, fee simple","warn":false},{"id":"C5","addr":"88 Clearview Way","prox":"0.9 mi","sub":"Clearview Park (unrestricted)","price":291000,"date":"3 months ago","style":"Ranch","bed":3,"bath":2,"gla":1375,"site":"0.30 acres","yr":2009,"cond":"C3","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length — MLS, fee simple","warn":false},{"id":"C6","addr":"312 Community Blvd","prox":"0.4 mi","sub":"Community Land Trust","price":209000,"date":"27 months ago","style":"Ranch","bed":3,"bath":2,"gla":1370,"site":"0.29 acres (CLT lease)","yr":2009,"cond":"C3","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length — CLT resale, income-qualified","warn":false},{"id":"C7","addr":"618 Parkside Drive","prox":"0.9 mi","sub":"Affordable Housing Authority","price":221000,"date":"6 months ago","style":"Ranch","bed":3,"bath":2,"gla":1395,"site":"0.30 acres","yr":2010,"cond":"C3","qual":"Q4","conc":"None","gar":"1-car attached","txn":"Arm''s length — AHA program resale, income-qualified","warn":false}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Different property type or construction","Different ownership structure / interest","Outside subject market area","Reflects different buyer pool / age restriction","Reflects encumbered or restricted-use value","Inadequate verification / data","Other"],"subject":{"address":"2417 Community Way","subdivision":"Community Land Trust — Restricted","style":"Ranch","bed":3,"bath":2,"gla":1380,"site":"0.30 acres (land leased from CLT)","yr":2010,"cond":"C3","qual":"Q4","garage":"1-car attached","bsmt":"None","pool":"None"}}'::jsonb
FROM ins,
  module_sections ms
  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- Scenario 6.8: Multigenerational / Dual Living Residence
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 8, 'advanced', 'Multigenerational / Dual Living Residence', 'Prime Lending engaged you to appraise an expanded single-family home designed for multigenerational living. The subject has a legally permitted internal suite (separate entrance, full kitchen, 1BR/1BA) as part of the primary structure — not a separate dwelling. Fannie Mae''s HomeReady program allows this as a single-unit property. Comparables should ideally include other multigenerational or dual-living properties; absent those, the suite contribution must be extracted from paired sales.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 6
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'For a Fannie Mae HomeReady multigenerational property, comparables must include permitted integrated suites, not unpermitted conversions or detached structures. C1 and C2 are direct suite-to-suite comparisons; C3 (no suite) provides the paired-sale that isolates the ~$50k suite contribution. C4 — unpermitted basement apartment; Fannie Mae HomeReady requires legally permitted units. C5 — detached guest house; physically larger on a bigger lot and a different product concept for the multigenerational buyer. C6 — 27 months old. C7 acceptable as secondary permitted-suite support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same sub, same configuration (Two-Story + permitted in-law suite), 2 mo. ago, arm''s length. Directly reflects the multigenerational buyer market.","C2":"Strong comp — adjacent sub, permitted in-law suite, 3 mo. ago, arm''s length. Minor GLA and site adj. Multigenerational buyer pool.","C3":"Good comp — same sub, no suite. Paired-sale analysis: C1 ($598k) vs C3 ($548k) isolates the in-law suite contribution (~$50k), supporting the suite adjustment.","C4":"Reject — unpermitted basement apartment. Fannie Mae HomeReady requires the in-law unit to be legally permitted. An unpermitted unit cannot be recognized in the appraisal, and using a comp that appears to reflect an unpermitted unit would inflate the permitted-suite value.","C5":"Reject — detached guest house, not an integrated in-law suite. A separate structure with additional BR/BA and on a larger lot is a different configuration; buyers seeking multigenerational integrated living treat detached guest houses as a different product.","C6":"Reject — 27 months old; outside the 12-month guideline.","C7":"Acceptable — permitted in-law suite, arm''s length 5 mo. ago. C1–C3 provide stronger direct support but this confirms the multigenerational value range."},"justification":"For a Fannie Mae HomeReady multigenerational property, comparables must include permitted integrated suites, not unpermitted conversions or detached structures. C1 and C2 are direct suite-to-suite comparisons; C3 (no suite) provides the paired-sale that isolates the ~$50k suite contribution. C4 — unpermitted basement apartment; Fannie Mae HomeReady requires legally permitted units. C5 — detached guest house; physically larger on a bigger lot and a different product concept for the multigenerational buyer. C6 — 27 months old. C7 acceptable as secondary permitted-suite support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"812 Heritage Drive","prox":"0.5 mi","sub":"Heritage Estates","price":598000,"date":"2 months ago","style":"Two-Story + in-law suite","bed":"4+1","bath":"3+1","gla":"2,380 SF + 620 SF suite","site":"9,800 SF","yr":2014,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS, permitted in-law suite","warn":false},{"id":"C2","addr":"421 Ridgecrest Manor","prox":"0.8 mi","sub":"Ridgecrest Estates","price":608000,"date":"3 months ago","style":"Two-Story + in-law suite","bed":"4+1","bath":"3+1","gla":"2,460 SF + 680 SF suite","site":"10,200 SF","yr":2016,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS, permitted in-law suite","warn":false},{"id":"C3","addr":"118 Heritage Way","prox":"0.6 mi","sub":"Heritage Estates","price":548000,"date":"4 months ago","style":"Two-Story (no suite)","bed":4,"bath":3,"gla":"2,380 SF (no suite)","site":"9,900 SF","yr":2015,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C4","addr":"714 Heritage Blvd","prox":"0.5 mi","sub":"Heritage Estates","price":621000,"date":"3 months ago","style":"Two-Story + unpermitted basement apt.","bed":"4+1","bath":"3+1","gla":"2,390 SF + 700 SF (unpermitted)","site":"9,700 SF","yr":2015,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS","warn":true},{"id":"C5","addr":"88 Ridgecrest Drive","prox":"0.8 mi","sub":"Ridgecrest Estates","price":635000,"date":"2 months ago","style":"Two-Story + detached guest house","bed":"4+2","bath":"3+2","gla":"2,410 SF + 900 SF (detached)","site":"0.45 acres","yr":2016,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS","warn":false},{"id":"C6","addr":"312 Heritage Court","prox":"0.4 mi","sub":"Heritage Estates","price":581000,"date":"27 months ago","style":"Two-Story + in-law suite","bed":"4+1","bath":"3+1","gla":"2,370 SF + 630 SF suite","site":"9,800 SF","yr":2014,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS, permitted suite","warn":false},{"id":"C7","addr":"618 Ridgecrest Court","prox":"0.9 mi","sub":"Ridgecrest Estates","price":601000,"date":"5 months ago","style":"Two-Story + in-law suite","bed":"4+1","bath":"3+1","gla":"2,420 SF + 640 SF suite","site":"10,100 SF","yr":2015,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — MLS, permitted suite","warn":false}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Different property type or construction","Different ownership structure / interest","Outside subject market area","Reflects different buyer pool / age restriction","Reflects encumbered or restricted-use value","Inadequate verification / data","Other"],"subject":{"address":"3518 Heritage Court","subdivision":"Heritage Estates","style":"Two-Story + in-law suite","bed":"4+1","bath":"3+1","gla":"2,400 SF + 650 SF suite","site":"10,000 SF","yr":2015,"cond":"C2","qual":"Q4","garage":"3-car attached","bsmt":"None","pool":"None"}}'::jsonb
FROM ins,
