-- Scenario 6.9: Non-Traditional Construction — Structural Insulated Panel (SIP)
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 9, 'advanced', 'Non-Traditional Construction — Structural Insulated Panel (SIP)', 'Mountain West Lending engaged you to appraise a custom home built with Structural Insulated Panel (SIP) construction for a purchase loan. SIP homes have superior energy efficiency and structural strength but represent a small, niche market. Fannie Mae requires that appraisals for non-traditional construction explain how market acceptance is reflected in the comparable selection; in limited markets, paired sales analysis and bracketing are essential.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 6
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'SIP construction requires a two-pronged strategy: (1) use SIP comparables where available (C1, C2, C7) and (2) use conventional Q5 comps as paired sales to isolate the SIP market premium (C3 vs C1 = ~$23k). This bracketing approach satisfies Fannie Mae''s requirement to demonstrate market acceptance. C4 — Q4 quality cannot be adjusted reliably to Q5; quality tier is the primary value driver in this custom-home market. C5 — builder-to-own-LLC; non-arm''s length and undermines independence in a builder-specialty context. C6 — 18 miles, non-competing mountain community. C7 acceptable as secondary SIP support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same market area, SIP construction, Q5 custom quality, 2 mo. before effective date, arm''s length. At 1.1 mi, extended distance is necessary given limited SIP sales inventory.","C2":"Strong comp — SIP construction, Q5, 1 mo. after effective date (no change), arm''s length. GLA and acreage adj. 2.8 mi distance is appropriate for a niche construction market with limited comparable inventory.","C3":"Good comp — conventional frame but Q5 custom quality, same market area, 1 mo. before effective date, arm''s length. Paired with C1 (SIP): C1 ($718k) vs C3 ($695k) suggests market recognition of a modest SIP premium (~$23k), supporting bracketing.","C4":"Reject — Q4 tract-quality construction vs subject''s Q5 custom. The quality tier difference cannot be reliably bridged; adjustments would be too large and speculative to support the custom SIP value conclusion.","C5":"Reject — builder sold to its own LLC. Non-arm''s length; for a non-traditional construction appraisal where the builder''s own practices are under market scrutiny, a sale to the builder''s affiliated entity cannot establish independent market value.","C6":"Reject — 18 miles away in a different mountain community with different access, amenity, and economic characteristics. Despite SIP construction and quality match, this location does not compete with the subject''s market.","C7":"Acceptable — SIP construction, Q5, 3 mo. before effective date, arm''s length. Slightly smaller GLA and acreage; C1–C3 more directly comparable but this confirms the SIP custom-home value range."},"justification":"SIP construction requires a two-pronged strategy: (1) use SIP comparables where available (C1, C2, C7) and (2) use conventional Q5 comps as paired sales to isolate the SIP market premium (C3 vs C1 = ~$23k). This bracketing approach satisfies Fannie Mae''s requirement to demonstrate market acceptance. C4 — Q4 quality cannot be adjusted reliably to Q5; quality tier is the primary value driver in this custom-home market. C5 — builder-to-own-LLC; non-arm''s length and undermines independence in a builder-specialty context. C6 — 18 miles, non-competing mountain community. C7 acceptable as secondary SIP support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"5214 Summit Court","prox":"1.1 mi","sub":"Summit Ridge","price":718000,"date":"14 months ago","style":"Two-Story (SIP construction)","bed":4,"bath":3,"gla":2600,"site":"1.0 acres","yr":2018,"cond":"C2","qual":"Q5","conc":"None","gar":"3-car attached","txn":"Arm''s length — deed/MLS","warn":false},{"id":"C2","addr":"11042 Ridge Road","prox":"2.8 mi","sub":"Ridge Estates","price":731000,"date":"11 months ago","style":"Two-Story (SIP construction)","bed":4,"bath":3,"gla":2720,"site":"1.3 acres","yr":2020,"cond":"C2","qual":"Q5","conc":"None","gar":"3-car attached","txn":"Arm''s length — deed/MLS","warn":false},{"id":"C3","addr":"3100 Summit Drive","prox":"1.8 mi","sub":"Summit Ridge","price":695000,"date":"13 months ago","style":"Two-Story (conventional frame — comparable quality)","bed":4,"bath":3,"gla":2620,"site":"1.1 acres","yr":2019,"cond":"C2","qual":"Q5","conc":"None","gar":"3-car attached","txn":"Arm''s length — deed/MLS","warn":false},{"id":"C4","addr":"9200 Summit Way","prox":"0.8 mi","sub":"Summit Ridge","price":621000,"date":"13 months ago","style":"Two-Story (conventional frame)","bed":4,"bath":3,"gla":2640,"site":"1.2 acres","yr":2018,"cond":"C2","qual":"Q4","conc":"None","gar":"3-car attached","txn":"Arm''s length — deed/MLS","warn":false},{"id":"C5","addr":"8100 Valley Road","prox":"0.5 mi","sub":"Summit Ridge","price":748000,"date":"13 months ago","style":"Two-Story (SIP construction)","bed":4,"bath":3,"gla":2660,"site":"1.2 acres","yr":2019,"cond":"C2","qual":"Q5","conc":"None","gar":"3-car attached","txn":"Builder sold to builder''s own LLC — per deed","warn":true},{"id":"C6","addr":"22 Heritage Drive","prox":"18 mi","sub":"Heritage Crossing","price":724000,"date":"13 months ago","style":"Two-Story (SIP construction)","bed":4,"bath":3,"gla":2680,"site":"1.3 acres","yr":2019,"cond":"C2","qual":"Q5","conc":"None","gar":"3-car attached","txn":"Arm''s length — deed/MLS","warn":false},{"id":"C7","addr":"2871 Ridge Court","prox":"2.1 mi","sub":"Ridge Estates","price":702000,"date":"15 months ago","style":"Two-Story (SIP construction)","bed":4,"bath":3,"gla":2580,"site":"1.0 acres","yr":2018,"cond":"C2","qual":"Q5","conc":"None","gar":"3-car attached","txn":"Arm''s length — deed/MLS","warn":false}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Different property type or construction","Different ownership structure / interest","Outside subject market area","Reflects different buyer pool / age restriction","Reflects encumbered or restricted-use value","Inadequate verification / data","Other"],"subject":{"address":"8842 Summit View Drive","subdivision":"Summit Ridge","style":"Two-Story (SIP construction)","bed":4,"bath":3,"gla":2650,"site":"1.2 acres","yr":2019,"cond":"C2","qual":"Q5","garage":"3-car attached","bsmt":"Finished","pool":"None"}}'::jsonb
FROM ins,
  module_sections ms
  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

-- Scenario 6.10: Ground Lease / Leasehold Interest
WITH ins AS (
  INSERT INTO scenarios (category_id, order_index, difficulty, title, scenario_text)
  SELECT cat.id, 10, 'advanced', 'Ground Lease / Leasehold Interest', 'You have been engaged to appraise the leasehold interest in a residential property for a purchase loan. The subject sits on land owned by a private land trust; the buyer will own only the improvements, not the land, under a 99-year ground lease at $400/month (CPI-adjusted every 5 years). Leasehold interests require specialized comparable selection: the appraiser must use other leasehold sales or, absent those, carefully adjust fee simple comps for the leasehold encumbrance.'
  FROM scenario_categories cat
  JOIN module_sections ms ON ms.id = cat.section_id
  WHERE ms.code = 'M2-S3' AND cat.order_index = 6
  RETURNING id
)
INSERT INTO model_answers (scenario_id, field_id, answer_text, commentary, model_data, field_options_override)
SELECT ins.id, sf.id,
  'Leasehold appraisals require leasehold comparable sales — not fee simple. C1, C2, C3 are all leasehold transactions under the same or comparable land trust terms ($385k–$405k). C4 and C5 — fee simple sales at $491k–$498k, approximately $95k–$100k above leasehold comps. This delta represents the land value embodied in fee simple ownership that the leasehold buyer does not acquire. Using fee simple comps in the primary grid without a full leasehold deduction overstates value by ~25%. C6 — 27 months old. C7 acceptable as secondary leasehold support.',
  NULL,
  '{"verdicts":{"C1":"accept","C2":"accept","C3":"accept","C4":"reject","C5":"reject","C6":"reject","C7":"accept"},"ranking":["C1","C2","C3"],"explanations":{"C1":"Best comp — same community, same ground lease terms (same land trust), leasehold interest, 3 mo. ago, arm''s length. Directly reflects the leasehold market. No adjustment needed for ownership structure.","C2":"Strong comp — adjacent leasehold community with comparable lease terms, most recent (2 mo.), arm''s length. Minor GLA adj. Reflects the leasehold buyer pool.","C3":"Good comp — same community, same lease terms, 5 mo. ago, arm''s length. Seller concession adj required.","C4":"Reject — fee simple ownership vs subject''s leasehold interest. The $100k premium reflects the land value the fee simple buyer acquires. For a leasehold appraisal, using fee simple comps without a land-value deduction systematically overstates the leasehold value. A leasehold interest never equals the fee simple value of the same property.","C5":"Reject — fee simple comp for a leasehold interest. The ownership structure difference is not adjustable without specialized leasehold analysis. Fee simple comps in the primary comparison grid would overstate the leasehold value by approximately the present value of the land interest.","C6":"Reject — 27 months old; outside the 12-month guideline. Ground lease terms can be renegotiated over time; a stale comp may not reflect current leasehold market conditions.","C7":"Acceptable — leasehold with comparable terms, arm''s length 6 mo. ago. Slightly larger GLA and site; C1–C3 provide stronger direct support but this confirms the leasehold value range."},"justification":"Leasehold appraisals require leasehold comparable sales — not fee simple. C1, C2, C3 are all leasehold transactions under the same or comparable land trust terms ($385k–$405k). C4 and C5 — fee simple sales at $491k–$498k, approximately $95k–$100k above leasehold comps. This delta represents the land value embodied in fee simple ownership that the leasehold buyer does not acquire. Using fee simple comps in the primary grid without a full leasehold deduction overstates value by ~25%. C6 — 27 months old. C7 acceptable as secondary leasehold support."}'::jsonb,
  '{"comps":[{"id":"C1","addr":"2814 Lakeridge Court","prox":"0.5 mi","sub":"Lakeridge Estates (ground lease)","price":398000,"date":"3 months ago","style":"Ranch","bed":3,"bath":2,"gla":1860,"site":"Leased — 0.38 acres","yr":2007,"cond":"C2","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS, leasehold (same land trust)","warn":false},{"id":"C2","addr":"591 Lakeview Drive","prox":"0.9 mi","sub":"Lakeview Leasehold Community","price":405000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1930,"site":"Leased — 0.42 acres","yr":2009,"cond":"C2","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS, leasehold (comparable land trust terms)","warn":false},{"id":"C3","addr":"109 Lakeridge Lane","prox":"0.6 mi","sub":"Lakeridge Estates (ground lease)","price":385000,"date":"5 months ago","style":"Ranch","bed":3,"bath":2,"gla":1875,"site":"Leased — 0.39 acres","yr":2008,"cond":"C2","qual":"Q4","conc":"$4,000 seller paid","gar":"2-car attached","txn":"Arm''s length — MLS, leasehold (same land trust)","warn":false},{"id":"C4","addr":"714 Lakeridge Blvd","prox":"0.5 mi","sub":"Lakeridge Heights (fee simple)","price":498000,"date":"2 months ago","style":"Ranch","bed":3,"bath":2,"gla":1895,"site":"Fee simple — 0.40 acres","yr":2008,"cond":"C2","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS, fee simple","warn":false},{"id":"C5","addr":"88 Lakeview Court","prox":"0.8 mi","sub":"Lakeview Heights (fee simple)","price":491000,"date":"3 months ago","style":"Ranch","bed":3,"bath":2,"gla":1910,"site":"Fee simple — 0.41 acres","yr":2009,"cond":"C2","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS, fee simple","warn":false},{"id":"C6","addr":"312 Lakeridge Way","prox":"0.4 mi","sub":"Lakeridge Estates (ground lease)","price":372000,"date":"27 months ago","style":"Ranch","bed":3,"bath":2,"gla":1870,"site":"Leased — 0.38 acres","yr":2007,"cond":"C2","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS, leasehold (same land trust)","warn":false},{"id":"C7","addr":"618 Lakeview Lane","prox":"1.1 mi","sub":"Lakeview Leasehold Community","price":395000,"date":"6 months ago","style":"Ranch","bed":3,"bath":2,"gla":1945,"site":"Leased — 0.43 acres","yr":2009,"cond":"C2","qual":"Q4","conc":"None","gar":"2-car attached","txn":"Arm''s length — MLS, leasehold (comparable terms)","warn":false}],"rejection_reasons":["Sale date outside acceptable range","Non-arm''s length transaction","Distressed / REO / foreclosure sale","Insufficient physical similarity","Different property type or construction","Different ownership structure / interest","Outside subject market area","Reflects different buyer pool / age restriction","Reflects encumbered or restricted-use value","Inadequate verification / data","Other"],"subject":{"address":"4821 Lakeridge Drive","subdivision":"Lakeridge Estates (ground lease)","style":"Ranch","bed":3,"bath":2,"gla":1890,"site":"Leased — 0.40 acres","yr":2008,"cond":"C2","qual":"Q4","garage":"2-car attached","bsmt":"None","pool":"Pool"}}'::jsonb
FROM ins,
  module_sections ms
  JOIN section_fields sf ON sf.section_id = ms.id
WHERE ms.code = 'M2-S3' AND sf.field_key = 'comparables';

